import {IonRippleEffect,IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _greater_cloud_invocation = {title: "Greater Cloud Invocation", jsx: <><h2 id="feat-greater_cloud_invocation-greater-cloud-invocation">Greater Cloud Invocation</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 9</Link></p>
<p>Your devotion to the <Link to="/family/cloud_dragon">cloud dragons</Link> of your kingdom causes your connection with them to strengthen.<br/><strong>Prerequisites:</strong> <Link to="/feat/cloud_invocation">Cloud Invocation</Link>, Mbe'ke <Link to="/race/dwarf">dwarf</Link>.<br/><strong>Benefit:</strong> The duration of your Cloud Invocation increases to 1 minute per level, and you can dismiss it as an immediate action. You can create mist with your Cloud Invocation ability multiple times per day, so long as you do not exceed a total duration of 1 minute per level, and you expend the duration of your Cloud Invocation in 1-minute increments. If you create a mist cloud while any previous mist is still present, the previous mist ends. Additionally, you can have the mist remain centered on you, rather than stationary.</p>
</>};
const _greater_dirge_of_doom = {title: "Greater Dirge of Doom", jsx: <><h2 id="feat-greater_dirge_of_doom-greater-dirge-of-doom">Greater Dirge of Doom</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 149</Link></p>
<p>The haunting sound of sepulchral intonations chills the most stalwart adversary to its very core.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_dirge_of_doom">Improved Dirge of Doom</Link>, ability to perform <Link to="/performance/dirge_of_doom">dirge of doom</Link>.<br/><strong>Benefit:</strong> The effect of your dirge of doom lingers with a target for 2 rounds after the creature leaves the dirge's area of effect. If you use your dirge on a creature that is <Link to="/misc/shaken">shaken</Link>, it becomes <Link to="/misc/frightened">frightened</Link>. If you use it on a creature that is frightened, it becomes <Link to="/misc/panicked">panicked</Link>. Once affected by this feat, a creature cannot be affected by it again for 24 hours.<br/><strong>Normal:</strong> Fear effects on a creature end immediately once it leaves the area of dirge of doom. A fear effect cannot be made more extreme by dirge of doom and can be changed only to the frightened condition by the Improved Dirge of Doom feat.</p>
</>};
const _greater_dirty_trick = {title: "Greater Dirty Trick", jsx: <><h2 id="feat-greater_dirty_trick-greater-dirty-trick-combat">Greater Dirty Trick (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 161</Link></p>
<p>When you pull a dirty trick, your foe is truly hindered.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_dirty_trick">Improved Dirty Trick</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to attempt a <Link to="/rule/dirty_trick">dirty trick</Link>. This bonus stacks with the bonus granted by Improved Dirty Trick. Whenever you successfully perform a dirty trick, the penalty lasts for 1d4 rounds, plus 1 round for every 5 by which your attack exceeds the target's CMD. In addition, removing the condition requires the target to spend a standard action.<br/><strong>Normal:</strong> The condition imposed by a dirty trick lasts for 1 round plus 1 round for every 5 by which your attack exceeds the target's CMD. Removing the condition requires the target to spend a move action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_dirty_trick--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_dirty_trick-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 120</Link><br/>You can select this feat even if you don't meet the ability score prerequisite (Intelligence 13). You gain the benefits of this feat only as long as you have at least 1 stamina point in your stamina pool. When you successfully complete a dirty trick combat maneuver, you can spend 5 stamina points to make the condition you inflicted with that maneuver require a full-round action to remove (instead of a standard action).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_disarm = {title: "Greater Disarm", jsx: <><h2 id="feat-greater_disarm-greater-disarm-combat">Greater Disarm (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 125</Link></p>
<p>You can knock weapons far from an enemy's grasp.<br/><strong>Prerequisites:</strong> <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_disarm">Improved Disarm</Link>, base attack bonus +6, Int 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/rule/disarm">disarm</Link> a foe. This bonus stacks with the bonus granted by Improved Disarm. Whenever you successfully disarm an opponent, the weapon lands 15 feet away from its previous wielder, in a random direction.<br/><strong>Normal:</strong> Disarmed weapons and gear land at the feet of the disarmed creature.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_disarm--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_disarm-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 120</Link><br/>You can select this feat even if you don't meet the ability score prerequisite (Intelligence 13). You gain the benefits of this feat only as long as you have at least 1 stamina point in your stamina pool. When you successfully disarm a foe, you can spend 5 stamina points to select where the weapon lands by choosing a square within 15 feet of the disarmed foe. If you choose a square in your space and have at least one hand free, you can grab the weapon as part of the disarm attempt.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_disarm--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You can knock weapons far from an enemy's grasp.<br/><strong>Prerequisites:</strong> <Link to="/rule/deft_maneuvers">Deft Maneuvers</Link>, base attack bonus +6, Int 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/rule/disarm">disarm</Link> a foe. This bonus stacks with the bonus granted by Deft Manauvers. Whenever you successfully disarm an opponent, the weapon lands 15 feet away from its previous wielder, in a random direction.<br/><strong>Normal:</strong> Disarmed weapons and gear land at the feet of the disarmed creature.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_dispel_focus = {title: "Greater Dispel Focus", jsx: <><h2 id="feat-greater_dispel_focus-greater-dispel-focus">Greater Dispel Focus</h2>
<p><strong>Sources</strong> <Link to="/source/monster_summoners_handbook">Monster Summoner's Handbook pg. 9</Link></p>
<p>You are a master of the art of dispelling.<br/><strong>Prerequisites:</strong> <Link to="/feat/dispel_focus">Dispel Focus</Link>, ability to cast <Link to="/spell/dispel_magic">dispel magic</Link>.<br/><strong>Benefit:</strong> Whenever you attempt a dispel check based on your caster level, you gain a +2 bonus to the check. This stacks with the bonus from Dispel Focus.</p>
</>};
const _greater_drag = {title: "Greater Drag", jsx: <><h2 id="feat-greater_drag-greater-drag-combat">Greater Drag (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 161</Link></p>
<p>Foes that you drag are thrown out of balance.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/improved_drag">Improved Drag</Link>, <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/rule/drag">drag</Link> a foe. This bonus stacks with the bonus granted by Improved Drag. Whenever you drag a foe, his movement provokes attacks of opportunity from all of your allies (but not you).<br/><strong>Normal:</strong> Creatures moved by drag do not provoke attacks of opportunity.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_drag--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_drag-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>When you succeed at a drag combat maneuver check, you can spend 5 stamina points to gain up to 10 feet of movement for your drag. You can use this movement in place of your normal movement, but only to drag an opponent.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_drow_nobility = {title: "Greater Drow Nobility", jsx: <><h2 id="feat-greater_drow_nobility-greater-drow-nobility">Greater Drow Nobility</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 105</Link></p>
<p>You have mastered the lesser spell-like abilities of the drow, demonstrating true nobility.<br/><strong>Prerequisites:</strong> Cha 13, <Link to="/feat/drow_nobility">Drow Nobility</Link>, <Link to="/feat/improved_drow_nobility">Improved Drow Nobility</Link>, able to use drow spell-like abilities, <Link to="/race/drow">drow</Link>.<br/><strong>Benefit:</strong> Your <Link to="/spell/detect_magic">detect magic</Link> spell-like ability is now constant. You may use your <Link to="/spell/dancing_lights">dancing lights</Link>, <Link to="/spell/deeper_darkness">deeper darkness</Link>, <Link to="/spell/faerie_fire">faerie fire</Link>, <Link to="/spell/feather_fall">feather fall</Link>, and <Link to="/spell/levitate">levitate</Link> spell-like abilities at will.</p>
</>};
const _greater_eldritch_heritage = {title: "Greater Eldritch Heritage", jsx: <><h2 id="feat-greater_eldritch_heritage-greater-eldritch-heritage">Greater Eldritch Heritage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 152</Link></p>
<p>Your discovered bloodline power reaches its zenith.<br/><strong>Prerequisites:</strong> Cha 17, <Link to="/feat/eldritch_heritage">Eldritch Heritage</Link>, <Link to="/feat/improved_eldritch_heritage">Improved Eldritch Heritage</Link>, character level 17th.<br/><strong>Benefit:</strong> You gain an additional power from the <Link to="/ability/sorcerer_bloodlines">bloodline</Link> you selected with the Eldritch Heritage feat. You gain a 15th-level (or lower) sorcerer bloodline power that you do not already have. For purposes of using that power, treat your character level as your sorcerer level for all your sorcerer bloodline powers granted by this feat, Eldritch Heritage, and Improved Eldritch Heritage.</p>
</>};
const _greater_elemental_focus = {title: "Greater Elemental Focus", jsx: <><h2 id="feat-greater_elemental_focus-greater-elemental-focus">Greater Elemental Focus</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 161</Link></p>
<p>Choose an energy type to which you have already applied the Elemental Focus feat. Any spells you cast of this energy type are very hard to resist.<br/><strong>Prerequisites:</strong> <Link to="/feat/elemental_focus">Elemental Focus</Link>.<br/><strong>Benefit:</strong> Add +1 to the Difficulty Class for all saving throws against spells that deal damage of the energy type you select. This bonus stacks with the bonus from Elemental Focus.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take this feat, it applies to a new energy type to which you have already applied the Elemental Focus feat.</p>
</>};
const _greater_feint = {title: "Greater Feint", jsx: <><h2 id="feat-greater_feint-greater-feint-combat">Greater Feint (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 125</Link></p>
<p>You are skilled at making foes overreact to your attacks.<br/><strong>Prerequisites:</strong> <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_feint">Improved Feint</Link>, base attack bonus +6, Int 13.<br/><strong>Benefit:</strong> Whenever you use <Link to="/rule/feint">feint</Link> to cause an opponent to lose his Dexterity bonus, he loses that bonus until the beginning of your next turn, in addition to losing his Dexterity bonus against your next attack.<br/><strong>Normal:</strong> A creature you feint loses its Dexterity bonus against your next attack.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_feint--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_feint-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>You can select this feat even if you don't meet the ability score prerequisite (Intelligence 13). You gain the benefits of this feat only as long as you have at least 1 stamina point in your stamina pool. If you have at least 1 point in your stamina pool, you can feint as a swift action, but the feint causes the opponent to become <Link to="/rule/flat_footed">flat-footed</Link> only for your next attack rather than for all attacks until the beginning of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_feint--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You are skilled at making foes overreact to your attacks.<br/><strong>Prerequisites:</strong> <Link to="/rule/deft_maneuvers">Deft Maneuvers</Link>, base attack bonus +6, Int 13.<br/><strong>Benefit:</strong> Whenever you use <Link to="/rule/feint">feint</Link> to cause an opponent to lose his Dexterity bonus, he loses that bonus until the beginning of your next turn, in addition to losing his Dexterity bonus against your next attack.<br/><strong>Normal:</strong> A creature you feint loses its Dexterity bonus against your next attack.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_gathlain_magic = {title: "Greater Gathlain Magic", jsx: <><h2 id="feat-greater_gathlain_magic-greater-gathlain-magic">Greater Gathlain Magic</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 13</Link></p>
<p>You have greatly developed your innate magical abilities.<br/><strong>Prerequisites:</strong> Cha 15, <Link to="/feat/advanced_gathlain_magic">Advanced Gathlain Magic</Link>, character level 9th, <Link to="/race/gathlain">gathlain</Link>.<br/><strong>Benefit:</strong> You gain the following spells as spell-like abilities, each of which are usable 1/day: <Link to="/spell/command_plants">command plants</Link>, <Link to="/spell/thorny_entanglement">thorny entanglement</Link>.</p>
</>};
const _greater_grapple = {title: "Greater Grapple", jsx: <><h2 id="feat-greater_grapple-greater-grapple-combat">Greater Grapple (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 125</Link></p>
<p>Maintaining a grapple is second nature to you.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_grapple">Improved Grapple</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, base attack bonus +6, Dex 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/misc/grapple">grapple</Link> a foe. This bonus stacks with the bonus granted by Improved Grapple. Once you have grappled a creature, maintaining the grapple is a move action. This feat allows you to make two grapple checks each round (to move, harm, or pin your opponent), but you are not required to make two checks. You only need to succeed at one of these checks to maintain the grapple.<br/><strong>Normal:</strong> Maintaining a grapple is a standard action.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_grapple--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_grapple-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>After you take a move action to successfully maintain a grapple, you can spend 5 stamina points before the end of your turn to maintain that grapple as a swift action. This allows you to make up to three grapple checks to maintain a grapple during a round, but you still can't maintain a grapple until the round after you initiate it.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_grapple--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>Maintaining a grapple is second nature to you.<br/><strong>Prerequisites:</strong> <Link to="/rule/unarmed_combatant">Unarmed Combatant</Link>, base attack bonus +6, Dex 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/misc/grapple">grapple</Link> a foe. This bonus stacks with the bonus granted by Unarmed Combatant. Once you have grappled a creature, maintaining the grapple is a move action. This feat allows you to make two grapple checks each round (to move, harm, or pin your opponent), but you are not required to make two checks. You only need to succeed at one of these checks to maintain the grapple.<br/><strong>Normal:</strong> Maintaining a grapple is a standard action.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_hunters_bond = {title: "Greater Hunter's Bond", jsx: <><h2 id="feat-greater_hunters_bond-greater-hunters-bond-combat">Greater Hunter's Bond (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 113</Link></p>
<p>Your allies can target additional foes.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_hunters_bond">Improved Hunter's Bond</Link>, hunter's bond (hunting companions) class feature, <Link to="/class/ranger">ranger</Link> level 12th.<br/><strong>Benefit:</strong> When you activate hunter's bond, you can select a number of targets equal to your Wisdom modifier as long as they all count as your <Link to="/ability/favored_enemy">favored enemy</Link>.<br/><strong>Normal:</strong> You select one target against which your allies receive your favored enemy bonus.</p>
</>};
const _greater_ironclad_reactions = {title: "Greater Ironclad Reactions", jsx: <><h2 id="feat-greater_ironclad_reactions-greater-ironclad-reactions-armor-mastery-combat">Greater Ironclad Reactions (Armor Mastery, Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 16</Link></p>
<p>You are able to quickly react to attacks.<br/><strong>Prerequisites:</strong> <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/feat/ironclad_reactions">Ironclad Reactions</Link>, base attack bonus +11 or fighter level 8th, armor training class feature, proficiency with medium armor.<br/><strong>Benefit:</strong> You can use Ironclad Reactions more than once per round, but not more than once for each act you take that provokes an attack of opportunity. Each 5-foot step you take still counts as expending one use of an attack of opportunity.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_ironclad_reactions--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_ironclad_reactions-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 20</Link><br/>You can spend 5 stamina points to use this feat without it counting against your maximum number of attacks of opportunity for that round.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_meditation_master = {title: "Greater Meditation Master", jsx: <><h2 id="feat-greater_meditation_master-greater-meditation-master-meditation">Greater Meditation Master (Meditation)</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast pg. 28</Link></p>
<p>You are able to glean insight from your momentary meditation longer than most.<br/><strong>Prerequisites:</strong> Wis 15, <Link to="/feat/combat_meditation">Combat Meditation</Link>, <Link to="/feat/meditation_master">Meditation Master</Link>, character level 11th.<br/><strong>Benefit:</strong> When you meditate, you gain a +2 insight bonus instead of a +1 insight bonus. You can split this bonus between any two d20 rolls made over the duration of the feat that you used to meditate, adding +1 to each d20 roll, or using the full bonus on any one d20 roll, adding +2 to that single roll.</p>
</>};
const _greater_mercy = {title: "Greater Mercy", jsx: <><h2 id="feat-greater_mercy-greater-mercy">Greater Mercy</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 152</Link></p>
<p>Your mercy has incredible recuperative properties.<br/><strong>Prerequisites:</strong> Cha 13, <Link to="/ability/lay_on_hands">lay on hands</Link> class feature, mercy class feature.<br/><strong>Benefit:</strong> When you use your lay on hands ability and the target of that ability does not have any conditions your <Link to="/ability/mercies">mercies</Link> can remove, it instead heals an additional +1d6 points of damage.</p>
</>};
const _greater_mesmerizing_feint = {title: "Greater Mesmerizing Feint", jsx: <><h2 id="feat-greater_mesmerizing_feint-greater-mesmerizing-feint-combat">Greater Mesmerizing Feint (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 134</Link></p>
<p>You can feint against nearly any creature.<br/><strong>Prerequisites:</strong> <Link to="/feat/mesmerizing_feint">Mesmerizing Feint</Link>, Bluff 10 ranks, hypnotic stare class feature, <Link to="/stare/psychic_inception">psychic inception</Link> bold stare.<br/><strong>Benefit:</strong> You can <Link to="/rule/feint">feint</Link> against mindless creatures at a -4 penalty. Such a creature must be a subject of your hypnotic stare, and the creature has a 50% chance of ignoring the effects of your feint.<br/><strong>Normal:</strong> Feinting against a creature that is mindless is impossible.</p>
</>};
const _greater_overrun = {title: "Greater Overrun", jsx: <><h2 id="feat-greater_overrun-greater-overrun-combat">Greater Overrun (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 125</Link></p>
<p>Enemies must dive to avoid your dangerous move.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_overrun">Improved Overrun</Link>, <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +6, Str 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to overrun a foe. This bonus stacks with the bonus granted by Improved Overrun. Whenever you <Link to="/rule/overrun">overrun</Link> opponents, they provoke attacks of opportunity if they are knocked <Link to="/rule/prone">prone</Link> by your overrun.<br/><strong>Normal:</strong> Creatures knocked prone by your overrun do not provoke an attack of opportunity.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_overrun--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_overrun-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>If you succeed at a combat maneuver check to overrun an opponent, but do not exceed your opponent's CMD by 5 or more, you can spend 2 stamina points to knock the target prone anyway.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_overrun--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>Enemies must dive to avoid your dangerous move.<br/><strong>Prerequisites:</strong> <Link to="/rule/powerful_maneuvers">Powerful Maneuvers</Link>, base attack bonus +6, Str 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to overrun a foe. This bonus stacks with the bonus granted by Powerful Maneuvers. Whenever you <Link to="/rule/overrun">overrun</Link> opponents, they provoke attacks of opportunity if they are knocked <Link to="/rule/prone">prone</Link> by your overrun.<br/><strong>Normal:</strong> Creatures knocked prone by your overrun do not provoke an attack of opportunity.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_penetrating_strike = {title: "Greater Penetrating Strike", jsx: <><h2 id="feat-greater_penetrating_strike-greater-penetrating-strike-combat">Greater Penetrating Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 125</Link></p>
<p>Your attacks penetrate the defenses of most foes.<br/><strong>Prerequisites:</strong> <Link to="/feat/penetrating_strike">Penetrating Strike</Link>, <Link to="/feat/weapon_focus">Weapon Focus</Link>, 16th-level fighter.<br/><strong>Benefit:</strong> Your attacks with weapons selected with Weapon Focus ignore up to 10 points of damage reduction. This amount is reduced to 5 points for damage reduction without a type (such as DR 10/-).</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_penetrating_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_penetrating_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>When you use a weapon with which you have Weapon Focus to damage a creature that has damage reduction, you can spend 5 stamina points to allow all your allies within 30 feet to ignore 10 points of that creature's damage reduction for 1 round. This amount is reduced to 5 points for damage reduction without a type (such as DR 10/-). This effect does not stack with Greater Penetrating Strike's normal effect, but it does allow you to apply the effect to all your other weapons for the duration.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_penetrating_strike--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>Your attacks penetrate the defenses of most foes.<br/><strong>Prerequisites:</strong> <Link to="/feat/penetrating_strike">Penetrating Strike</Link>, <Link to="/feat/weapon_focus">Weapon Focus</Link>, 16th-level fighter.<br/><strong>Benefit:</strong> Your attacks with weapons from the group in which you have Weapon Focus ignore up to 10 points of damage reduction. This amount is reduced to 5 points for damage reduction without a type (such as DR 10/-).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_planar_infusion = {title: "Greater Planar Infusion", jsx: <><h2 id="feat-greater_planar_infusion-greater-planar-infusion-conduit">Greater Planar Infusion (Conduit)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 28</Link></p>
<p>You have mastered the powers of another plane.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_planar_infusion">Improved Planar Infusion</Link>, <Link to="/feat/planar_infusion">Planar Infusion</Link>, character level 13th.<br/><strong>Benefit:</strong> Choose a plane for which you've gained an improved infusion via Improved Planar Infusion. You gain that plane's greater infusion as well.</p>
</>};
const _greater_planar_mentor = {title: "Greater Planar Mentor", jsx: <><h2 id="feat-greater_planar_mentor-greater-planar-mentor">Greater Planar Mentor</h2>
<p><strong>Sources</strong> <Link to="/source/plane_hoppers_handbook">Plane-Hopper's Handbook pg. 26</Link></p>
<p>Your mentor begins to look upon you as an equal and can even answer your call.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_planar_mentor">Improved Planar Mentor</Link>, <Link to="/feat/planar_mentor">Planar Mentor</Link>, character level 13th.<br/><strong>Benefit:</strong> You can benefit from your Planar Mentor feat one additional time per day. You add the following to the list of spell-like abilities you can cast using Improved Planar Mentor for their respective alignments, each of which affects only a single target within 30 feet: <Link to="/spell/blasphemy">blasphemy</Link> (evil), <Link to="/spell/dictum">dictum</Link> (lawful), <Link to="/spell/holy_word">holy word</Link> (good), <Link to="/spell/slay_living">slay living</Link> (neutral), and <Link to="/spell/word_of_chaos">word of chaos</Link> (chaotic).</p>
<p>Once per week you can cast <Link to="/spell/greater_planar_ally">greater planar ally</Link> as a spell-like ability, but only to conjure your planar mentor. Your mentor requires only half the normal payment for its services.</p>
</>};
const _greater_ray_shield = {title: "Greater Ray Shield", jsx: <><h2 id="feat-greater_ray_shield-greater-ray-shield-combat-shield-mastery">Greater Ray Shield (Combat, Shield Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 18</Link></p>
<p>You can turn your shield to deflect rays and other ranged attacks without harming it.<br/><strong>Prerequisites:</strong> Dex 17, <Link to="/feat/missile_shield">Missile Shield</Link>, <Link to="/feat/ray_shield">Ray Shield</Link>, <Link to="/feat/spellbreaker">Spellbreaker</Link>.<br/><strong>Benefit:</strong> When you use the Ray Shield feat, your shield is not affected by the deflected ranged touch attack.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_ray_shield--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_ray_shield-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 20</Link><br/>When you successfully deflect a ranged touch attack, you can spend 10 stamina points as a swift or immediate action to reflect the attack toward another target, which must be within 60 feet of you. The total distance from the original attacker, to you, and then to the new target cannot exceed the original attack's maximum range. You take a -5 penalty on the ranged touch attack to hit the new target.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_rending_fury = {title: "Greater Rending Fury", jsx: <><h2 id="feat-greater_rending_fury-greater-rending-fury-combat">Greater Rending Fury (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 103</Link></p>
<p>When your claws latch on to an opponent, the effect is bloody and horrific.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_rending_fury">Improved Rending Fury</Link>, <Link to="/feat/rending_fury">Rending Fury</Link>, base attack bonus +12, <Link to="/umr/rend">rend</Link> special attack.<br/><strong>Benefit:</strong> Whenever you rend an opponent, you deal 1d6 <Link to="/umr/bleed">bleed</Link> damage to that opponent. This is an addition to the effects of the rend.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_rending_fury--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_rending_fury-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>When you rend an opponent, you can spend 2 stamina points to deal 1d6+2 points of bleed damage to your opponent instead of 1d6 points of bleed damage.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_reposition = {title: "Greater Reposition", jsx: <><h2 id="feat-greater_reposition-greater-reposition-combat">Greater Reposition (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 161</Link></p>
<p>When you reposition foes, they are left vulnerable to the attacks of your allies.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_reposition">Improved Reposition</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/rule/reposition">reposition</Link> a foe. This bonus stacks with the bonus granted by Improved Reposition. Whenever you reposition a foe, his movement provokes attacks of opportunity from all of your allies (but not you).<br/><strong>Normal:</strong> Creatures moved by reposition do not provoke attacks of opportunity.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_reposition--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_reposition-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>You can select this feat even if you don't meet the ability score prerequisite (Intelligence 13). You gain the benefits of this feat only as long as you have at least 1 stamina point in your stamina pool. When attempting to reposition a foe, you can spend 5 stamina points to increase your melee reach by 5 feet for the purpose of determining where you can move the foe.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_school_familiar = {title: "Greater School Familiar", jsx: <><h2 id="feat-greater_school_familiar-greater-school-familiar">Greater School Familiar</h2>
<p><strong>Sources</strong> <Link to="/source/familiar_folio">Familiar Folio pg. 14</Link></p>
<p>Your school familiar's powers are greater than others of its kind.<br/><strong>Prerequisites:</strong> <Link to="/feat/school_familiar">School Familiar</Link>, wizard level 10th, specialized arcane school class feature.<br/><strong>Benefit:</strong> Your school <Link to="/sidekick/familiar">familiar</Link> gains the greater school power from the <Link to="/arc-familiar/school_familiar">school familiar</Link> archetype.</p>
</>};
const _greater_serpent_lash = {title: "Greater Serpent Lash", jsx: <><h2 id="feat-greater_serpent_lash-greater-serpent-lash-combat">Greater Serpent Lash (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/rival_guide">Rival Guide pg. 23</Link></p>
<p>Your ability to disarm and pull foes off balance with your whip is impressive.<br/><strong>Prerequisites:</strong> <Link to="/feat/serpent_lash">Serpent Lash</Link>, base attack bonus +4.<br/><strong>Benefit:</strong> When you make a successful <Link to="/rule/disarm">disarm</Link> or <Link to="/rule/trip">trip</Link> maneuver using the Serpent Lash feat, you can make your additional disarm or trip attempt against any target within your whip's reach. With a <Link to="/rule/reposition">reposition</Link> maneuver, you can move the target creature to any point within your whip's reach.</p>
</>};
const _greater_shield_focus = {title: "Greater Shield Focus", jsx: <><h2 id="feat-greater_shield_focus-greater-shield-focus-combat">Greater Shield Focus (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 125</Link></p>
<p>You are skilled at deflecting blows with your shield.<br/><strong>Prerequisites:</strong> <Link to="/feat/shield_focus">Shield Focus</Link>, <Link to="/feat/shield_proficiency">Shield Proficiency</Link>, base attack bonus +1, 8th-level fighter.<br/><strong>Benefit:</strong> Increase the AC bonus granted by any shield you are using by 1. This bonus stacks with the bonus granted by Shield Focus.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_shield_focus--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_shield_focus-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>When an attack is made against you while you are using a shield, you can spend up to 4 stamina points. For that attack, your shield bonus increases by an amount equal to the number of stamina points you spent. This increase does not stack with any gained from the Shield Focus combat trick.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_shield_focus--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You are skilled at deflecting blows with your shield.<br/><strong>Prerequisites:</strong> Shield Focus, Shield Proficiency, base attack bonus +1, 8th-level fighter.<br/><strong>Benefit:</strong> Increase the AC bonus granted by any shield you are using by 1. This bonus stacks with the bonus granted by Shield Focus. Additionally, the AC bonus against ranged weapons granted by Shield Focus now affects ranged touch attacks (including rays and similar magical effects).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_shield_specialization = {title: "Greater Shield Specialization", jsx: <><h2 id="feat-greater_shield_specialization-greater-shield-specialization-combat">Greater Shield Specialization (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 162</Link></p>
<p>Your masterful shieldwork provides even greater protection to your vital areas.<br/><strong>Prerequisites:</strong> Proficiency with selected shield, <Link to="/feat/greater_shield_focus">Greater Shield Focus</Link>, <Link to="/feat/shield_focus">Shield Focus</Link>, <Link to="/feat/shield_specialization">Shield Specialization</Link> with selected shield, fighter level 12th.<br/><strong>Benefit:</strong> Choose one type of shield (buckler, light, heavy, or tower shield) for which you possess the Shield Specialization feat. With the selected shield, you gain a +2 bonus to your Armor Class against critical hit confirmation rolls (this bonus stacks with that from Shield Specialization). In addition, once per day you may negate a critical hit, and damage is instead rolled normally.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, it applies to a new type of shield.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_shield_specialization--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_shield_specialization-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>You can spend 5 stamina points to use your selected shield to negate a critical hit a second time each day.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_skalds_vigor = {title: "Greater Skald's Vigor", jsx: <><h2 id="feat-greater_skalds_vigor-greater-skalds-vigor">Greater Skald's Vigor</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 149</Link></p>
<p>Your song and your enthusiasm invigorate your allies.<br/><strong>Prerequisites:</strong> <Link to="/feat/skalds_vigor">Skald's Vigor</Link>, Perform (sing) 10 ranks.<br/><strong>Benefit:</strong> Your allies share in the <Link to="/umr/fast_healing">fast healing</Link> granted by your Skald's Vigor, starting in the round when you begin your performance. They must be able to hear the performance. If you stop maintaining the song, the fast healing ends immediately, even if other effects of your song linger.</p>
</>};
const _greater_snap_shot = {title: "Greater Snap Shot", jsx: <><h2 id="feat-greater_snap_shot-greater-snap-shot-combat">Greater Snap Shot (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 103</Link></p>
<p>You can prey on any gap in your foe's guard with impunity, and with even greater range.<br/><strong>Prerequisites:</strong> Dex 17, <Link to="/feat/improved_snap_shot">Improved Snap Shot</Link>, <Link to="/feat/rapid_shot">Rapid Shot</Link>, <Link to="/feat/snap_shot">Snap Shot</Link>, base attack bonus +12.<br/><strong>Benefit:</strong> Whenever you make an attack of opportunity using a ranged weapon and hit, you gain a +2 bonus on the damage roll and a +2 bonus on rolls to confirm a critical hit with that attack. These bonuses increase to +4 when you have base attack bonus +16, and to +6 when you have base attack bonus +20.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_snap_shot--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_snap_shot-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>When you make an attack of opportunity using a ranged weapon, you can spend 3 stamina points to gain your bonus from Greater Snap Shot on the attack roll.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_spell_focus = {title: "Greater Spell Focus", jsx: <><h2 id="feat-greater_spell_focus-greater-spell-focus">Greater Spell Focus</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 125</Link></p>
<p>Choose a school of magic to which you have already applied the <Link to="/feat/spell_focus">Spell Focus</Link> feat. Any spells you cast of this school are very hard to resist.<br/><strong>Prerequisites:</strong> Spell Focus.<br/><strong>Benefit:</strong> Add +1 to the Difficulty Class for all saving throws against spells from the school of magic you select. This bonus stacks with the bonus from Spell Focus.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, it applies to a new school to which you already have applied the Spell Focus feat.</p>
</>};
const _greater_spell_penetration = {title: "Greater Spell Penetration", jsx: <><h2 id="feat-greater_spell_penetration-greater-spell-penetration">Greater Spell Penetration</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 125</Link></p>
<p>Your spells break through spell resistance much more easily than most.<br/><strong>Prerequisites:</strong> <Link to="/feat/spell_penetration">Spell Penetration</Link>.<br/><strong>Benefit:</strong> You get a +2 bonus on caster level checks (1d20 + caster level) made to overcome a creature's spell resistance. This bonus stacks with the one from Spell Penetration.</p>
</>};
const _greater_spell_specialization = {title: "Greater Spell Specialization", jsx: <><h2 id="feat-greater_spell_specialization-greater-spell-specialization">Greater Spell Specialization</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 152</Link></p>
<p>You can sacrifice a prepared spell in order to spontaneously cast your specialized spell.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/spell_focus">Spell Focus</Link>, <Link to="/feat/spell_specialization">Spell Specialization</Link>, able to prepare 5th-level spells.<br/><strong>Benefit:</strong> By sacrificing a prepared spell of the same or higher level than your specialized spell, you may spontaneously cast your specialized spell. The specialized spell is treated as its normal level, regardless of the spell slot used to cast it. You may add a metamagic feat to the spell by increasing the spell slot and casting time, just like a <Link to="/class/cleric">cleric</Link> spontaneously casting a cure or inflict spell with a metamagic feat.</p>
</>};
const _greater_spelleater = {title: "Greater Spelleater", jsx: <><h2 id="feat-greater_spelleater-greater-spelleater">Greater Spelleater</h2>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins pg. 12</Link></p>
<p>Your ability to defeat magic has grown stronger with use.<br/><strong>Prerequisites:</strong> Cha 13, character level 5th, <Link to="/race/ghoran">ghoran</Link>, spelleater racial trait.<br/><strong>Benefit:</strong> Once per week, instead of casting <Link to="/spell/dispel_magic">dispel magic</Link> as a spell-like ability, you can cast <Link to="/spell/greater_dispel_magic">greater dispel magic</Link>. This exhausts your daily use of <em>dispel magic</em> granted by the spelleater racial trait. In all other respects, this ability is treated as the spelleater racial trait.</p>
</>};
const _greater_spring_attack = {title: "Greater Spring Attack", jsx: <><h2 id="feat-greater_spring_attack-greater-spring-attack-combat">Greater Spring Attack (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 113</Link></p>
<p>You are a scything wind cutting through the battlefield as you topple your foes.<br/><strong>Prerequisites:</strong> Dex 17, <Link to="/feat/acrobatic_steps">Acrobatic Steps</Link>, <Link to="/feat/dodge">Dodge</Link>, <Link to="/feat/improved_spring_attack">Improved Spring Attack</Link>, <Link to="/feat/mobility">Mobility</Link>, <Link to="/feat/nimble_moves">Nimble Moves</Link>, <Link to="/feat/spring_attack">Spring Attack</Link>, base attack bonus +16.<br/><strong>Benefit:</strong> When you use Spring Attack, you can select three targets to attack during your movement instead of one. The second attack made this way is made at your full base attack bonus - 5, and the third attack made this way is made at your full base attack bonus - 10. All restrictions of Spring Attack apply to each target, and your movement does not provoke attacks of opportunity from any of your targets. You can't target the same creature more than once.<br/><strong>Special:</strong> A monk of at least 18th level can select this feat as a monk bonus feat, but only if he has Improved Spring attack and Spring Attack.</p>
</>};
const _greater_steal = {title: "Greater Steal", jsx: <><h2 id="feat-greater_steal-greater-steal-combat">Greater Steal (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 162</Link></p>
<p>You have a knack for snatching items from your opponents in combat.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_steal">Improved Steal</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/rule/steal">steal</Link> an item from a foe. This bonus stacks with the bonus granted by Improved Steal. If you successfully steal an item from a foe during combat, it does not notice the theft until after combat is over or if it attempts to use the missing item.<br/><strong>Normal:</strong> Creatures automatically notice items taken from them through the steal combat maneuver.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_steal--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_steal-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>You can select this feat even if you don't meet the ability score prerequisite (Intelligence 13). You gain the benefits of this feat only as long as you have at least 1 stamina point in your stamina pool. When attempting a steal combat maneuver with a whip, you can spend 2 stamina points to negate the -4 penalty on the check.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_stylized_spell = {title: "Greater Stylized Spell", jsx: <><h2 id="feat-greater_stylized_spell-greater-stylized-spell">Greater Stylized Spell</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_intrigue">Inner Sea Intrigue pg. 16</Link></p>
<p>You can modify your spell's superficial qualities in a greater variety of ways.<br/><strong>Prerequisites:</strong> <Link to="/feat/stylized_spell">Stylized Spell</Link>, Bluff 10 ranks, Spellcraft 10 ranks.<br/><strong>Benefit:</strong> When you modify a spell with Stylized Spell, you can apply one of the stylized magic options (see the Stylized Spell metamagic feat) without reducing the DC of the check to identify the spell. In addition, you can apply up to two additional stylized magic options, reducing the DC of checks to identify the spell by 5 per option as normal.</p>
</>};
const _greater_subjective_slam = {title: "Greater Subjective Slam", jsx: <><h2 id="feat-greater_subjective_slam-greater-subjective-slam-combat">Greater Subjective Slam (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 28</Link></p>
<p>Your gravitational impact is meteoric, and your ability to use the act of falling devastating.<br/><strong>Prerequisites:</strong> Con 15; Wis 15; <Link to="/feat/subjective_mobility">Subjective Mobility</Link>; <Link to="/feat/subjective_slam">Subjective Slam</Link>; base attack bonus +8 or monk level 7th.<br/><strong>Benefit:</strong> When using Subjective Slam, you take only a -1 penalty on the combat maneuver check for every 100 feet of falling speed, and the maximum damage for such a slam increases to 12d6.</p>
</>};
const _greater_sunder = {title: "Greater Sunder", jsx: <><h2 id="feat-greater_sunder-greater-sunder-combat">Greater Sunder (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 125</Link></p>
<p>Your devastating strikes cleave through weapons and armor and into their wielders, damaging both item and wielder alike in a single terrific strike.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_sunder">Improved Sunder</Link>, <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +6, Str 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/rule/sunder">sunder</Link> an item. This bonus stacks with the bonus granted by Improved Sunder. Whenever you sunder to destroy a weapon, shield, or suit of armor, any excess damage is applied to the item's wielder. No damage is transferred if you decide to leave the item with 1 hit point.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_sunder--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_sunder-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 121</Link><br/>When you succeed at a sunder combat maneuver check, you can spend a number of stamina points up to your Strength bonus to deal an amount of extra damage to the target equal to double the number of stamina points you spent. The damage type is the same as that of the weapon you used to attempt the maneuver.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_sunder--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>Your devastating strikes cleave through weapons and armor and into their wielders, damaging both item and wielder alike in a single terrific strike.<br/><strong>Prerequisites:</strong> <Link to="/rule/powerful_maneuvers">Powerful Maneuvers</Link>, base attack bonus +6, Str 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/rule/sunder">sunder</Link> an item. This bonus stacks with the bonus granted by Powerful Maneuvers. Whenever you sunder to destroy a weapon, shield, or suit of armor, any excess damage is applied to the item's wielder. No damage is transferred if you decide to leave the item with 1 hit point.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_tenacious_hunter = {title: "Greater Tenacious Hunter", jsx: <><h2 id="feat-greater_tenacious_hunter-greater-tenacious-hunter">Greater Tenacious Hunter</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 218</Link></p>
<p>The animal is capable of savaging hidden foes when they least expect it.<br/><strong>Prerequisites:</strong> <Link to="/feat/combat_reflexes">Combat Reflexes</Link>, <Link to="/feat/tenacious_hunter">Tenacious Hunter</Link>, Perception 3 ranks, Stealth 3 ranks, <Link to="/sidekick/animal_companion">animal companion</Link>.<br/><strong>Benefit:</strong> The animal companion can attempt a Perception check as a swift action to intentionally search for a stimulus. When using Perception to attempt to pinpoint an invisible foe, the animal companion's bonus from the Tenacious Hunter feat increases to +20. In addition, whenever the animal companion successfully uses Perception to oppose a Stealth check or to pinpoint an invisible creature's location, that foe is denied its Dexterity bonus to AC against all attacks that the animal companion makes before the start of the animal companion's next turn.<br/><strong>Normal:</strong> Using Perception to intentionally search for a stimulus is a move action.</p>
</>};
const _greater_trip = {title: "Greater Trip", jsx: <><h2 id="feat-greater_trip-greater-trip-combat">Greater Trip (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 126</Link></p>
<p>You can make free attacks on foes that you knock down.<br/><strong>Prerequisites:</strong> <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_trip">Improved Trip</Link>, base attack bonus +6, Int 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/rule/trip">trip</Link> a foe. This bonus stacks with the bonus granted by Improved Trip. Whenever you successfully trip an opponent, that opponent provokes attacks of opportunity.<br/><strong>Normal:</strong> Creatures do not provoke attacks of opportunity from being tripped.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_trip--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_trip-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>You can select this feat even if you don't meet the ability score prerequisite (Intelligence 13). You gain the benefits of this feat only as long as you have at least 1 stamina point in your stamina pool. You can spend 2 stamina points after you successfully trip an opponent to deal 1d6 points of falling damage to the target.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_trip--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You can make free attacks on foes that you knock down.<br/><strong>Prerequisites:</strong> <Link to="/rule/deft_maneuvers">Deft Maneuvers</Link>, base attack bonus +6, Int 13.<br/><strong>Benefit:</strong> You receive a +2 bonus on checks made to <Link to="/rule/trip">trip</Link> a foe. This bonus stacks with the bonus granted by Deft Maneuvers. Whenever you successfully trip an opponent, that opponent provokes attacks of opportunity.<br/><strong>Normal:</strong> Creatures do not provoke attacks of opportunity from being tripped.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_two_weapon_fighting = {title: "Greater Two-Weapon Fighting", jsx: <><h2 id="feat-greater_two_weapon_fighting-greater-two-weapon-fighting-combat">Greater Two-Weapon Fighting (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 126</Link></p>
<p>You are incredibly skilled at fighting with two weapons at the same time.<br/><strong>Prerequisites:</strong> Dex 19, <Link to="/feat/improved_two_weapon_fighting">Improved Two-Weapon Fighting</Link>, <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link>, base attack bonus +11.<br/><strong>Benefit:</strong> You get a third attack with your off-hand weapon, albeit at a -10 penalty.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_two_weapon_fighting--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_two_weapon_fighting-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>If you hit with the third attack granted by this feat and your base attack bonus is 16 or higher, you can spend 2 stamina points to make another attack with your off hand at a -15 penalty.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_two_weapon_fighting--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>You are skilled at fighting with two weapons.<br/><strong>Prerequisites:</strong> Dex 15, Two-Weapon Fighting, base attack bonus +6.<br/><strong>Benefit:</strong> In addition to the standard single extra attack you get with an off-hand weapon, you get a second attack with it, albeit at a -5 penalty. When your base attack bonus reaches +11, you also gain a third attack with your off-hand weapon, albeit at a -10 penalty.<br/><strong>Normal:</strong> Without this feat, you can only get a single extra attack with an off-hand weapon.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_uncivilized_tactics = {title: "Greater Uncivilized Tactics", jsx: <><h2 id="feat-greater_uncivilized_tactics-greater-uncivilized-tactics-combat">Greater Uncivilized Tactics (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 23</Link></p>
<p>Your foes find it difficult to recover from your rough-and-tumble combat style and debilitating attacks.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/improved_uncivilized_tactics">Improved Uncivilized Tactics</Link>, <Link to="/feat/power_attack">Power Attack</Link>, <Link to="/feat/uncivilized_tactics">Uncivilized Tactics</Link>.<br/><strong>Benefit:</strong> You gain a +2 bonus on checks to use Uncivilized Tactics. This bonus stacks with the bonus granted by Improved Uncivilized Tactics. Additionally, a foe must take a full-round action to recover the use of a limb or natural attack you've incapacitated with Uncivilized Tactics.<br/><strong>Normal:</strong> As a standard action, a foe can regain the use of a limb or natural attack incapacitated with Uncivilized Tactics.</p>
</>};
const _greater_vital_strike = {title: "Greater Vital Strike", jsx: <><h2 id="feat-greater_vital_strike-greater-vital-strike-combat">Greater Vital Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 126</Link></p>
<p>You can make a single attack that deals incredible damage.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_vital_strike">Improved Vital Strike</Link>, <Link to="/feat/vital_strike">Vital Strike</Link>, base attack bonus +16.<br/><strong>Benefit:</strong> When you use the attack action, you can make one attack at your highest base attack bonus that deals additional damage. Roll the weapon's damage dice for the attack four times and add the results together before adding bonuses from Strength, weapon abilities (such as <Link to="/magic-enh/flaming">flaming</Link>), precision based damage, and other damage bonuses. These extra weapon damage dice are not multiplied on a critical hit, but are added to the total.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_vital_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_vital_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When using the Vital Strike combat trick, you can spend 4 stamina points instead of 2 to reroll four damage dice.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_weapon_focus = {title: "Greater Weapon Focus", jsx: <><h2 id="feat-greater_weapon_focus-greater-weapon-focus-combat">Greater Weapon Focus (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 126</Link></p>
<p>Choose one type of weapon (including unarmed strike or grapple) for which you have already selected Weapon Focus. You are a master at your chosen weapon.<br/><strong>Prerequisites:</strong> Proficiency with selected weapon, <Link to="/feat/weapon_focus">Weapon Focus</Link> with selected weapon, base attack bonus +1, 8th-level fighter.<br/><strong>Benefit:</strong> You gain a +1 bonus on attack rolls you make using the selected weapon. This bonus stacks with other bonuses on attack rolls, including those from Weapon Focus.<br/><strong>Special:</strong> You can gain Greater Weapon Focus multiple times. Its effects do not stack. Each time you take the feat, it applies to a new type of weapon.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_weapon_focus--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_weapon_focus-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>Once per round, you can spend 2 stamina points to gain your Greater Weapon Focus bonus on attack rolls with another weapon. This bonus lasts until the start of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_weapon_focus--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>Choose one <Link to="/ability/weapon_groups">weapon group</Link> listed under the fighter's Weapon Training class feature for which you have already selected Weapon Focus. You are a master at your chosen weapon type.<br/><strong>Prerequisites:</strong> <Link to="/feat/weapon_focus">Weapon Focus</Link> with the selected weapon group, base attack bonus +1, 8th-level fighter.<br/><strong>Benefit:</strong> You gain a +1 bonus on attack rolls you make using the selected weapon. This bonus stacks with other bonuses on attack rolls, including those from Weapon Focus.<br/><strong>Special:</strong> You can gain Greater Weapon Focus multiple times. Its effects do not stack. Each time you take the feat, it applies to a new weapon group.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_weapon_of_the_chosen = {title: "Greater Weapon of the Chosen", jsx: <><h2 id="feat-greater_weapon_of_the_chosen-greater-weapon-of-the-chosen-combat">Greater Weapon of the Chosen (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 149</Link></p>
<p>Your deity guides your hand when you fight with her favored weapon.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_weapon_of_the_chosen">Improved Weapon of the Chosen</Link>, <Link to="/feat/weapon_focus">Weapon Focus</Link> with deity's favored weapon, <Link to="/feat/weapon_of_the_chosen">Weapon of the Chosen</Link>, worship and receive spells from a deity.<br/><strong>Benefit:</strong> When you use your deity's favored weapon to attempt a single attack with the attack action, you roll two dice for your attack roll and take the higher result. You do not need to use your Weapon of the Chosen feat to gain this feat's benefit. As usual, the reroll does not apply to any confirmation rolls.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_weapon_of_the_chosen--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_weapon_of_the_chosen-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When making an attack as part of a full attack with the weapon designated by your Weapon of the Chosen feat, you can spend 5 stamina points to gain the benefits of this feat on that attack.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_weapon_shift = {title: "Greater Weapon Shift", jsx: <><h2 id="feat-greater_weapon_shift-greater-weapon-shift">Greater Weapon Shift</h2>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins pg. 9</Link></p>
<p>In animal form, your natural attacks are as deadly as the weapons you were holding.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_weapon_shift">Improved Weapon Shift</Link>, <Link to="/feat/weapon_shift">Weapon Shift</Link>, base attack bonus +8, wild shape class feature.<br/><strong>Benefit:</strong> When you apply a melee weapon's damage type and properties to your natural attacks using the Weapon Shift feat, your natural attacks also gain an enhancement bonus on attack and damage rolls equal to the enhancement bonus (if any) of the weapon.</p>
</>};
const _greater_weapon_specialization = {title: "Greater Weapon Specialization", jsx: <><h2 id="feat-greater_weapon_specialization-greater-weapon-specialization-combat">Greater Weapon Specialization (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 126</Link></p>
<p>Choose one type of weapon (including unarmed strike or grapple) for which you possess the Weapon Specialization feat. Your attacks with the chosen weapon are more devastating than normal.<br/><strong>Prerequisites:</strong> Proficiency with selected weapon, <Link to="/feat/greater_weapon_focus">Greater Weapon Focus</Link> with selected weapon, <Link to="/feat/weapon_focus">Weapon Focus</Link> with selected weapon, <Link to="/feat/weapon_specialization">Weapon Specialization</Link> with selected weapon, 12th-level fighter.<br/><strong>Benefit:</strong> You gain a +2 bonus on all damage rolls you make using the selected weapon. This bonus to damage stacks with other damage roll bonuses, including any you gain from Weapon Specialization.<br/><strong>Special:</strong> You can gain Greater Weapon Specialization multiple times. Its effects do not stack. Each time you take the feat, it applies to a new type of weapon.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_weapon_specialization--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_weapon_specialization-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>Once per round, you can spend 2 stamina points to gain your Greater Weapon Specialization bonus on damage rolls with another weapon. This bonus lasts until the start of your next turn.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-greater_weapon_specialization--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>Choose one <Link to="/ability/weapon_groups">weapon group</Link> listed under the fighter's Weapon Training class feature for which you possess the Weapon Specialization feat. Your attacks with these weapons are more devastating than normal.<br/><strong>Prerequisites:</strong> <Link to="/feat/greater_weapon_focus">Greater Weapon Focus</Link> with the selected weapon group, <Link to="/feat/weapon_specialization">Weapon Specialization</Link> with the selected weapon group, 12th-level fighter.<br/><strong>Benefit:</strong> You gain a +2 bonus on all damage rolls you make using any weapon from the selected group. This bonus to damage stacks with other damage roll bonuses, including any you gain from Weapon Specialization.<br/><strong>Special:</strong> You can gain Greater Weapon Specialization multiple times. Its effects do not stack. Each time you take the feat, it applies to a new weapon group.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_whip_mastery = {title: "Greater Whip Mastery", jsx: <><h2 id="feat-greater_whip_mastery-greater-whip-mastery-combat">Greater Whip Mastery (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 103</Link></p>
<p>You can use a whip to make combat maneuvers with ease.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_whip_mastery">Improved Whip Mastery</Link>, <Link to="/feat/whip_mastery">Whip Mastery</Link>, base attack bonus +8.<br/><strong>Benefit:</strong> You are so quick with your <Link to="/eq-weapon/whip">whip</Link> that you never drop it due to a failed <Link to="/rule/disarm">disarm</Link> or <Link to="/rule/trip">trip</Link> combat maneuver attempt. Further, you gain the ability to <Link to="/rule/grapple">grapple</Link> using your whip. To do so, use the normal grapple rules with the following changes.</p>
<blockquote>
<p><strong className="hl">Attack:</strong> You cannot use your whip to attack while you are using it to grapple an opponent.</p>
<p><strong className="hl">Damage:</strong> When dealing damage to your grappled opponent, you deal your whip's weapon damage rather than your unarmed strike damage.</p>
<p><strong className="hl">Free Hands:</strong> You take no penalty on your combat maneuver check for having fewer than two hands free when you use your whip to grapple.</p>
<p><strong className="hl">Reach:</strong> Rather than pulling your grappled opponent adjacent to you when you successfully grapple and when you move the grapple, you must keep him within your whip's reach minus his own reach to maintain the grapple. If the difference in reach is less than 0, such as is the case for a Medium whip wielder and a Gargantuan creature, you cannot grapple that opponent with your whip. If you have to pull a creature adjacent to you to grapple it with your whip, you still provoke an attack of opportunity from that opponent unless you have the <Link to="/feat/improved_grapple">Improved Grapple</Link> feat.</p>
<p><strong className="hl">Tie Up:</strong> While adjacent to your opponent, you can attempt to use your whip to tie him up. If you do so to an opponent you have grappled rather than pinned, you take only a -5 penalty on the combat maneuver check rather than the normal -10.</p>
</blockquote>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-greater_whip_mastery--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-greater_whip_mastery-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When you initiate a grapple with a whip, you can spend 5 stamina points to attempt a second grapple check as a swift action to either move or damage the creature you are grappling. This is not a check to maintain the grapple.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _greater_wild_empathy = {title: "Greater Wild Empathy", jsx: <><h2 id="feat-greater_wild_empathy-greater-wild-empathy">Greater Wild Empathy</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 152</Link></p>
<p>Your natural empathy stretches across the world of nature.<br/><strong>Prerequisites:</strong> Knowledge (nature) 5 ranks, <Link to="/ability/wild_empathy">wild empathy</Link> class feature.<br/><strong>Benefit:</strong> You gain a +2 insight bonus on wild empathy checks, and you may use wild empathy to duplicate an Intimidate check rather than a Diplomacy check. In addition, choose one of the following kinds of creatures: elementals, fey, lycanthropes, plants, or vermin. You may influence creatures of that type with wild empathy, if their Intelligence score is 1 or 2, or they do not possess an Intelligence score. Once you choose the type of creature, it cannot be changed.<br/><strong>Special:</strong> You may select this feat more than once. Each time, you may choose an additional creature type to influence.</p>
</>};
const _greater_wilding_strike = {title: "Greater Wilding Strike", jsx: <><h2 id="feat-greater_wilding_strike-greater-wilding-strike-combat">Greater Wilding Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 113</Link></p>
<p>You reach the pinnacle of your wilding strike abilities.<br/><strong>Prerequisites:</strong> Str 18, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/improved_wilding_strike">Improved Wilding Strike</Link>, <Link to="/feat/wilding">Wilding</Link>, <Link to="/feat/wilding_strike">Wilding Strike</Link>, base attack bonus +16.<br/><strong>Benefit:</strong> The damage die of your unarmed strikes increases to 1d10 (or 1d8 if you are Small). This does not stack with any other effects that increase the damage die of your unarmed strikes, including levels in classes such as <Link to="/class/monk">monk</Link>. Increases to your actual size category (such as <Link to="/spell/enlarge_person">enlarge person</Link>) still increase your damage die as normal.</p>
</>};
const _green_faith_acolyte = {title: "Green Faith Acolyte", jsx: <><h2 id="feat-green_faith_acolyte-green-faith-acolyte">Green Faith Acolyte</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 287</Link>, <Link to="/source/guide_to_darkmoon_vale">Guide to Darkmoon Vale pg. 60</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 218</Link></p>
<p>You have trained to channel your magical energies in ways that do not harm the natural world around you.<br/><strong>Prerequisites:</strong> Follower of the <Link to="/faith/green_faith">Green Faith</Link>.<br/><strong>Benefit:</strong> Spells you cast that deal damage, <Link to="/ability/channel_negative_energy">channel negative energy</Link>, or otherwise harm life do not hurt normal or magical plants. In addition, whenever you cast a spell that utilizes, heals, or enhances normal or magical plants (such as <Link to="/spell/entangle">entangle</Link> or <Link to="/spell/plant_growth">plant growth</Link>), you cast the spell at +1 caster level.</p>
</>};
const _green_tongue = {title: "Green Tongue", jsx: <><h2 id="feat-green_tongue-green-tongue">Green Tongue</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 13</Link></p>
<p>You know the language of the plants.<br/><strong>Prerequisites:</strong> Cha 13, character level 5th, <Link to="/race/gathlain">gathlain</Link>.<br/><strong>Benefit:</strong> You can cast <Link to="/spell/speak_with_plants">speak with plants</Link> once per day, as a spell-like ability. At 10th level and every 5 levels thereafter, you can cast speak with plants an additional time per day.</p>
</>};
const _grenade_expert = {title: "Grenade Expert", jsx: <><h2 id="feat-grenade_expert-grenade-expert">Grenade Expert</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_115_trail_of_the_hunted">Pathfinder #115: Trail of the Hunted pg. 74</Link></p>
<p>You are skilled at both manufacturing and using alchemical grenades.<br/><strong>Prerequisites:</strong> <Link to="/feat/throw_anything">Throw Anything</Link>.<br/><strong>Benefit:</strong> When you light an alchemical grenade (such as a <Link to="/eq-weapon/fuse_grenade">fuse grenade</Link>, <Link to="/eq-weapon/pellet_grenade">pellet grenade</Link>, or <Link to="/eq-weapon/sting_grenade">sting grenade</Link>) you select how many rounds later the grenade explodes (minimum 1 round, maximum 3 rounds). In addition, you gain a +4 bonus on Craft (alchemy) checks to craft grenades.<br/><strong>Normal:</strong> Alchemical grenades explode 1d3 rounds after the fuse is lit.</p>
</>};
const _grisly_ornament = {title: "Grisly Ornament", jsx: <><h2 id="feat-grisly_ornament-grisly-ornament-item-creation">Grisly Ornament (Item Creation)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 24</Link></p>
<p>You adorn your gear with mementos from your foes.<br/><strong>Prerequisites:</strong> <Link to="/feat/harvest_parts">Harvest Parts</Link>.<br/><strong>Benefit:</strong> You can attempt a Craft or Heal check to craft a special type of trophy called an ornament from part of a creature that's been dead for less than an hour. You take a -4 penalty on this check if you or an ally didn't slay the creature. You can craft one ornament per character level per day. Each corpse provides enough material for one ornament plus one additional ornament per size category above Medium. You can wear one ornament in each magic item slot not already occupied by another item. When you craft an ornament, you choose whether it affects Armor Class, attack rolls, CMB, CMD, saving throws, or skill checks. The ornament provides a morale bonus equal to the monster's CR divided by 4 (round down, minimum 1) to the selected statistic against creatures of the same creature type as the source of the ornament. This bonus increases by 1 against creatures of the exact same variety (so a red dragon's talon provides the increased bonus against red dragons but not all dragons). An ornament remains effective for 1 day, plus 1 additional day for every 5 by which you exceed the DC to craft it. You can give ornaments to others, but gifted ornaments have a morale bonus equal to the monster's CR divided by 6 (round down, minimum 0) and remain effective for only 24 hours.</p>
<p>Also see: <Link to="/eq-misc/display_stand">display stand</Link>.</p>
</>};
const _groom = {title: "Groom", jsx: <><h2 id="feat-groom-groom">Groom</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 132</Link></p>
<p>You recruit a professional groom to care for your mount.<br/><strong>Prerequisites:</strong> Character level 4th.<br/><strong>Benefit:</strong> This feat is similar to the <Link to="/feat/leadership">Leadership</Link> feat, with several exceptions to note. You can attract only a 1st-level cohort (referred to hereafter as a groom) with this feat, and cannot recruit followers of his own. You determine your Leadership score according to the rules presented in the Leadership feat, but your groom is always at least 3 levels lower than your level.</p>
<p>A groom can take levels in bard, fighter, or ranger. A groom can't multiclass, though he can take any archetype for which he qualifies.</p>
<p>A groom finds the best place to stable and conceal your mount and the mounts of up to five allies while you and your allies are elsewhere. A groom adds half his level (minimum 1) to Stealth checks when concealing himself and any mounts that are left in his care. A groom also gains the ability to speak with animals as a supernatural ability, but he can use this ability only with horses, riding dogs, and other mounts of the animal type.</p>
<p>If a groom gains enough XP to bring him to 2 levels lower than your level, he doesn't gain the new level until you gain your next level; until you advance, his XP total remains 1 less than the amount needed to attain the next level.</p>
<p>If you release your groom from service or otherwise lose your groom, you can recruit a new one. At 7th level, you can swap this feat for the Leadership feat.</p>
</>};
const _ground_grabber = {title: "Ground-Grabber", jsx: <><h2 id="feat-ground_grabber-ground-grabber-combat">Ground-Grabber (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 23</Link></p>
<p>When pressed by big opponents, you hunker down to more easily keep your feet.<br/><strong>Prerequisites:</strong> Con 13.<br/><strong>Benefit:</strong> You gain a +2 competence bonus to your Combat Maneuver Defense against awesome blow, bull rush, drag, reposition, or trip combat maneuvers from opponents larger than you.</p>
</>};
const _groundling = {title: "Groundling", jsx: <><h2 id="feat-groundling-groundling">Groundling</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 162</Link></p>
<p>You can speak with burrowing animals.<br/><strong>Prerequisites:</strong> Cha 13, <Link to="/race/gnome">gnome</Link>, gnome magic racial trait.<br/><strong>Benefit:</strong> You can use <Link to="/spell/speak_with_animals">speak with animals</Link> as a spell-like ability at will, but only to communicate with burrowing animals like gophers, moles, and the like. You can still use your gnome speak with animals ability once per day to speak with any animal, as usual.</p>
</>};
const _group_deliver_touch_spells = {title: "Group Deliver Touch Spells", jsx: <><h2 id="feat-group_deliver_touch_spells-group-deliver-touch-spells-teamwork">Group Deliver Touch Spells (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/familiar_folio">Familiar Folio pg. 18</Link></p>
<p>You and your teammates can deliver touch spells through each other's familiars.<br/><strong>Prerequisites:</strong> <Link to="/feat/group_shared_spells">Group Shared Spells</Link>, must have a <Link to="/ability/familiar">familiar</Link> with the share spells and deliver touch spells abilities.<br/><strong>Benefit:</strong> You and any allies with this feat can cast spells through one another's familiars as though each ally had the share spells ability with each other familiar. This feat otherwise functions as the share spells ability.</p>
</>};
const _group_shared_spells = {title: "Group Shared Spells", jsx: <><h2 id="feat-group_shared_spells-group-shared-spells-teamwork">Group Shared Spells (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 113</Link>, <Link to="/source/familiar_folio">Familiar Folio pg. 18</Link></p>
<p>You and your allies can cast spells through each other's familiars as if they were your own.<br/><strong>Prerequisites:</strong> <Link to="/ability/familiar">Familiar</Link> with the share spells ability.<br/><strong>Benefit:</strong> You and any of your allies with this feat can cast spells with a target of "you" on each other's familiars as touch spells. Both the target familiar and that familiar's master must be willing for the spell to take effect. You can cast spells on each other's familiars even if the spells would not normally affect creatures of the targeted familiar's type.</p>
</>};
const _grow_plant_creature = {hasJL:true,title: "Grow Plant Creature", jsx: <><div className="jumpList" id="feat-grow_plant_creature-jumplist"><h2>Jump to:</h2><ul><li><InnerLink toTop to="feat-grow_plant_creature-assassin-vine">Assassin Vine</InnerLink></li><li><InnerLink toTop to="feat-grow_plant_creature-treant">Treant</InnerLink></li><li><InnerLink toTop to="feat-grow_plant_creature-viper-vine">Viper Vine</InnerLink></li></ul></div><h2 id="feat-grow_plant_creature-grow-plant-creature-item-creation">Grow Plant Creature (Item Creation)</h2>
<p><strong>Sources</strong> <Link to="/source/cohorts_and_companions">Cohorts and Companions pg. 20</Link></p>
<p>Through careful study and communion with nature, you have learned how to cultivate and raise plant creatures.<br/><strong>Prerequisites:</strong> <Link to="/feat/train_plants">Train Plants</Link>, Handle Animal 5 ranks, Knowledge (nature) 5 ranks.</p>
<p>Each plant creature has a list of additional prerequisites, costs, and skill checks required to grow them. At the GM's discretion, characters with this feat may grow other plant creatures as well.</p>
<h3 id="feat-grow_plant_creature-growing-plant-creatures">Growing Plant Creatures</h3>
<p>The process of growing a plant companion is very similar to the process of <Link to="/family/leshy">growing a leshy</Link>. The creator begins by growing an array of especially verdant plants, and then performs rituals to have a spirit of nature inhabit it. Typically, the creator is a powerful druid, but anyone capable of making the required Knowledge checks and casting the required spells may attempt the process.</p>
<p>Cultivated minions closely resemble more familiar plant creatures - and share the same stat blocks - but are approximated copies woven from horticulture and magic. An "assassin vine" cultivated by a druid using the Grow Plant Creature feat isn't a true assassin vine, and the seeds it produces would sprout into mundane ivy, grape vines, or similar vines originally used to construct it. At the GM's discretion, this may allow druids to grow plant minions with special abilities, such as a peach treant who produces fruit or a viper vine woven from stinging nettles whose touch causes burning welts. Such adjustments should always increase the cost to create a plant creature, and should adjust their challenge rating if they greatly expand the minion's combat abilities or utility.</p>
<p>Growing a plant creature takes 2 weeks per Hit Die, during which the creator must fertilize, water, and protect the growth. During this period, the creator must use certain rare nutrients and fertilizer to prime the transformation from a normal plant into a plant creature; the cost of these components varies according to the type, but is never less than 1,000 gp per Hit Die. The cultivator must succeed at a Knowledge (nature) check at this time in order to properly form the plant body; the exact check as well as the required DC varies according to the creature. If the check fails, the plant withers and dies and the cultivator must begin anew.</p>
<p>If the skill check is successful, the cultivator must then perform a 24-hour awakening ritual. During this ritual, the cultivator must cast the spells detailed in each individual creature's entry. At the awakening ritual's climax, there is a flat 50% chance that the attempt to create the creature succeeds - if this final check fails, no appropriate spirit is close enough to answer the call. The plant body becomes dormant, and remains so for 3 months. After this time, another awakening ritual can be performed (requiring another 1,000 gp of materials); this new ritual also has a flat 50% chance of success. At the GM's discretion, the awakening ritual's chance for success might increase to 75% or even 100% in natural and unspoiled environments appropriate to the individual creature. Discovering such a rare and magical site should be the focus of its own adventure. If the awakening ritual is successful, the creature awakens fully formed. A freshly created plant creature is under no particular compulsion to obey its creator, but most regard their makers as friends and allies.</p>
<p>Plant creatures are particularly adept at growing other plant creatures of the same type. Sentient creatures of the plant type gain a +5 racial bonus on their Knowledge (nature) checks to cultivate other plant creatures, halve the time required to grow the creature, and reduce the materials cost by 25%. A plant creature improves the success chance of any awakening ritual it personally performs by 5% per Hit Die it possesses.</p>
<p>At the GM's discretion, it may be possible to create plant creatures with more Hit Dice than normal. Each additional Hit Die adds 2,250 gp to the cost of creating it (and thus 4,500 gp to the overall price), increases the DC of the Knowledge check by 2, and requires an additional 2 weeks of growth.</p>
<h3 id="feat-grow_plant_creature-assassin-vine" data-hash-target>Assassin Vine</h3>
<p>An <Link to="/monster/assassin_vine">assassin vine</Link> is usually grown deep in a forest or swamp, although it's possible to cultivate an assassin vine among overgrown grape vines if the area is shaded from direct sun.</p>
<p><strong>Price</strong> 7,750 gp</p>
<h4 id="feat-grow_plant_creature-ritual">Ritual</h4>
<p><strong>Requirements</strong> Grow Plant Creature, Knowledge (nature) 5 ranks, <Link to="/spell/entangle">entangle</Link>, <Link to="/spell/summon_natures_ally_iv">summon nature's ally IV</Link>; <strong>Skill Check</strong> Knowledge (nature) DC 16</p>
<h3 id="feat-grow_plant_creature-treant" data-hash-target>Treant</h3>
<p>The ancient knowledge and wisdom possessed by the spirit of a <Link to="/monster/treant">treant</Link> is unmatched. A treant is usually grown in a grove of ancient trees of the predominant local variety.</p>
<p><strong>Price</strong> 25,750 gp</p>
<h4 id="feat-grow_plant_creature-ritual">Ritual</h4>
<p><strong>Requirements</strong> Grow Plant Creature, Knowledge (nature) 10 ranks, Knowledge (geography or history) 4 ranks, <Link to="/spell/liveoak">liveoak</Link>, <Link to="/spell/speak_with_plants">speak with plants</Link>; <strong>Skill Check</strong> Knowledge (nature) DC 24</p>
<h3 id="feat-grow_plant_creature-viper-vine" data-hash-target>Viper Vine</h3>
<p>Terrifying and deadly, <Link to="/monster/viper_vine">viper vines</Link> make excellent guardians. A viper vine is usually grown in jungles or swamps.</p>
<p><strong>Price</strong> 43,750 gp</p>
<h4 id="feat-grow_plant_creature-ritual">Ritual</h4>
<p><strong>Requirements</strong> Grow Plant Creature, Knowledge (nature) 12 ranks, <em>entangle,</em> <Link to="/spell/summon_natures_ally_vii">summon nature's ally VII</Link>; <strong>Skill Check</strong> Knowledge (nature) DC 32</p>
</>};
const _growth_in_ash = {title: "Growth in Ash", jsx: <><h2 id="feat-growth_in_ash-growth-in-ash">Growth in Ash</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 6</Link></p>
<p>You're aware that when fire passes, growth can begin.<br/><strong>Benefit:</strong> When you succeed at a Reflex save to avoid <Link to="/rule/catching_on_fire">catching on fire</Link>, or when you cease taking ongoing fire damage from a spell or effect, you can smear ash on yourself as an immediate action to gain <Link to="/umr/fast_healing">fast healing</Link> 1 for 3 rounds. For every Hit Die you have beyond 3, extend the duration of this fast healing by an additional round.</p>
</>};
const _grudge_fighter = {title: "Grudge Fighter", jsx: <><h2 id="feat-grudge_fighter-grudge-fighter-combat">Grudge Fighter (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 141</Link></p>
<p>You feel great anger at anyone who dares to attack you, and this fury makes your own attacks that much stronger.<br/><strong>Prerequisites:</strong> <Link to="/race/orc">Orc</Link>.<br/><strong>Benefit:</strong> You gain a +1 morale bonus on attack and damage rolls made against any creature that attacked you in the current combat.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-grudge_fighter--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-grudge_fighter-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When you hit a creature that attacked you in the current combat, you can spend up to 2 stamina points to deal an amount of extra damage to it equal to double the number of stamina points you spent.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _gruesome_butcher = {title: "Gruesome Butcher", jsx: <><h2 id="feat-gruesome_butcher-gruesome-butcher-story">Gruesome Butcher (Story)</h2>
<p><strong>Sources</strong> <Link to="/source/agents_of_evil">Agents of Evil pg. 9</Link></p>
<p>You dedicated yourself to the cause of slaughter against a specific group or people, either for country, for vengeance, or perhaps just for sport.<br/><strong>Prerequisites:</strong> You must have been rendered unconscious and left for dead on a battlefield between warring factions or have the Child Soldier (early event) or Drafted (conflict) <Link to="/rule/bad_beginnings">background</Link>.<br/><strong>Benefit:</strong> Select a particular nation, organization, or humanoid subtype (such as Cheliax, <Link to="/rule/eagle_knights">Eagle Knights</Link>, or goblinoids). You gain a +4 bonus on Sense Motive checks to determine whether a given creature is affiliated with that group and a +4 bonus on Bluff and Diplomacy checks to conceal your animosity toward members of that group.<br/><strong>Goal:</strong> Deliver the killing blow to a number of your hated foes whose combined Hit Dice total is equal to 10 &times; your current character level.<br/><strong>Completion Benefit:</strong> You gain a +2 bonus on Bluff, Knowledge, Perception, Sense Motive, and Survival checks against foes of your selected type, and a +2 bonus on weapon attack and damage rolls against them. These bonuses stack with a ranger's <Link to="/ability/favored_enemy">favored enemy</Link> bonuses.<br/><strong>Special:</strong> By meeting the goal of this feat, your name becomes known to your enemy. Creatures of your chosen enemy faction gain a +1 morale bonus on attack and damage rolls against you should they become aware of your identity with a successful Knowledge (local) check (DC = 10 + your character level).</p>
</>};
const _gruesome_shapechanger = {title: "Gruesome Shapechanger", jsx: <><h2 id="feat-gruesome_shapechanger-gruesome-shapechanger-monster">Gruesome Shapechanger (Monster)</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 88</Link></p>
<p>When you change shape, it is a violent and bloody affair.<br/><strong>Prerequisites:</strong> Shapechanger subtype.<br/><strong>Benefit:</strong> When you change shape, your previous form sloughs off your body in a spray of blood and viscera that congeals into a thick, disgusting slime that dissolves within 24 hours. Until the slime dissolves or is cleaned in some way, the space where you stood when you changed (or the space below if you changed in mid-air) becomes slippery, counting as <Link to="/rule/difficult_terrain">difficult terrain</Link> and increasing the DC of <Link to="/skill/acrobatics">Acrobatics</Link> checks made in that area by 5. Any foe witnessing this gruesome shape change must succeed at a Fortitude save (DC = 10 + 1/2 your Hit Dice + your Constitution modifier) or be <Link to="/misc/sickened">sickened</Link> for 1 minute.<br/><strong>Special:</strong> The gruesome way you change shape is tiring. Once you've used your change shape ability, you must wait 1d4 rounds before you can use it again. If you take this feat, it changes the way your shapechanging ability works; you cannot choose to avoid this feat's effects.</p>
</>};
const _gruesome_slaughter = {title: "Gruesome Slaughter", jsx: <><h2 id="feat-gruesome_slaughter-gruesome-slaughter-combat">Gruesome Slaughter (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 150</Link></p>
<p>You can inspire extreme revulsion when you slaughter your enemies.<br/><strong>Prerequisites:</strong> <Link to="/feat/intimidating_prowess">Intimidating Prowess</Link>, <Link to="/feat/killing_flourish">Killing Flourish</Link>, Intimidate 11 ranks, slayer level 11th.<br/><strong>Benefit:</strong> Creatures you demoralize by using the Killing Flourish feat must succeed at a Fortitude save (DC = 10 + 1/2 your character level + the higher of your Strength or Dexterity modifier) or become <Link to="/misc/sickened">sickened</Link> for 1 minute.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-gruesome_slaughter--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-gruesome_slaughter-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When using this feat, you can spend up to 5 stamina points to increase the DC of the effect by an amount equal to the number of stamina points you spent.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _guarded_charge = {title: "Guarded Charge", jsx: <><h2 id="feat-guarded_charge-guarded-charge-combat-shield-mastery">Guarded Charge (Combat, Shield Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 18</Link></p>
<p>Your raised shield protects you as you charge forward.<br/><strong>Prerequisites:</strong> <Link to="/feat/shield_focus">Shield Focus</Link>, base attack bonus +6 or fighter level 4th.<br/><strong>Benefit:</strong> When performing a bull rush or overrun combat maneuver as part of a charge, you don't provoke an attack of opportunity for that maneuver. If you already have the <Link to="/feat/improved_bull_rush">Improved Bull Rush</Link> or <Link to="/feat/improved_overrun">Improved Overrun</Link> feats, you gain an additional +2 bonus on your combat maneuver check when attempting the respective maneuver.<br/><strong>Special:</strong> This feat counts as having a Strength score of 13 and <Link to="/feat/power_attack">Power Attack</Link> for the purposes of meeting the prerequisites of Improved Bull Rush and Improved Overrun, and for feats that require either of those two feats as prerequisites.</p>
</>};
const _guardian_of_the_wild = {title: "Guardian of the Wild", jsx: <><h2 id="feat-guardian_of_the_wild-guardian-of-the-wild">Guardian of the Wild</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 28</Link></p>
<p>Your mystic connection with the wilderness enhances your ability to react to threats.<br/><strong>Prerequisites:</strong> <Link to="/feat/attuned_to_the_wild">Attuned to the Wild</Link>, <Link to="/race/elf">elf</Link>.<br/><strong>Benefit:</strong> When you are in a terrain type you have selected the Attuned to the Wild feat for, you gain a +2 dodge bonus to Armor Class. If you are in an area that qualifies as more than one kind of terrain, these bonuses do not stack; you receive the bonus for only one of the terrain types.</p>
</>};
const _guardian_of_tradition = {title: "Guardian of Tradition", jsx: <><h2 id="feat-guardian_of_tradition-guardian-of-tradition">Guardian of Tradition</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_monster_codex">Inner Sea Monster Codex pg. 35</Link></p>
<p>Your deity rewards your devotion to the duty of your race.<br/><strong>Prerequisites:</strong> Domain class feature, <Link to="/monster/girtablilu">girtablilu</Link>.<br/><strong>Benefit:</strong> You can replace one of the domains offered by your deity with one of the following druid domains: <Link to="/druiddomain/desert">Desert</Link>, <Link to="/druiddomain/ruins">Ruins</Link>, or <Link to="/druiddomain/vermin">Vermin</Link>. You gain a +1 bonus to your caster level when casting domain spells from the selected domain.</p>
</>};
const _guardians_return = {title: "Guardian's Return", jsx: <><h2 id="feat-guardians_return-guardians-return-familiar">Guardian's Return (Familiar)</h2>
<p><strong>Sources</strong> <Link to="/source/familiar_folio">Familiar Folio pg. 19</Link></p>
<p>Your familiar can teleport to you when you're in need.<br/><strong>Prerequisites:</strong> Must have a <Link to="/ability/familiar">familiar</Link> with the <Link to="/arc-familiar/protector">protector</Link> archetype.<br/><strong>Benefit:</strong> Once per day when you take damage from a melee attack, as long as your familiar is within empathic link range, it can teleport back to your square as an immediate action. It can bring no more than 5 pounds of items with it when it teleports in this way. This ability otherwise functions as <Link to="/spell/dimension_door">dimension door</Link>.</p>
</>};
const _guided_hand = {title: "Guided Hand", jsx: <><h2 id="feat-guided_hand-guided-hand">Guided Hand</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 103</Link></p>
<p>Your deity blesses any strike you make with that deity's favored weapon.<br/><strong>Prerequisites:</strong> <Link to="/ability/channel_energy">Channel energy</Link> class feature, <Link to="/feat/channel_smite">Channel Smite</Link>, proficiency with your deity's favored weapon.<br/><strong>Benefit:</strong> With your deity's favored weapon, you can use your Wisdom modifier instead of your Strength or Dexterity modifier on attack rolls.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-guided_hand--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Guided Hand</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 66</Link><br/>Attacks made with your deity's favored weapon are divinely inspired.<br/><strong>Prerequisites:</strong> Guided Hand.<br/><strong>Benefit:</strong> When making attacks with your deity's favored weapon, you can add your Wisdom modifier instead of your Strength or Dexterity modifier on damage rolls.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _guided_star = {title: "Guided Star", jsx: <><h2 id="feat-guided_star-guided-star-combat">Guided Star (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/paths_of_the_righteous">Paths of the Righteous pg. 29</Link></p>
<p>The grace of Desna guides your starknife to its target and back to your hand.<br/><strong>Prerequisites:</strong> <Link to="/feat/starry_grace">Starry Grace</Link>, worshiper of <Link to="/faith/desna">Desna</Link>.<br/><strong>Benefit:</strong> You can empower a <Link to="/eq-weapon/starknife">starknife</Link> with magical power once per day per character level as a swift action. Until the end of your turn, add your Wisdom modifier to your damage rolls with the starknife in addition to any other modifiers you normally add. If you throw the starknife during that time, it returns to you at the beginning of your next turn (as per the <Link to="/magic-enh/returning">returning</Link> weapon special ability).</p>
</>};
const _guild_emissary = {title: "Guild Emissary", jsx: <><h2 id="feat-guild_emissary-guild-emissary">Guild Emissary</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_streets">Heroes of the Streets pg. 29</Link></p>
<p>Not only are you associated with a powerful thieves' guild or similar shadowy group, you are well-enough connected to gain benefits when dealing with the underworld in any settlement.<br/><strong>Prerequisites:</strong> <Link to="/feat/leadership">Leadership</Link> or <Link to="/feat/underworld_connections">Underworld Connections</Link> (see below).<br/><strong>Benefit:</strong> You can attempt a special character level check (1d20 + your Charisma modifier + your character level) in place of a <Link to="/skill/diplomacy">Diplomacy</Link> check when attempting to gather information. You can ask local contacts to find information for you. While this still takes the normal amount of time (typically 1d4 hours), you can gather information about multiple topics at once (up to a maximum number of topics equal to 3 + your Charisma bonus).</p>
<p>Additionally, when you are in a <Link to="/rule/the_settlement_stat_block">settlement</Link> no smaller than a small city and are seeking a magic item with a value equal to or less than the city's base value and the item is not available, you can check again after 1 day (rather than 1 week).</p>
<p>If using the <Link to="/rule/contacts">contact rules</Link> you gain a single reliable contact each time you enter a settlement no smaller than a small city. This contact is randomly determined to be a fence, gossip, manipulator, merchant, petty criminal, snitch, or thug. The contact operates only within that city, and if the contact's <Link to="/rule/trust">Trust score</Link> goes down, it immediately drops to 1.</p>
</>};
const _gun_twirling = {title: "Gun Twirling", jsx: <><h2 id="feat-gun_twirling-gun-twirling-grit">Gun Twirling (Grit)</h2>
<p><strong>Sources</strong> <Link to="/source/champions_of_balance">Champions of Balance pg. 19</Link></p>
<p>You can spin and juggle a small firearm, making it difficult to predict where you will shoot.<br/><strong>Prerequisites:</strong> <Link to="/feat/amateur_gunslinger">Amateur Gunslinger</Link> feat or grit class feature, <Link to="/feat/dazzling_display">Dazzling Display</Link>, <Link to="/feat/weapon_focus">Weapon Focus</Link>.<br/><strong>Benefit:</strong> You can spend 1 grit point to make a <Link to="/rule/feint">feint</Link> attempt using a one-handed firearm for which you have Weapon Focus (instead of a melee weapon). The target of this feint must be within 30 feet of you and be able to see you.</p>
<p>If you have the <Link to="/feat/quick_draw">Quick Draw</Link> feat, you can holster a one-handed firearm as a free action as long as you have at least 1 grit point.</p>
</>};
const _gunsmithing = {title: "Gunsmithing", jsx: <><h2 id="feat-gunsmithing-gunsmithing">Gunsmithing</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 103</Link></p>
<p>You know the secrets of repairing and restoring firearms.<br/><strong>Benefit:</strong> If you have access to a <Link to="/eq-misc/gunsmiths_kit">gunsmith's kit</Link>, you can create and restore firearms, craft bullets, and mix black powder for all types of firearms. You do not need to make a Craft check to create firearms and ammunition or to restore firearms.</p>
<p><strong>Crafting Firearms:</strong> You can craft any early <Link to="/main/equipment_firearms">firearm</Link> for a cost in raw materials equal to half the price of the firearm. At your GM's discretion, you can craft advanced firearms for a cost in raw materials equal to half the price of the firearm. Crafting a firearm in this way takes 1 day of work for every 1,000 gp of the firearm's price (minimum 1 day).</p>
<p><strong>Crafting Ammunition:</strong> You can craft <Link to="/eq-weapon/bullet">bullets</Link>, <Link to="/eq-weapon/pellets">pellets</Link>, and <Link to="/eq-weapon/black_powder">black powder</Link> for a cost in raw materials equal to 10% of the price. If you have at least 1 rank in Craft (alchemy), you can craft <Link to="/eq-weapon/alchemical_cartridge">alchemical cartridges</Link> for a cost in raw materials equal to half the price of the cartridge. At your GM's discretion, you can craft metal cartridges for a cost in raw materials equal to half the cost of the cartridge. Crafting bullets, black powder, or cartridges takes 1 day of work for every 1,000 gp of ammunition (minimum 1 day).</p>
<p><strong>Restoring a Broken Firearm:</strong> Each day, with an hour's worth of work, you can use this feat to repair a single firearm with the broken condition. You can take time during a rest period to restore a broken firearm with this feat.</p>
<p><strong>Special:</strong> If you are a <Link to="/class/gunslinger">gunslinger</Link>, this feat grants the following additional benefit. You can use this feat to repair and restore your initial, battered weapon. It costs 300 gp and 1 day of work to upgrade it to a <Link to="/rule/masterwork_w">masterwork</Link> firearm of its type.</p>
</>};
const _half_drow_paragon = {title: "Half-Drow Paragon", jsx: <><h2 id="feat-half_drow_paragon-half-drow-paragon">Half-Drow Paragon</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 47</Link></p>
<p>Your drow blood is particularly strong.<br/><strong>Prerequisites:</strong> Drow-blooded and drow magic racial traits, <Link to="/race/half_elf">half-elf</Link>.<br/><strong>Benefit:</strong> You count as a drow for any effects that relate to race. Furthermore, the spell-like abilities granted to you by your drow magic racial trait count as drow spell-like abilities for the purposes of any feat prerequisites.</p>
</>};
const _halfling_slinger = {title: "Halfling Slinger", jsx: <><h2 id="feat-halfling_slinger-halfling-slinger-combat">Halfling Slinger (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/halflings_of_golarion">Halflings of Golarion pg. 23</Link></p>
<p>You have honed your racial talent for slingcraft.<br/><strong>Prerequisites:</strong> <Link to="/race/halfling">Halfling</Link>.<br/><strong>Benefit:</strong> You gain a +1 racial bonus on attack rolls made using a <Link to="/eq-weapon/sling">sling</Link>.</p>
</>};
const _hamatula_grasp = {title: "Hamatula Grasp", jsx: <><h2 id="feat-hamatula_grasp-hamatula-grasp-combat">Hamatula Grasp (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 27</Link></p>
<p>You deal terrible damage to impaled foes.<br/><strong>Prerequisites:</strong> <Link to="/feat/hamatula_strike">Hamatula Strike</Link>, <Link to="/feat/improved_grapple">Improved Grapple</Link>, Strength 13, base attack bonus +9.<br/><strong>Benefit:</strong> When attacking an impaled opponent with the weapon that impales them, you only suffer a -2 penalty to your grapple check. If the check succeeds, you deal an extra 1d6 damage.</p>
</>};
const _hamatula_strike = {title: "Hamatula Strike", jsx: <><h2 id="feat-hamatula_strike-hamatula-strike-combat">Hamatula Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 27</Link></p>
<p>You can catch your opponents on your weapon and hold them in place.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_grapple">Improved Grapple</Link>, Strength 13, Base Attack Bonus +7.<br/><strong>Benefit:</strong> Whenever you damage an opponent with a piercing weapon, you can immediately make a <Link to="/rule/grapple">grapple</Link> check; success means the opponent is impaled on your weapon and you both gain the grappled condition. While the opponent is impaled, as an attack action you may make a grapple check on your turn at a -4 penalty to damage the opponent with your weapon, even if your weapon cannot normally be used in a grapple.<br/><strong>Normal:</strong> You can only attack with an unarmed strike, natural weapon, or light weapon against opponents you are grappling.</p>
</>};
const _hamatulatsu = {title: "Hamatulatsu", jsx: <><h2 id="feat-hamatulatsu-hamatulatsu-combat">Hamatulatsu (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 287</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 83</Link></p>
<p>You have mastered a deadly fighting form inspired by the hideous attacks of the <Link to="/monster/barbed_devil">barbed devil</Link>.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>.<br/><strong>Benefit:</strong> Your unarmed attacks can deal either bludgeoning or piercing damage. You decide which type of damage you deal whenever you attack a foe, but you may only choose one type at a time. If you critically hit a foe with your unarmed strike while doing piercing damage, the additional pain caused by the strike causes the foe to become <Link to="/misc/sickened">sickened</Link> for 1 round (or <Link to="/misc/staggered">staggered</Link> for 1 round if the target is already sickened). Multiple critical hits in a round against a single foe do not increase the duration of the sickened or staggered condition.<br/><strong>Special:</strong> Hamatulatsu may be selected as a substitute bonus feat at 6th level by a monk even if the monk does not otherwise meet the prerequisites. This fighting style is normally only taught to women of the Sisterhood of the Golden Erinyes.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-hamatulatsu--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-hamatulatsu-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 25</Link><br/>By spending 5 stamina points, you can treat a hit with an unarmed strike as a critical hit for the purpose of determining the benefits that you gain from Hamatulatsu.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _hammer_guards_the_anvil = {title: "Hammer Guards the Anvil", jsx: <><h2 id="feat-hammer_guards_the_anvil-hammer-guards-the-anvil-teamwork">Hammer Guards the Anvil (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 7</Link></p>
<p>Your allies cover you when your guard is down.<br/><strong>Benefit:</strong> Creatures threatened by an ally with this feat cannot make attacks of opportunity against you when you pick up an item from the ground, retrieve a stored item, sheathe a weapon, or stand up from prone.</p>
</>};
const _hammer_the_gap = {title: "Hammer the Gap", jsx: <><h2 id="feat-hammer_the_gap-hammer-the-gap-combat">Hammer the Gap (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 103</Link></p>
<p>You repeatedly strike the same location, causing increasing amounts of damage.<br/><strong>Prerequisites:</strong> Base attack bonus +6.<br/><strong>Benefit:</strong> When you take a full-attack action, each consecutive hit against the same opponent deals extra damage equal to the number of previous consecutive hits you have made against that opponent this turn. This damage is multiplied on a critical hit.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-hammer_the_gap--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-hammer_the_gap-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When you use this feat, you can spend 5 stamina points to increase the amount of extra damage dealt by 1 point per consecutive hit you make.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _hammer_throw = {title: "Hammer Throw", jsx: <><h2 id="feat-hammer_throw-hammer-throw-combat">Hammer Throw (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 9</Link></p>
<p>You can throw a hammer with such force that it knocks your foes over.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/improved_trip">Improved Trip</Link>, <Link to="/feat/precise_shot">Precise Shot</Link>, base attack bonus +1, <Link to="/race/dwarf">dwarf</Link>.<br/><strong>Benefit:</strong> As a standard action, you can make a single ranged attack with a weapon that deals bludgeoning damage against a creature no more than one size category larger than you that is within the weapon's first range increment. If you hit and damage the target, you can immediately attempt to perform a <Link to="/rule/trip">trip</Link> combat maneuver against that target. This does not provoke an attack of opportunity, and if your combat maneuver check fails by 10 or more, you do not fall prone.</p>
</>};
const _hands_autonomy = {title: "Hand's Autonomy", jsx: <><h2 id="feat-hands_autonomy-hands-autonomy">Hand's Autonomy</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 24</Link></p>
<p>Your possessed hand can act independently.<br/><strong>Prerequisites:</strong> <Link to="/feat/possessed_hand">Possessed Hand</Link>.<br/><strong>Benefit:</strong> You reduce the penalties for <Link to="/rule/two_weapon_fighting">fighting with two weapons</Link> (including fighting with double weapons or when throwing weapons from each hand) by 2, to a minimum penalty of -1. This benefit stacks with the <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link> feat. When you are unconscious, paralyzed, asleep, or stunned, your possessed hand can still act on your behalf in a limited fashion. The hand uses your statistics when performing any action in this manner. The hand can't take attacks of opportunity, but can draw attacks of opportunity from actions it takes. The hand can perform the following actions each turn on your initiative count.</p>
<ul>
<li>The hand can retrieve or pick up an item or weapon as a standard action.</li>
<li>The hand can attempt any of the following skill checks at a -4 penalty: Disable Device, Escape Artist, Heal, Sleight of Hand, or Use Magic Device.</li>
<li>The hand can knock you <Link to="/rule/prone">prone</Link> as a free action, and drag you while you're prone at a speed of 5 feet as a full-round action.</li>
<li>The hand can perform any other action appropriate for a hand and an arm, such as pouring a held potion into your mouth or awakening you from a <Link to="/spell/sleep">sleep</Link> spell.</li>
<li>The hand can make a single melee or ranged attack with a light or one-handed weapon as a full-round action.</li>
</ul>
</>};
const _hands_detachment = {title: "Hand's Detachment", jsx: <><h2 id="feat-hands_detachment-hands-detachment">Hand's Detachment</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 24</Link></p>
<p>Your possessed hand can painlessly pull free of your body or reattach itself, leaving you with a bloodless but raw-looking stump at the end of one arm while the hand itself performs remote tasks under your command, acting in many ways like a strange familiar.<br/><strong>Prerequisites:</strong> <Link to="/feat/hands_autonomy">Hand's Autonomy</Link>, <Link to="/feat/possessed_hand">Possessed Hand</Link>.<br/><strong>Benefit:</strong> You can remove your possessed hand, allowing the possessing spirit to animate and control its motion. Removing or reattaching your possessed hand is a full-round action. This deals no damage to you, but you can't use the hand while it is removed. The hand acts as a wizard's <Link to="/ability/familiar">familiar</Link>, using your character level as your effective wizard level, except it doesn't gain the alertness, share spells, deliver touch spells, spell resistance, or scry on familiar abilities. Use the statistics for a <Link to="/monster/crawling_hand">crawling hand</Link> to represent the detached hand, save that the hand isn't undead, doesn't have the mark quarry ability, and shares your alignment. If the hand is destroyed, the spirit regenerates your missing hand in 2d4 days. This process can be accelerated by <Link to="/spell/regenerate">regenerate</Link> or similar magic. You cannot use the Possessed Hand feat or any feat with the Possessed Hand feat as a prerequisite until the hand is fully regenerated. If you have the familiar class feature, you can choose for your possessed hand to become your <Link to="/sidekick/familiar">familiar</Link>, granting it all familiar abilities as normal. If selected as a familiar, your possessed hand grants you a +3 bonus on Sleight of Hand checks.</p>
</>};
const _hands_knowledge = {title: "Hand's Knowledge", jsx: <><h2 id="feat-hands_knowledge-hands-knowledge">Hand's Knowledge</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 24</Link></p>
<p>The connection to the memories of the spirit possessing your hand deepens.<br/><strong>Prerequisites:</strong> <Link to="/feat/possessed_hand">Possessed Hand</Link>.<br/><strong>Benefit:</strong> Select one Knowledge skill; this skill becomes a class skill for you. Additionally, select one of the following skills: Disable Device, Escape Artist, Heal, Sleight of Hand, or Use Magic Device. This skill becomes a class skill for you and you can attempt checks with the skill untrained. Once per day as a swift action, you can gain a bonus to any of the above skill checks equal to 1/2 your character level.</p>
</>};
const _hands_of_valor = {title: "Hands of Valor", jsx: <><h2 id="feat-hands_of_valor-hands-of-valor">Hands of Valor</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 212</Link></p>
<p>Your touch staunches wounds and inspires great deeds.<br/><strong>Prerequisites:</strong> <Link to="/ability/lay_on_hands">Lay on hands</Link> class feature, worshiper of <Link to="/faith/iomedae">Iomedae</Link>.<br/><strong>Benefit:</strong> Once per day when you use lay on hands, you can also imbue that ally with valor. In addition to the normal effects of your lay on hands, the targeted ally gains a sacred bonus on attack rolls and on saves against fear effects equal to your Charisma bonus (minimum +1) for 1 minute.</p>
</>};
const _hands_sight = {title: "Hand's Sight", jsx: <><h2 id="feat-hands_sight-hands-sight">Hand's Sight</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 25</Link></p>
<p>By manifesting an eerie, spiritual eye of its own, your possessed hand can "see" on your behalf.<br/><strong>Prerequisites:</strong> <Link to="/feat/possessed_hand">Possessed Hand</Link>.<br/><strong>Benefit:</strong> While your possessed hand isn't carrying anything, you gain darkvision with a range of 60 feet and cannot be <Link to="/rule/flanked">flanked</Link>.</p>
</>};
const _harder_they_fall = {title: "Harder They Fall", jsx: <><h2 id="feat-harder_they_fall-harder-they-fall-combat-teamwork">Harder They Fall (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 113</Link>, <Link to="/source/giant_hunters_handbook">Giant Hunter's Handbook pg. 19</Link></p>
<p>You can work with an ally to move or knock over a foe that's too large for either of you to overcome alone.<br/><strong>Prerequisites:</strong> Str 13, Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/power_attack">Power Attack</Link>.<br/><strong>Benefit:</strong> When you use the <Link to="/rule/aid_another_2">aid another</Link> action to grant an ally who also has this feat a +2 bonus on a <Link to="/rule/bull_rush">bull rush</Link> or <Link to="/rule/trip">trip</Link> combat maneuver check, the ally can attempt that maneuver even against foes two or more size categories larger than herself.</p>
</>};
const _hard_headed = {title: "Hard-Headed", jsx: <><h2 id="feat-hard_headed-hard-headed-combat">Hard-Headed (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 18</Link></p>
<p>Your thick skull is almost a weapon unto itself.<br/><strong>Prerequisites:</strong> Base attack bonus +1, <Link to="/race/dwarf">dwarf</Link>.<br/><strong>Benefit:</strong> You gain a +1 bonus on attack rolls and combat maneuver checks made using a helmet. You receive a +2 bonus on saves against spells and special abilities that cause you to become <Link to="/misc/staggered">staggered</Link> or <Link to="/misc/stunned">stunned</Link>.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-hard_headed--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-hard_headed-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When targeted by a spell or a special ability that could cause you to become staggered or stunned, you can spend up to 2 stamina points before attempting the save to gain a bonus on the saving throw equal to the number of stamina points you spent.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _hardy_liver = {title: "Hardy Liver", jsx: <><h2 id="feat-hardy_liver-hardy-liver">Hardy Liver</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_taverns">Inner Sea Taverns pg. 59</Link></p>
<p>You can hold your liquor and poisons better than most.<br/><strong>Prerequisites:</strong> <Link to="/feat/great_fortitude">Great Fortitude</Link>.<br/><strong>Benefit:</strong> You gain a +2 bonus on Fortitude saving throws against ingested poisons. You take no penalties when you are tipsy, and the penalties for being <Link to="/rule/drunkenness">drunk or soused</Link> are halved for you.</p>
</>};
const _harmonic_sage = {title: "Harmonic Sage", jsx: <><h2 id="feat-harmonic_sage-harmonic-sage">Harmonic Sage</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 104</Link></p>
<p>Your thorough understanding of acoustics in artificial surroundings allows you to improve the power of your bardic performance.<br/><strong>Prerequisites:</strong> <Link to="/ability/bardic_performance">Bardic performance</Link> class feature, Knowledge (engineering) 5 ranks.<br/><strong>Benefit:</strong> While inside an artificial structure, you can spend a free action to make a DC 15 Knowledge (engineering) check when you begin your bardic performance. Success on this check allows you to do one of the following.</p>
<blockquote>
<p><strong className="hl">Self-Harmonize:</strong> By performing over the acoustic reverberations of your performance, you increase the DC of your bardic performance effects +1.</p>
<p><strong className="hl">Reverberation:</strong> You can choose to have the effect of your current bardic performance continue for 1 round after you cease maintaining it, regardless of why you cease maintaining it. You can still have no more than one bardic performance in effect at one time.</p>
</blockquote>
<p><strong>Normal:</strong> A bardic performance lasts only as long as you maintain it.</p>
</>};
const _harmonic_spell = {title: "Harmonic Spell", jsx: <><h2 id="feat-harmonic_spell-harmonic-spell">Harmonic Spell</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 287</Link>, <Link to="/source/pathfinder_12_crown_of_fangs">Pathfinder #12: Crown of Fangs pg. 59</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 218</Link></p>
<p>You can weave bardic music effects into your spellcasting in such a way that your spellcasting and bardic performance become indistinguishable.<br/><strong>Prerequisites:</strong> Bardic performance ability.<br/><strong>Benefit:</strong> Whenever you cast a spell while you are maintaining a <Link to="/ability/bardic_performance">bardic performance</Link>, you can maintain the bardic performance for that round without expending one of your rounds of performance for the day. In addition, you can switch from one bardic performance to another as a swift action when you cast a spell while maintaining a bardic performance.</p>
</>};
const _harrowed = {title: "Harrowed", jsx: <><h2 id="feat-harrowed-harrowed">Harrowed</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 287</Link>, <Link to="/source/curse_of_the_crimson_throne_players_guide">Curse of the Crimson Throne Player's Guide pg. 14</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 218</Link></p>
<p>Numerous Harrow readings early in your life seem to have hit the mark precisely, increasing your belief that you are destined for a specific purpose in life.<br/><strong>Benefit:</strong> You get a +1 bonus on all Will saves made to resist enchantment effects. Once per day, you may draw a card from a <Link to="/eq-misc/harrow_deck">Harrow deck</Link> you own. At any one time for the rest of that day, you may apply a +2 bonus on any d20 roll modified by the card's suit. For example, if you drew a card from the suit of Dexterity, you could apply this +2 bonus on an Initiative check, a Reflex save, a Dexterity-based skill check, or a ranged attack roll. You may assign this +2 bonus after you make the roll, but you must do so before you know whether the roll was a success or not.</p>
</>};
const _harrowed_summoning = {title: "Harrowed Summoning", jsx: <><h2 id="feat-harrowed_summoning-harrowed-summoning">Harrowed Summoning</h2>
<p><strong>Sources</strong> <Link to="/source/the_harrow_handbook">The Harrow Handbook pg. 14</Link></p>
<p>Your summoned creatures are empowered by the magic of the harrow.<br/><strong>Prerequisites:</strong> <Link to="/feat/harrowed">Harrowed</Link>.<br/><strong>Benefit:</strong> When you cast a conjuration (summoning) spell or use a spell-like ability to summon one or more creatures, you can draw two random cards from a complete <Link to="/eq-misc/harrow_deck">harrow deck</Link> you own. Doing so adds both a somatic component (if the spell does not already have one) and a focus component (the harrow deck) to the spell, but does not increase the spell's casting time. For the duration of the spell, each summoned creature gains a +4 enhancement bonus to the corresponding ability scores of the drawn card's suits. If both cards are the same suit, each summoned creature gains a +6 bonus to that ability score instead. If either card's alignment is a true match for the summoned creatures' alignment, the duration of the spell is doubled, while drawing an opposite match halves the duration of the spell. If both a true match and an opposite match are drawn, the spell's duration is unchanged.</p>
<p>A creature summoned in this way is distinctly altered by the cards drawn. Its physical appearance reflects the visual elements of the cards (for example, a creature summoned with The Publican might have only one eye). The creature's personality is also influenced by the cards, but not so much as to alter its alignment (for example, The Snakebite might summon a creature that likes to gossip).</p>
</>};
const _harrying_partners = {title: "Harrying Partners", jsx: <><h2 id="feat-harrying_partners-harrying-partners-combat-teamwork">Harrying Partners (Combat, Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 10</Link></p>
<p>Your movements perfectly synchronize with your ally's to greater effect.<br/><strong>Prerequisites:</strong> Any <Link to="/main/teamwork_feat">teamwork feat</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> When you successfully use the <Link to="/rule/aid_another_2">aid another</Link> action to improve the Armor Class or attack roll of an ally who also has this feat, the benefit from aid another lasts until the beginning of your next turn.<br/><strong>Normal:</strong> The bonus granted by aid another either grants your ally a +2 bonus on her next attack roll against an opponent or grants your ally a +2 bonus to AC against that opponent's next attack made before the beginning of your next turn.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-harrying_partners--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-harrying_partners-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 20</Link><br/>When using the aid another action to help an ally who also has this feat, you can spend 5 stamina points to grant a +4 bonus instead of the normal +2. Alternatively, you can grant your ally a +2 bonus both on her next attack roll and to her AC against the next attack against her.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _haruspicy = {title: "Haruspicy", jsx: <><h2 id="feat-haruspicy-haruspicy">Haruspicy</h2>
<p><strong>Sources</strong> <Link to="/source/occult_origins">Occult Origins pg. 24</Link></p>
<p>You observe the signs of the universe by studying how spilled blood and viscera fall, learning insights into how to best appease unseen forces.<br/><strong>Prerequisites:</strong> Knowledge (religion) 3 ranks.<br/><strong>Benefit:</strong> If you perform a successful <Link to="/misc/coup_de_grace">coup de grace</Link>, you gain a +2 circumstance bonus on skill checks attempted as part of a single occult ritual or occult skill unlock performed within the next minute. Alternatively, you can instead gain a +1 caster level bonus on a single divination or necromancy spell. The ritual or spell must begin within 1 minute of the <em>coup de grace.</em></p>
</>};
const _harvest_parts = {title: "Harvest Parts", jsx: <><h2 id="feat-harvest_parts-harvest-parts-item-creation">Harvest Parts (Item Creation)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_hunters_handbook">Monster Hunter's Handbook pg. 24</Link></p>
<p>You can extract the choicest parts from a monster's carcass to use as resources when crafting items.<br/><strong>Prerequisites:</strong> Craft (any) 1 rank or Heal 1 rank.<br/><strong>Benefit:</strong> You can attempt a Craft or Heal check, as though making a <Link to="/rule/harvesting_trophies">trophy</Link>, to gain usable resources from a creature that has been dead for less than an hour. Only creatures with a CR of 1 or higher yield usable parts. The value of the parts you harvest is equal to the creature's CR squared &times; 10 gp (increases to CR derived from class levels or templates do not contribute to this value). This value can be used only as raw materials for crafting alchemical, masterwork, mundane, or magic items. Items crafted using creature parts must be made of a suitable material - typically bone or hide, with metal only in extraordinary cases. No more than a quarter of a crafted item's cost can be supplied with harvested parts. Harvested parts remain usable for 2 days before they rot (unless used to craft objects or somehow preserved). Creature parts that are harvested in this manner can't be bought or sold in most settlements.</p>
</>};
const _haunt_scavenger = {title: "Haunt Scavenger", jsx: <><h2 id="feat-haunt_scavenger-haunt-scavenger-item-creation">Haunt Scavenger (Item Creation)</h2>
<p><strong>Sources</strong> <Link to="/source/haunted_heroes_handbook">Haunted Heroes Handbook pg. 30</Link></p>
<p>You can use spiritual essence to craft magic items.<br/><strong>Prerequisites:</strong> Any one item creation feat or Craft (alchemy) 3 ranks.<br/><strong>Benefit:</strong> You can harvest the ectoplasmic remains of haunts, incorporeal undead, or the like to craft magic items. Whenever you encounter a recently neutralized haunt, the remains of an incorporeal undead creature, or the remains of a creature that has the ability to possess another creature using a racial spell-like ability or supernatural ability (such as a <Link to="/template/ghost">ghost</Link> or a <Link to="/monster/shadow_demon">shadow demon</Link>), you can attempt to extract material components from those remains that are suitable for crafting magic items. You must have access to an <Link to="/eq-misc/alchemists_lab">alchemist's lab</Link> in order to extract components from a haunt or creature, and you must begin extracting these components within 10 minutes of the haunt or creature's death or destruction. After 10 minutes, the components have degraded too much to be of any use to you.</p>
<p>Harvesting components with this feat can take several hours. Performing at least 1 minute of work extracting components from a haunt or creature prevents its material components from degrading further for 24 hours, allowing you to safely suspend and resume harvesting these components without fear of subsequent degradation. This ectoplasmic residue is portable once the extraction work begins, provided you have a vial to contain the source residue (the actual amount of residue is never much, physically, but the value of the components you can extract from the residue increases with the power of the original haunt or creature).</p>
<p>Each hour, attempt a Craft (alchemy) or a Knowledge (religion) check to successfully handle the residue and extract useful material. The DC for this check is equal to 15 + the CR of the haunt or creature being harvested. If you succeed at the check, you harvest 50 gp worth of components. If you fail the check by 4 or less, you can attempt to harvest those components again. If you fail the check by 5 or more, the residue spoils and you cannot scavenge any more from that particular source. A single source can yield an amount of components up to a maximum value of 50 gp per point of CR before it is depleted.</p>
<p>Material components harvested with Haunt Scavenger can be used in place of the material components of enchantment or necromancy spells and extracts, provided they are of equal or greater value compared to the spell's normal material components. Additionally, they can be used in place of actual gold to fund the construction of a magic item with an enchantment or necromancy aura.</p>
</>};
const _haunted_gnome = {title: "Haunted Gnome", jsx: <><h2 id="feat-haunted_gnome-haunted-gnome-combat">Haunted Gnome (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 104</Link></p>
<p>You use your gnome magic to take on an eerie illusory appearance.<br/><strong>Prerequisites:</strong> Cha 13, gnome magic racial trait, Knowledge (arcana) 1 rank.<br/><strong>Benefit:</strong> You add <Link to="/spell/haunted_fey_aspect">haunted fey aspect</Link> to your list of gnome magic spell-like abilities, and you can use this spell-like ability twice per day.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-haunted_gnome--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-haunted_gnome-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>You can spend 5 stamina points to use haunted fey aspect an additional time in a day.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _haunted_gnome_assault = {title: "Haunted Gnome Assault", jsx: <><h2 id="feat-haunted_gnome_assault-haunted-gnome-assault-combat">Haunted Gnome Assault (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 104</Link></p>
<p>Discharging your disturbing glamer as you strike a telling blow, you haunt a foe with lingering fear.<br/><strong>Prerequisites:</strong> Cha 13, gnome magic racial trait, <Link to="/feat/haunted_gnome">Haunted Gnome</Link>, Knowledge (arcana) 3 ranks.<br/><strong>Benefit:</strong> You gain one use of your gnome magic that is independent of your gnome magic spell-like abilities. When you wish to cast a gnome magic spell-like ability for which you have no daily uses remaining, you can expend this independent use to do so.</p>
<p>Further, while you are under the effect of <Link to="/spell/haunted_fey_aspect">haunted fey aspect</Link>, you can discharge that spell as a free action after you hit an opponent with a charge attack or score a critical hit against an opponent. If you do, that opponent becomes <Link to="/misc/shaken">shaken</Link> for 1 round.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-haunted_gnome_assault--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-haunted_gnome_assault-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When you hit an opponent with a charge attack or confirm a critical hit, you can spend 2 stamina points to make the target of the attack shaken for 1 round without discharging haunted fey aspect.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _haunted_gnome_shroud = {title: "Haunted Gnome Shroud", jsx: <><h2 id="feat-haunted_gnome_shroud-haunted-gnome-shroud-combat">Haunted Gnome Shroud (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 104</Link></p>
<p>Your disturbing glamer expands to make your exact location hard to pinpoint.<br/><strong>Prerequisites:</strong> Cha 13, gnome magic racial trait, <Link to="/feat/haunted_gnome">Haunted Gnome</Link>, <Link to="/feat/haunted_gnome_assault">Haunted Gnome Assault</Link>, Knowledge (arcana) 6 ranks.<br/><strong>Benefit:</strong> You gain another independent use of your gnome magic like that which Haunted Gnome Assault grants. Further, while you are under the effect of <Link to="/spell/haunted_fey_aspect">haunted fey aspect</Link>, you also have concealment (20% miss chance) against an opponent until that opponent deals you damage.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-haunted_gnome_shroud--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-haunted_gnome_shroud-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When an opponent misses you due to the miss chance from Haunted Gnome Shroud, you can spend 5 stamina points to impose a -2 penalty on all that opponent's attack rolls against you until that opponent deals damage to you. This ability doesn't stack with itself.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _healers_hands = {title: "Healer's Hands", jsx: <><h2 id="feat-healers_hands-healers-hands-conduit">Healer's Hands (Conduit)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 28</Link></p>
<p>Your healing efforts are bolstered by positive energy.<br/><strong>Prerequisites:</strong> Heal 1 rank, Knowledge (planes) 1 rank.<br/><strong>Benefit:</strong> You can use the <Link to="/skill/heal">Heal</Link> skill to treat deadly wounds as a full-round action. You do not take a penalty for not using a <Link to="/eq-misc/healers_kit">healer's kit</Link> when treating deadly wounds this way, and you can do so on a given creature more than once per day. When treating deadly wounds this way, if your result exceeds the DC by 10 or more, add your ranks in Knowledge (planes) to the damage healed. These benefits do not apply to creatures that are not healed by positive energy. You can use this feat's benefit a number of times per day equal to your ranks in Knowledge (planes).</p>
</>};
const _healing_potion = {title: "Healing Potion", jsx: <><h2 id="feat-healing_potion-healing-potion">Healing Potion</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 16</Link></p>
<p>You can infuse a healing spell into a potion that produces a different effect.<br/><strong>Prerequisites:</strong> <Link to="/feat/brew_potion">Brew Potion</Link>, ability to cast <Link to="/spell/cure_serious_wounds">cure serious wounds</Link>.<br/><strong>Benefit:</strong> When you brew a potion, you can add the effects of one of the following spells to the potion's effects: <Link to="/spell/cure_light_wounds">cure light wounds</Link>, <Link to="/spell/cure_moderate_wounds">cure moderate wounds</Link>, or <em>cure serious wounds.</em> When imbibed, the potion has the effect of both the chosen <em>cure</em> spell and the spell used to brew the potion. When brewing the potion, you must expend both spells as though you were creating two separate potions. Due to the intricacies of making such a carefully blended potion, you must use particularly fine and rare ingredients, meaning you must pay twice the cost of creating each potion separately. The combined spell levels of the <em>cure</em> spell and the other spell used in the potion must be level 3 or less (for example, you could combine <em>cure light wounds</em> with a 2nd-level spell to create a healing potion, or <em>cure moderate wounds</em> with a 1st-level spell, or <em>cure serious wounds</em> with a 0-level spell).</p>
<h3 id="feat-healing_potion-versatile-brewing">Versatile Brewing</h3>
<p>The above feat allows potion brewers to concoct unusual variations in their potions, altering the potions' effects in strange and useful ways. This feat functions similarly to metamagic feats, though it affects the creation of potions instead of the normal casting of spells. Level limits for potions apply to their level after the application of any relevant metamagic feats (if the feat affects the component spell's level).</p>
<p>Other versatile bewing feats: <Link to="/feat/delayed_potion">Delayed Potion</Link>, <Link to="/feat/lengthy_potion">Lengthy Potion</Link>, <Link to="/feat/vaporous_potion">Vaporous Potion</Link>.</p>
</>};
const _heavenly_bane = {title: "Heavenly Bane", jsx: <><h2 id="feat-heavenly_bane-heavenly-bane">Heavenly Bane</h2>
<p><strong>Sources</strong> <Link to="/source/distant_realms">Distant Realms pg. 32</Link></p>
<p>Your weapons carry a trace of the divine when imbued with your bane ability.<br/><strong>Prerequisites:</strong> Bane class feature.<br/><strong>Benefit:</strong> Whenever you have a weapon imbued with the <Link to="/magic-enh/bane">bane</Link> special quality, that weapon is considered good and lawful for the purpose of overcoming damage reduction.</p>
</>};
const _heavenly_radiance = {title: "Heavenly Radiance", jsx: <><h2 id="feat-heavenly_radiance-heavenly-radiance">Heavenly Radiance</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 88</Link></p>
<p>Your heavenly light can be used in a variety of ways.<br/><strong>Prerequisites:</strong> <Link to="/race/aasimar">Aasimar</Link>, <Link to="/spell/daylight">daylight</Link> spell-like ability, sufficiently high level (see below).<br/><strong>Benefit:</strong> You gain one additional use per day of <em>daylight.</em> Choose one spell from the table below; by expending a use of <em>daylight,</em> you may use this spell as a spell-like ability. To select a spell, you must meet the minimum character level for its listing in the table. The save DC for this spell is Charisma-based.</p>
<ScrollContainer id="feat-heavenly_radiance--table-0"><table>
<thead>
<tr>
<th>Spell-Like Ability</th>
<th>Minimum Character Level</th>
</tr>
</thead>
<tbody><tr>
<td className="ion-activatable"><Link to="/spell/flare_burst">Flare burst<IonRippleEffect /></Link></td>
<td>1st</td>
</tr>
<tr>
<td className="ion-activatable"><Link to="/spell/wake_of_light">Wake of light<IonRippleEffect /></Link></td>
<td>3rd</td>
</tr>
<tr>
<td className="ion-activatable"><Link to="/spell/searing_light">Searing light<IonRippleEffect /></Link></td>
<td>5th</td>
</tr>
<tr>
<td className="ion-activatable"><Link to="/spell/wandering_star_motes">Wandering star motes<IonRippleEffect /></Link></td>
<td>7th</td>
</tr>
<tr>
<td className="ion-activatable"><Link to="/spell/sunbeam">Sunbeam (one beam only)<IonRippleEffect /></Link></td>
<td>9th</td>
</tr>
</tbody></table></ScrollContainer>
<p><strong>Special:</strong> You may take this feat multiple times. Each time you select it, you gain an additional use of daylight and may select another spell from the table.</p>
</>};
const _heavens_light = {title: "Heaven's Light", jsx: <><h2 id="feat-heavens_light-heavens-light-conduit">Heaven's Light (Conduit)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 28</Link></p>
<p>You are a luminous beacon in the darkness, an icon of order and kindness through which the light of Heaven itself can shine, even in the most dreadful of realms.<br/><strong>Prerequisites:</strong> Knowledge (planes) 1 rank.<br/><strong>Benefit:</strong> As a standard action, you can emit an aura of bright light centered on a glowing halo above or behind your head. The illumination provided is equal in intensity to that of a torch. If you have at least 5 ranks in Knowledge (planes) the illumination is equivalent to that created by a <Link to="/spell/daylight">daylight</Link> spell. If you have at least 15 ranks in Knowledge (planes), the light becomes further infused with Heavenly power, and each evil creature within 30 feet of you must succeed at a Fortitude save (DC = 10 + half your level + your Charisma modifier) or become <Link to="/misc/sickened">sickened</Link> by the light for as long as it remains in range plus 1 additional round after leaving the area.</p>
<p>You can use this feat's benefit for a number of rounds per day equal to your ranks in Knowledge (planes). These rounds need not be consecutive.</p>
</>};
const _heavens_step = {title: "Heaven's Step", jsx: <><h2 id="feat-heavens_step-heavens-step-combat">Heaven's Step (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_132_the_six_legend_soul">Pathfinder #132: The Six-Legend Soul pg. 73</Link></p>
<p>Like the daring Heaven's Step Offensive championed by Grand Prince Gennaris III of Taldor, you confidently take the fight to your enemy and strike an unexpected blow.<br/><strong>Prerequisites:</strong> Dex 15, <Link to="/feat/following_step">Following Step</Link>, <Link to="/feat/step_up">Step Up</Link>, <Link to="/feat/step_up_and_strike">Step Up and Strike</Link>, base attack bonus +10.<br/><strong>Benefit:</strong> When you make an attack using Step Up and Strike, you can also make an extra attack with your offhand weapon using your highest base attack bonus. Both attacks take the normal penalties for <Link to="/rule/two_weapon_fighting">two-weapon fighting</Link>.</p>
</>};
const _heavy_gravity_acclimation = {title: "Heavy Gravity Acclimation", jsx: <><h2 id="feat-heavy_gravity_acclimation-heavy-gravity-acclimation">Heavy Gravity Acclimation</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 29</Link></p>
<p>Your muscles work overtime in areas with heavy gravity.<br/><strong>Prerequisites:</strong> Str 17 or <Link to="/feat/endurance">Endurance</Link>.<br/><strong>Benefit:</strong> You do not take the normal penalties for being on heavy <Link to="/rule/gravity_traits">gravity</Link> planes. At the GM's discretion, this effect may apply to certain environments on the Material Plane, such as high-gravity planets. In addition, your Strength is considered to be 4 higher for the purpose of determining your carrying capacity.</p>
</>};
const _hefty_brute = {title: "Hefty Brute", jsx: <><h2 id="feat-hefty_brute-hefty-brute">Hefty Brute</h2>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins pg. 22</Link></p>
<p>You might be a different subspecies or simply a well-fed and well-grown beast, but either way you're built on a more massive scale than the rest of your kind.<br/><strong>Prerequisites:</strong> <Link to="/sidekick/animal_companion">Animal companion</Link> or <Link to="/sidekick/familiar">familiar</Link>.<br/><strong>Benefit:</strong> You treat your size as one category larger for the purposes of calculating CMB, CMD, carrying capacity, and any size-based special attacks you use or that are used against you (such as <Link to="/umr/grab">grab</Link>, <Link to="/umr/swallow_whole">swallow whole</Link>, and <Link to="/umr/trample">trample</Link>).</p>
</>};
const _heighten_spell = {title: "Heighten Spell", jsx: <><h2 id="feat-heighten_spell-heighten-spell-metamagic">Heighten Spell (Metamagic)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 126</Link></p>
<p>You can cast spells as if they were a higher level.<br/><strong>Benefit:</strong> A heightened spell has a higher spell level than normal (up to a maximum of 9th level). Unlike other metamagic feats, Heighten Spell actually increases the effective level of the spell that it modifies. All effects dependent on spell level (such as saving throw DCs and ability to penetrate a <Link to="/spell/lesser_globe_of_invulnerability">lesser globe of invulnerability</Link>) are calculated according to the heightened level. The heightened spell is as difficult to prepare and cast as a spell of its effective level.</p>
</>};
const _heightened_trap_sense = {title: "Heightened Trap Sense", jsx: <><h2 id="feat-heightened_trap_sense-heightened-trap-sense">Heightened Trap Sense</h2>
<p><strong>Sources</strong> <Link to="/source/osirion_land_of_the_pharaohs">Osirion, Land of the Pharaohs pg. 29</Link></p>
<p>You are acutely attentive to the subtleties of traps and how they are hidden.<br/><strong>Prerequisites:</strong> Perception 6 ranks,<sup><InnerLink showBacklink="backlink-feat-heightened_trap_sense-ref-P-1" id="feat-heightened_trap_sense-ref-P-1" data-hash-target to="feat-heightened_trap_sense-P">1</InnerLink></sup> <Link to="/ability/trap_sense">trap sense</Link> +1.<br/><strong>Benefit:</strong> When you pass within 5 feet of a trap, you are entitled to an automatic Perception check to notice the trap. This check is made at a -10 penalty, or -5 if you are moving at half speed and taking no actions other than moving.<br/><strong>Normal:</strong> You must take an action to actively search.</p>
<section data-footnotes>
<h3 id="feat-heightened_trap_sense-label">Footnotes</h3>
<ol>
<li id="feat-heightened_trap_sense-P">
<p>This source was printed for 3.5; Pathfinder Society play reduced the skill rank prerequisites by 3. consult your GM if you wish to use the lower prerequisites. <InnerLink id="backlink-feat-heightened_trap_sense-ref-P-1" data-hash-target to="feat-heightened_trap_sense-ref-P-1" aria-label="Back to reference P-1">↩</InnerLink></p>
</li>
</ol>
</section>
</>};
const _hellcat_pounce = {title: "Hellcat Pounce", jsx: <><h2 id="feat-hellcat_pounce-hellcat-pounce-combat">Hellcat Pounce (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 27</Link></p>
<p>You attack unsuspecting foes twice.<br/><strong>Prerequisites:</strong> <Link to="/feat/hellcat_stealth">Hellcat Stealth</Link>, <Link to="/ability/sneak_attack">sneak attack</Link> +2d6.<br/><strong>Benefit:</strong> Whenever you attack and damage an opponent in the surprise round, you may immediately make a second attack against the same opponent using the same attack bonus. The target is not considered <Link to="/rule/flat_footed">flat-footed</Link> against this second attack.<br/><strong>Special:</strong> This ability only functions when carrying a light load or less.</p>
</>};
const _hellcat_stealth = {title: "Hellcat Stealth", jsx: <><h2 id="feat-hellcat_stealth-hellcat-stealth">Hellcat Stealth</h2>
<p><strong>Sources</strong> <Link to="/source/cheliax_empire_of_devils">Cheliax, Empire of Devils pg. 27</Link></p>
<p>You are difficult to see in the light.<br/><strong>Prerequisites:</strong> <Link to="/feat/skill_focus">Skill Focus</Link> (Stealth), Stealth 6 ranks.<br/><strong>Benefit:</strong> You may make Stealth checks in normal or bright light even when observed, but at a -10 penalty.<br/><strong>Normal:</strong> You cannot make Stealth checks while observed.</p>
</>};
const _hellish_shackles = {title: "Hellish Shackles", jsx: <><h2 id="feat-hellish_shackles-hellish-shackles">Hellish Shackles</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 212</Link></p>
<p>You can channel the shackles of Hell onto your foes.<br/><strong>Prerequisites:</strong> <Link to="/ability/channel_energy">Channel energy</Link> 5d6; worshiper of an archdevil, infernal duke, malbranche, or whore queen.<br/><strong>Benefit:</strong> Once per day when you channel negative energy to damage living creatures, you can attempt to affect damaged creatures with a <Link to="/spell/dimensional_anchor">dimensional anchor</Link>. Those damaged must make a successful Will save (DC equal to the DC of the channel effect) in addition to the normal Will save to halve damage from the channeled energy. Those that fail their save against the channeled energy take a -4 penalty on their saving throw against the <em>dimensional anchor</em> effect. Those that fail their second Will save are affected by <em>dimensional anchor</em> for a number of minutes equal to your Charisma modifier (minimum 1 minute).</p>
</>};
const _hellknight_aegis = {title: "Hellknight Aegis", jsx: <><h2 id="feat-hellknight_aegis-hellknight-aegis">Hellknight Aegis</h2>
<p><strong>Sources</strong> <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 62</Link></p>
<p>Your Hellknight armor guards you against many threats.<br/><strong>Prerequisites:</strong> <Link to="/feat/heavy_armor_proficiency">Heavy Armor Proficiency</Link>, base attack bonus +5, must swear allegiance to a single <Link to="/rule/hellknights">Hellknight</Link> order.<br/><strong>Benefit:</strong> Once per day as a full-round action, you can give your Hellknight armor the <Link to="/misc/broken">broken</Link> condition. Upon doing so, you are affected by one of the following spells (your choice), using your character level as your caster level: <Link to="/spell/break_enchantment">break enchantment</Link>, <Link to="/spell/neutralize_poison">neutralize poison</Link>, <Link to="/spell/remove_disease">remove disease</Link>, or <Link to="/spell/remove_paralysis">remove paralysis</Link>. Once you have used this benefit, your Hellknight armor must be repaired as normal to restore its full bonus to your Armor Class and return its armor check penalty to normal.</p>
<p>You can use this ability even if <Link to="/rule/paralyzed">paralyzed</Link> or otherwise restrained, but not if you are <Link to="/misc/unconscious">unconscious</Link>. For the purposes of this ability, "Hellknight armor" means any armor with the word "Hellknight" in its name. You cannot use this ability if your armor is already broken.</p>
</>};
const _hellknight_obedience = {title: "Hellknight Obedience", jsx: <><h2 id="feat-hellknight_obedience-hellknight-obedience">Hellknight Obedience</h2>
<p><strong>Sources</strong> <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 62</Link></p>
<p>Performing daily <Link to="/rule/hellknights">Hellknight</Link> reckonings grants you special boons.<br/><strong>Prerequisites:</strong> Knowledge (planes) 3 ranks, must swear allegiance to a single Hellknight order.<br/><strong>Benefit:</strong> Upon taking this feat, you gain proficiency in all of your <Link to="/ability/hellknight_orders">Hellknight order's</Link> favored weapons. Additionally, by meditating and inflicting strenuous reckonings upon yourself, you unlock the power behind your order's doctrine. Each Hellknight order has its own unique reckoning - a trial of obedience and pain. When coupled with the necessary reflection and meditation, this reckoning takes 1 hour per day to perform. Once you have performed your order's reckoning, you gain the benefit of a special ability as indicated in the Reckoning entry for the Hellknight order to which you've sworn allegiance. If you have at least 12 Hit Dice, you also gain the first boon granted by the Hellknight order. If you have at least 16 Hit Dice, you also gain the Hellknight order's second boon. If you have 20 Hit Dice or more, you also gain the Hellknight order's third boon. Unless a specific duration or number of uses per day is listed in a boon's description, the boon's effects are constant.</p>
<p>If you ever fail to perform a daily reckoning, you lose all access to the benefits and boons granted by this feat until you next perform the reckoning.</p>
<p>You can take this feat only if you are associated with a Hellknight order, whether you're in training to become a Hellknight, already a member, or otherwise aligned with the order - the specifics are left to you and the GM to determine. Once per year, you can change your Hellknight allegiance, but doing so requires the approval of the Hellknight order you wish to join. If you are ever cast out of the Hellknight order to which you've sworn allegiance, you lose the benefits of this feat until you restore yourself in the Hellknights' esteem. The details of this are left to the GM's discretion.</p>
<h3 id="feat-hellknight_obedience-reckonings">Reckonings</h3>
<p>Similar to an ascetic's flagellations or a paladin's atonement, Hellknight reckonings are rites of mortification a Hellknight uses to focus her mind, excise unwanted thoughts, and bring herself closer to the champion of law her order idealizes. A reckoning is typically a personal matter, performed in private by a willing, unarmored Hellknight while she meditates on some aspect of the Measure and the Chain.</p>
<p>Hellknights are assumed to police their own thoughts and perform reckonings as necessary. If a Hellknight doesn't regularly perform reckonings as part of her scheduled meditations, she doesn't lose any abilities or suffer negative effects - however, she might be censured by her fellow Hellknights if they learn of this dereliction.</p>
<p><strong className="hl">Performing a Reckoning:</strong> Performing the physical component of a reckoning typically takes 10 minutes and deals 1d4 points of nonlethal damage. A particularly righteous or conflicted Hellknight might choose to perform a longer, more extreme version of a reckoning. In this case, the reckoning deals 1d4 additional points of lethal damage. A devoted Hellknight with the Hellknight Obedience feat can undergo an hour-long nonlethal reckoning to gain the benefit of a special ability, in addition to boons available for those with 12, 16, or 20 Hit Dice. See the descriptions of the major Hellknight orders for descriptions of their specific reckonings and the boons these provide. Additionally, Hellknights with the <Link to="/feat/hellknight_obsession">Hellknight Obsession</Link> feat who choose to deal the lethal damage to themselves can access a suite of beneficial effects. The damage a reckoning deals cannot be reduced by any damage reduction or other ability or effect.</p>
</>};
const _hellknight_obsession = {title: "Hellknight Obsession", jsx: <><h2 id="feat-hellknight_obsession-hellknight-obsession">Hellknight Obsession</h2>
<p><strong>Sources</strong> <Link to="/source/path_of_the_hellknight">Path of the Hellknight pg. 62</Link></p>
<p>You equate pain with discipline and can inflict damage upon yourself to unlock greater power.<br/><strong>Prerequisites:</strong> <Link to="/feat/hellknight_obedience">Hellknight Obedience</Link>, Knowledge (planes) 3 ranks, must swear allegiance to a single <Link to="/rule/hellknights">Hellknight</Link> order.<br/><strong>Benefit:</strong> During your hour-long Hellknight reckoning, if you choose to deal lethal damage to yourself, you reach a state of fantastic focus. Once during the next 24 hours, you can draw upon this focus to gain the benefits of any one of the following effects. To activate the ability, you must deal 1 point of lethal damage to yourself as a swift action (unless otherwise noted). Members of the <Link to="/hkorder/order_of_the_nail">Order of the Nail</Link> often install a sharp barb within their armor that deals this damage when the wearer is subject to a critical hit; if you're struck by a critical hit while wearing such armor, using this ability doesn't require a swift action.</p>
<blockquote>
<p><strong className="hl">Fervor:</strong> The DCs to resist the effects of the boons granted by your Hellknight Obedience feat increase by 1 for 1 hour.</p>
<p><strong className="hl">Indomitability:</strong> You can reroll a single failed Will saving throw and must take the result of the second roll, even if it is worse. A swift action isn't required to use this effect, but you must still take 1 point of damage.</p>
<p><strong className="hl">Menacing:</strong> You gain a +3 bonus on Intimidate and Sense Motive skill checks for 1 hour.</p>
<p><strong className="hl">Mercilessness:</strong> The critical threat range of your order's favored weapon doubles for 1 hour (even if it is not a piercing or slashing weapon). This does not stack with any other effects that increase a weapon's critical threat range.</p>
</blockquote>
</>};
const _helpless_prisoner = {title: "Helpless Prisoner", jsx: <><h2 id="feat-helpless_prisoner-helpless-prisoner">Helpless Prisoner</h2>
<p><strong>Sources</strong> <Link to="/source/gnomes_of_golarion">Gnomes of Golarion pg. 31</Link></p>
<p>You can talk your way out of most restraints.<br/><strong>Prerequisites:</strong> Bluff 5 ranks, Escape Artist 1 rank, <Link to="/race/gnome">gnome</Link>.<br/><strong>Benefit:</strong> When you are restrained or imprisoned, you can make a <Link to="/skill/bluff">Bluff</Link> check against any one creature within 30 feet in which you emphasize both your own harmlessness and the pain or inconvenience of your current condition. If the creature knows you are dangerous, it adds a +4 bonus to its <Link to="/skill/sense_motive">Sense Motive</Link> check. If you win the check, the target does something intended to make you a little more comfortable - or at least shut you up - that gives you a +5 bonus on your next <Link to="/skill/escape_artist">Escape Artist</Link> check.<br/><strong>Special:</strong> At the GM's discretion, an especially evil or cruel creature may gain a +2 bonus to its Sense Motive check to resist this ability. If it succeeds, it does something to make your bindings even more secure and less comfortable, giving you a -5 penalty on all Escape Artist checks made in those particular bonds.</p>
</>};
const _hemorhaging_venom = {title: "Hemorhaging Venom", jsx: <><h2 id="feat-hemorhaging_venom-hemorhaging-venom-combat">Hemorhaging Venom (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/potions_and_poisons">Potions and Poisons pg. 5</Link></p>
<p>Your venom destroys blood vessels and melts bone.<br/><strong>Prerequisites:</strong> <Link to="/feat/spit_venom">Spit Venom</Link>, <Link to="/feat/virulent_venom">Virulent Venom</Link>, base attack bonus +7, <Link to="/race/nagaji">nagaji</Link>.<br/><strong>Benefit:</strong> Your ability to spit poison granted by the Spit Venom feat deals 2d6 points of <Link to="/rule/bleed">bleed</Link> damage on a failed saving throw in addition to all other effects. The bleeding can be stopped as normal with a successful DC 15 Heal check or the application of any effect that heals hit point damage. In addition, you gain one additional use per day of the ability to spit poison granted by the Spit Venom feat.</p>
</>};
const _herbal_components = {title: "Herbal Components", jsx: <><h2 id="feat-herbal_components-herbal-components">Herbal Components</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_wild">Heroes of the Wild pg. 23</Link></p>
<p>Your time in the wild has made you adept at finding cheap, natural substitutes for spell components that would be impossible to find outside of civilized society.<br/><strong>Prerequisites:</strong> <Link to="/feat/eschew_materials">Eschew Materials</Link>.<br/><strong>Benefit:</strong> Once per day, you can attempt a Profession (Herbalist) or Survival check to use herbal substitutes for the required material components of a single spell that normally cost up to 25 gp (DC = 5 + the gp value of component). These components can be used only for your own spells and can't be sold. They decay within a week if not used.<br/><strong>Normal:</strong> You must buy spell components for any spell requiring a material component.</p>
</>};
const _hermean_blood = {title: "Hermean Blood", jsx: <><h2 id="feat-hermean_blood-hermean-blood">Hermean Blood</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_world_guide">Inner Sea World Guide pg. 287</Link>, <Link to="/source/pathfinder_campaign_setting">Pathfinder Campaign Setting pg. 79</Link></p>
<p>You are the descendant of someone recruited to Hermea or the bastard result of a Hermean's illicit pairing with someone foreign to that land.<br/><strong>Prerequisites:</strong> You may only gain this feat at 1st level.<br/><strong>Benefit:</strong> Though you may not know it, the blood of greatness flows in your veins. Pick two skills that share the same associated ability score. Those skills are always considered class skills for you. It's possible that Hermean agents may come looking for you, either to evaluate you for an invitation or to cover up an embarrassing dalliance, as determined by the GM's whim.</p>
</>};
const _heroic_defiance = {title: "Heroic Defiance", jsx: <><h2 id="feat-heroic_defiance-heroic-defiance">Heroic Defiance</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 162</Link></p>
<p>You struggle on when others would fall.<br/><strong>Prerequisites:</strong> <Link to="/feat/diehard">Diehard</Link>, <Link to="/feat/endurance">Endurance</Link>, base Fortitude save +8.<br/><strong>Benefit:</strong> Once per day as an immediate action you can delay the onset of one harmful condition or affliction (such as <Link to="/misc/panicked">panicked</Link>, <Link to="/rule/paralyzed">paralyzed</Link>, <Link to="/misc/stunned">stunned</Link>, and so on), including permanent and instantaneous conditions. Activating this feat delays the onset of the condition until the end of your next turn, after which time the condition takes its normal effect. This feat has no effect on hit point damage or ability damage.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-heroic_defiance--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Heroic Defiance</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 66</Link><br/>You ignore harmful effects that would bring others down.<br/><strong>Prerequisites:</strong> Heroic Defiance.<br/><strong>Benefit:</strong> Once per day as an immediate action, you can attempt to negate the onset of one harmful condition or affliction (such as panicked, paralyzed, stunned, and so on) that allowed a saving throw for its onset, not including permanent and instantaneous conditions. When you do so, attempt a Will saving throw with a bonus equal to your tier against the original DC of the effect. If you succeed, the condition is negated. If you fail, the onset is delayed until the end of your next turn, after which it takes its normal effect. This feat has no effect on hit point damage or ability damage.</p>
<p>This effect is separate from the use of non-mythic Heroic Defiance.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _heroic_interposition = {title: "Heroic Interposition", jsx: <><h2 id="feat-heroic_interposition-heroic-interposition-combat">Heroic Interposition (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 212</Link></p>
<p>You arrive just when you are most needed to vanquish evil.<br/><strong>Prerequisites:</strong> Dex 13, <Link to="/feat/dodge">Dodge</Link>, <Link to="/feat/improved_initiative">Improved Initiative</Link>, <Link to="/feat/mobility">Mobility</Link>, worshiper of an empyreal lord.<br/><strong>Benefit:</strong> Once per day, you can move up to your speed as an immediate action, but you must end this movement adjacent to an opponent who is about to make an attack against an ally. As long as you are visible to the opponent you moved next to, that opponent takes a -2 penalty on the attack roll to which you moved in response.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-heroic_interposition--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-heroic_interposition-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 25</Link><br/>By spending 4 stamina points, you can use this feat an additional time per day.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _heroic_leader = {title: "Heroic Leader", jsx: <><h2 id="feat-heroic_leader-heroic-leader-combat">Heroic Leader (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/melee_tactics_toolbox">Melee Tactics Toolbox pg. 7</Link></p>
<p>Whether part of a partnership or an army, you stand head and shoulders above your companions.<br/><strong>Prerequisites:</strong> Cha 13; any <Link to="/main/combat_feat">combat feat</Link>; ability to gain an animal companion, cohort, eidolon, familiar, or mount.<br/><strong>Benefit:</strong> Your animal companion, cohort, eidolon, familiar, or mount doesn't count as threatening your opponent for the purposes of feats that require you to be the only character threatening a target. Allies with Hit Dice equal to or less than 1/2 your own Hit Dice don't count as threatening opponents for the purposes of such feats.</p>
</>};
const _heroic_recovery = {title: "Heroic Recovery", jsx: <><h2 id="feat-heroic_recovery-heroic-recovery">Heroic Recovery</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 162</Link></p>
<p>You can throw off the effects of crippling conditions.<br/><strong>Prerequisites:</strong> <Link to="/feat/diehard">Diehard</Link>, <Link to="/feat/endurance">Endurance</Link>, base Fortitude save +4.<br/><strong>Benefit:</strong> Once per day as a standard action you may attempt a new saving throw against a harmful condition or affliction requiring a Fortitude save that is affecting you. If this save against the affliction fails, there is no additional effect, but a successful save counts toward curing an affliction such as poison or disease. You cannot use this feat to recover from instantaneous effects, effects that do not allow a saving throw, or effects that do not require a Fortitude save.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-heroic_recovery--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Heroic Recovery</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 66</Link><br/>You can shrug off the effects of harmful conditions after they've taken effect.<br/><strong>Prerequisites:</strong> Heroic Recovery.<br/><strong>Benefit:</strong> As a swift action, you can expend one use of mythic power to use Heroic Recovery additional times. Whenever you do, add your tier to the result of the Fortitude save.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _heroic_will = {title: "Heroic Will", jsx: <><h2 id="feat-heroic_will-heroic-will">Heroic Will</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 77</Link></p>
<p>Your indomitable will breaks free from mental shackles.<br/><strong>Prerequisites:</strong> <Link to="/feat/iron_will">Iron Will</Link>, base Will save +4, <Link to="/race/human">human</Link>.<br/><strong>Benefit:</strong> Once per day as a standard action, you may attempt a new saving throw against a harmful condition requiring a Will save that is affecting you. If you are dominated, controlled, or cannot take an action because of the effect against which you are trying to make a new saving throw, you can make this saving throw at the start of the turn as no action, but on a success, your turn ends. You cannot use this feat to remove instantaneous effects, effects that do not require a Will save, or effects that do not allow a saving throw.</p>
</>};
const _heros_display = {title: "Hero's Display", jsx: <><h2 id="feat-heros_display-heros-display-combat-performance">Hero's Display (Combat, Performance)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 104</Link></p>
<p>With a dramatic flourish you display your weapons to the crowd. Onlookers are elated, and your enemies are demoralized.<br/><strong>Prerequisites:</strong> <Link to="/feat/dazzling_display">Dazzling Display</Link>, <Link to="/feat/weapon_focus">Weapon Focus</Link>, and proficiency with the selected weapon.<br/><strong>Benefit:</strong> When you spend a swift action to make a <Link to="/rule/performance_combat">performance combat</Link> check, you present the weapon in which you have Weapon Focus in a triumphant display. You gain a +2 bonus on the performance combat check and make an Intimidate check to demoralize all foes within 30 feet who can see your display.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-heros_display--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-heros_display-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When using this feat, you can spend up to 6 stamina points to increase the radius of the demoralizing effect by 5 feet per stamina point you spent (to a maximum of 60 feet).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _heros_fortune = {title: "Hero's Fortune", jsx: <><h2 id="feat-heros_fortune-heros-fortune-hero-point">Hero's Fortune (Hero Point)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 324</Link></p>
<p>Even at the start of your career, it was clear that you had a chance at greatness, and your legend continues to grow with every adventure.<br/><strong>Benefit:</strong> You gain a hero point. The maximum number of <Link to="/rule/hero_points">hero points</Link> you can have at any one time is increased to 5.<br/><strong>Normal:</strong> You can have no more than 3 hero points at one time.<br/><strong>Special:</strong> NPCs who take this feat receive 1 hero point and can have up to 3 (not 5).</p>
</>};
const _hex_strike = {title: "Hex Strike", jsx: <><h2 id="feat-hex_strike-hex-strike-combat">Hex Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 104</Link></p>
<p>Chanting and cursing, you put a hex on your enemy as part of your unarmed strike.<br/><strong>Prerequisites:</strong> Hex class feature, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>.<br/><strong>Benefit:</strong> When you gain this feat, choose one hex that you can use to affect no more than one opponent. If you make a successful unarmed strike against an opponent, in addition to dealing your unarmed strike damage, you can use a swift action to deliver the effects of the chosen hex to that opponent. Doing so does not provoke attacks of opportunity.<br/><strong>Special:</strong> You can take this feat multiple times. Each time you take it, you apply it to a different qualifying hex.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-hex_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-hex_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>You can spend 5 stamina points to apply the effects of your chosen hex as a free action instead of a swift action.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _hidden_presence = {title: "Hidden Presence", jsx: <><h2 id="feat-hidden_presence-hidden-presence">Hidden Presence</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 135</Link></p>
<p>You are adept at hiding within your host.<br/><strong>Prerequisites:</strong> Int or Cha 17, ability to cast possession or greater possession.<br/><strong>Benefit:</strong> While possessing another creature, you can hide yourself from divinations and pass through wards such as <Link to="/spell/magic_circle_against_evil">magic circle against evil</Link> or the effects of a <Link to="/spell/forbiddance">forbiddance</Link> spell. You must attempt a Will save against the spell (even if it doesn't normally allow a saving throw). If you succeed, the spell treats you as if you were your host (for instance, divinations would reveal only the host's alignment, and forbiddance keyed to the host's alignment wouldn't damage you). If your saving throw fails, the spell functions against you as normal; if the spell normally allows a save, your previous failure doesn't count as a failed save against the spell's normal effects.</p>
</>};
const _hide_worker = {title: "Hide Worker", jsx: <><h2 id="feat-hide_worker-hide-worker">Hide Worker</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 113</Link></p>
<p>You excel at crafting armor made from the hides of animals or monsters.<br/><strong>Prerequisites:</strong> Craft (armor) 3 ranks, Knowledge (nature) 3 ranks.<br/><strong>Benefit:</strong> You gain a +4 bonus on Craft (armor) checks to create armor or shields from the hides of living creatures (such as <Link to="/eq-material/dragonhide">dragonhide</Link>). If you succeed at a Craft (armor) check to create armor or shields from the hides of living creatures by 5 or more, you also decrease the cost to make the item by 10%.</p>
</>};
const _high_magic_focus = {title: "High Magic Focus", jsx: <><h2 id="feat-high_magic_focus-high-magic-focus-teamwork">High Magic Focus (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_races">Inner Sea Races pg. 206</Link></p>
<p>With the help of your fellow scholars, you can cast higher forms of magic, enhancing your spells by drawing upon their magical reserves rather than your own.<br/><strong>Prerequisites:</strong> Any <Link to="/main/metamagic_feat">metamagic feat</Link>, Spellcraft 7 ranks, ability to cast 2nd-level spells, <Link to="/race/human">human</Link> (Garundi).<br/><strong>Benefit:</strong> With the help of allies who also have this feat, you can spontaneously apply metamagic feats to your spells without using a higher-level slot or increasing the casting time. Each ally must <Link to="/rule/ready_an_action">ready an action</Link> to cast the same spell you intend to cast. For each other ally within 30 feet who does so, you reduce the cost of the spontaneous metamagic feat by 1 level (to a minimum of 0, and you must have at least one ally assist you, even if the metamagic feat is normally a +0 adjustment). The allies don't need to have the metamagic feat you choose to apply, and the effective level of the spell (after applying the metamagic feat) can't be higher than the highest level of spells you can cast. Lastly, when you use this ability, the spell each ally readies is lost, as if they had cast that spell.</p>
</>};
const _hinder = {title: "Hinder", jsx: <><h2 id="feat-hinder-hinder-blood-hex">Hinder (Blood Hex)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 29</Link></p>
<p>You curse a bleeding opponent with uncertainty.<br/><strong>Prerequisites:</strong> Int 13, Use Magic Device 5 ranks.<br/><strong>Benefit:</strong> As a standard action, you can curse an enemy you've damaged with a melee attack in the last minute to become hesitant. The target must succeed at a Reflex save or take a -10 penalty on any initiative check it makes in the next minute.<br/><strong>Special:</strong> If a shaman or witch uses this <Link to="/rule/feats_class">blood hex</Link>, the target is unable to take a full-attack action for 1 round. This effect can be extended with the cackle hex.</p>
</>};
const _hinderance_dismissal = {title: "Hinderance Dismissal", jsx: <><h2 id="feat-hinderance_dismissal-hinderance-dismissal">Hinderance Dismissal</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 13</Link></p>
<p>You've mastered the art of dismissing certain spells when they become a problem for you or your allies.<br/><strong>Benefit:</strong> You can dismiss any pit spell (such as <Link to="/spell/create_pit">create pit</Link>, <Link to="/spell/hungry_pit">hungry pit</Link>, <Link to="/spell/spiked_pit">spiked pit</Link>, and similar spells with "pit" in their names) or wall spell (such as <Link to="/spell/wall_of_fire">wall of fire</Link>, <Link to="/spell/wall_of_ice">wall of ice</Link>, and similar spells with "wall" in their names) you cast. The spells must have a duration of at least 1 round. This ability follows the normal rules for <Link to="/misc/dismiss">dismissing</Link> spells, allowing you to dismiss conjured pits and walls as a standard action.<br/><strong>Normal:</strong> Several pit and wall spells cannot be dismissed without the use of this feat.</p>
</>};
const _hobgoblin_discipline = {title: "Hobgoblin Discipline", jsx: <><h2 id="feat-hobgoblin_discipline-hobgoblin-discipline">Hobgoblin Discipline</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 124</Link></p>
<p>The presence of other hobgoblins bolsters your resolve.<br/><strong>Prerequisites:</strong> Base attack bonus +1, <Link to="/race/hobgoblin">hobgoblin</Link>.<br/><strong>Benefit:</strong> While you are within 30 feet of at least two other hobgoblins, you gain a +1 morale bonus on saving throws.</p>
</>};
const _hold_the_blade = {title: "Hold the Blade", jsx: <><h2 id="feat-hold_the_blade-hold-the-blade-combat">Hold the Blade (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/dragon_empires_primer">Dragon Empires Primer pg. 25</Link></p>
<p>You can take your opponent's weapon after being stabbed in the back.<br/><strong>Prerequisites:</strong> <Link to="/feat/improved_disarm">Improved Disarm</Link>, base attack bonus +10.<br/><strong>Benefit:</strong> Whenever an enemy deals damage to you with a melee weapon as part of a <Link to="/rule/flanking">flanking</Link> attack or sneak attack, you can make a combat maneuver check to <Link to="/rule/disarm">disarm</Link> against that opponent as an immediate action. You must have at least one hand free when you use this feat. When you use this feat, you take a -4 penalty to your AC until your next turn. You can only use this feat once per round.</p>
</>};
const _hollow_soul = {title: "Hollow Soul", jsx: <><h2 id="feat-hollow_soul-hollow-soul-conduit">Hollow Soul (Conduit)</h2>
<p><strong>Sources</strong> <Link to="/source/planar_adventures">Planar Adventures pg. 29</Link></p>
<p>You can temporarily replace your soul with a fragment of the all-consuming void of Abaddon.<br/><strong>Prerequisites:</strong> Knowledge (planes) 9 ranks.<br/><strong>Benefit:</strong> As a move action, you can enter a state of emotional and spiritual hollowness. While in this state, you react to positive and negative energy as if you were undead: positive energy harms you, while negative energy heals you. Whenever you are targeted by an effect that specifically affects living creatures or undead creatures, or that affects both in different ways, you have a 50% chance to count as an undead creature rather than a living creature. You are immune to effects that specifically target your soul (such as <Link to="/spell/trap_the_soul">trap the soul</Link>). However, while under the effect of this feat, you cannot benefit from beneficial mind-affecting effects, morale bonuses, or <Link to="/ability/bardic_performance">bardic performances</Link>.</p>
<p>You can use this feat's benefit for a number of minutes per day equal to your ranks in Knowledge (planes). These minutes need not be consecutive, but they must be spent in 1-minute increments.</p>
</>};
const _holy_water_assault = {title: "Holy Water Assault", jsx: <><h2 id="feat-holy_water_assault-holy-water-assault-combat">Holy Water Assault (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 23</Link></p>
<p>You have found new and effective uses for holy water in combating the undead.<br/><strong>Prerequisites:</strong> Base attack bonus +1, Knowledge (religion) 3 ranks.<br/><strong>Benefit:</strong> In addition to <Link to="/eq-weapon/holy_water">holy water's</Link> normal uses, you can use holy water to create a variety of other effects, which are listed below. To use holy water in a particular way, you must meet the additional requirements of that effect, such as a particular feat, ranks in a specific skill, or the ability to cast a certain spell (specified after the effect's name). Unless otherwise specified, using any of these abilities consumes one vial of holy water.</p>
<blockquote>
<p><strong>Blinding Water (<Link to="/feat/improved_precise_shot">Improved Precise Shot</Link>):</strong> By uttering a short prayer as swift action, you can empower a vial of holy water with blinding light. If you successfully throw that vial of holy water and land a direct hit against an undead creature by the end of your next turn, the target takes damage from the holy water as normal and also becomes <Link to="/misc/blinded">blinded</Link> (Reflex DC 13 negates blindness). This even affects creatures that do not have eyes such as <Link to="/template/skeleton">skeletons</Link>, but not creatures that don't rely on vision.</p>
<p><strong>Concentrate Holy Water (Craft [alchemy] 4 ranks):</strong> Through alchemical processes, you can refine multiple doses of holy water into a single hyperpotent dose. To do so, you must possess two or more flasks of holy water and you must succeed at a Craft (alchemy) check that takes 10 minutes of uninterrupted time. The DC of the Craft (alchemy) check is equal to 15 + 2 &times; the number of doses of holy water you are combining. For example, combining three flasks of holy water would require a successful DC 21 Craft (alchemy) check. Success means you combine all of the doses into a single concentrated flask of holy water. If you fail the check by 4 or less, the distillation process failed and must be tried again. If you fail the check by 5 or more, the distillation process failed and all of the doses of holy water are wasted. The maximum number of doses of holy water you can combine is equal to half the number of ranks you possess in Craft (alchemy).</p>
<p>A direct hit with a flask of concentrated holy water deals 2d4 points of damage + 2 points of damage &times; the number of doses of holy water used to an undead creature or an evil outsider. Undead creatures and evil outsiders within 5 feet of where the flask hits take 1 point of damage + 1 point of damage &times; the number of doses of holy water used. For example, a flask of concentrated holy water made of 3 doses of holy water would deal 2d4+6 points of damage on a direct hit, and 4 points of damage to undead creatures and evil outsiders within 5 feet of the target.</p>
<p><strong>Healing Glyph (ability to cast <Link to="/spell/glyph_of_warding">glyph of warding</Link>):</strong> You can replace the diamond material component in a <em>glyph of warding</em> spell with a vial of holy water. When you do so, you must place a spell glyph containing a conjuration (healing) spell of 3rd level or lower, which can be designed to benefit allies or harm undead.</p>
<p><strong>Healing Water (Heal 5 ranks):</strong> You can use holy water for curative purposes. When you pour a vial of holy water over your hands, you gain a +4 bonus on Heal checks to perform first aid, treat wounds, treat poison, or treat disease in the next hour. Additionally, once per day you can drink a vial of holy water to heal yourself of 1d8 points of damage.</p>
<p><strong>Holy Circle (ability to cast <Link to="/spell/magic_circle_against_evil">magic circle against evil</Link>):</strong> You can replace the silver material component of a <em>magic circle against evil</em> spell with a vial of holy water. When you do so, the duration of the spell increases 20 minutes per level instead of 10 minutes, and the Spellcraft DC to add a special diagram to the circle is 15 instead of 20.</p>
<p><strong>Holy Water Splash (<Link to="/feat/point_blank_shot">Point-Blank Shot</Link>):</strong> When you throw a flask of holy water, creatures in the area of the holy water's splash radius take 1 additional point of damage as long as they are within 30 feet of you. This ability does not stack with other effects that increase the damage dealt to creatures within the splash radius of holy water, such as the <em>concentrate holy water</em> ability of this feat or the <Link to="/spell/empower_holy_water">empower holy water</Link> spell.</p>
</blockquote>
</>};
const _hook_fighter = {title: "Hook Fighter", jsx: <><h2 id="feat-hook_fighter-hook-fighter-combat">Hook Fighter (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_armory_2">Adventurer's Armory 2 pg. 22</Link></p>
<p>In your deft hands, a climbing tool becomes a deadly weapon.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You treat a <Link to="/eq-misc/grappling_hook">grappling hook</Link> as a one-handed weapon that deals piercing damage equal to a <Link to="/eq-weapon/heavy_pick">heavy pick</Link> of its size and that has the <Link to="/misc/disarm">disarm</Link> and <Link to="/misc/trip">trip</Link> special weapon features. You do not incur penalties as you would for using a grappling hook as an <Link to="/misc/improvised_weapon">improvised weapon</Link>. If you are proficient with <Link to="/eq-weapon/whip">whips</Link> and your grappling hook has at least 10 feet of rope or chain attached to it, you can treat it as a two-handed melee weapon with 15-foot reach, though you can use it against foes anywhere within your reach (including adjacent foes), though you don't threaten any squares with it. Changing between using a grappling hook as a normal weapon and a reach weapon is a move action. When performing a <Link to="/rule/reposition">reposition</Link> maneuver with a grappling hook, you can only move the target toward you from its original position.</p>
</>};
const _horde_charge = {title: "Horde Charge", jsx: <><h2 id="feat-horde_charge-horde-charge-teamwork">Horde Charge (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 57</Link></p>
<p>When you charge with an ally, you are more deadly.<br/><strong>Prerequisites:</strong> Base attack bonus +1, <Link to="/race/half_orc">half-orc</Link> or <Link to="/race/orc">orc</Link>.<br/><strong>Benefit:</strong> When charging during the same round as an ally with this feat, you gain a +2 bonus on attack and damage rolls in addition to the normal bonus for charging. If you can make multiple attacks on a <Link to="/rule/charge">charge</Link>, this bonus only applies to the first attack.</p>
</>};
const _horn_of_the_criosphinx = {title: "Horn of the Criosphinx", jsx: <><h2 id="feat-horn_of_the_criosphinx-horn-of-the-criosphinx-combat">Horn of the Criosphinx (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_sands">People of the Sands pg. 13</Link></p>
<p>You end your charge in a devastating two-handed attack.<br/><strong>Prerequisites:</strong> Base attack bonus +6 or monk level 6th.<br/><strong>Benefit:</strong> Whenever you make a successful charge attack while wielding a two-handed weapon in both hands, add two times your Strength bonus to the damage roll.<br/><strong>Normal:</strong> A character wielding a two-handed weapon adds 1-1/2 times her Strength bonus to damage rolls.<br/><strong>Special:</strong> A monk can use this feat as long as he is wielding a two-handed weapon or both his hands are empty.<br/><strong>Note:</strong> A monk can take this feat as a bonus feat at 6th level. To benefit from this feat, monks must have both hands free and be capable of delivering an unarmed strike.</p>
</>};
const _horn_rider = {title: "Horn Rider", jsx: <><h2 id="feat-horn_rider-horn-rider-combat">Horn Rider (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 164</Link></p>
<p>You can defend yourself using the horn or tusk of a creature you're lashed to.<br/><strong>Prerequisites:</strong> Base attack bonus +1.<br/><strong>Benefit:</strong> You gain a +1 shield bonus to AC when lashed into a <Link to="/eq-misc/horn_harness">horn harness</Link>.<br/><strong>Special:</strong> A creature with this feat can take the <Link to="/feat/mounted_archery">Mounted Archery</Link> feat without possessing 1 rank in the Ride skill or the <Link to="/feat/mounted_combat">Mounted Combat</Link> feat.</p>
</>};
const _horn_riders_charge = {title: "Horn Rider's Charge", jsx: <><h2 id="feat-horn_riders_charge-horn-riders-charge-combat">Horn Rider's Charge (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 164</Link></p>
<p>When the animal you're lashed to charges, you use its momentum in your own attack.<br/><strong>Prerequisites:</strong> <Link to="/feat/horn_rider">Horn Rider</Link>, base attack bonus +1.<br/><strong>Benefit:</strong> Whenever you're lashed into a <Link to="/eq-misc/horn_harness">horn harness</Link> and you <Link to="/rule/ready_an_action">ready an action</Link> to make a melee attack against the target of a <Link to="/rule/charge">charge</Link> made by the creature you're lashed to, you gain the attack bonus for charging and your attack deals double damage (or triple damage with a <Link to="/eq-weapon/lance">lance</Link>). This benefit does not stack with the benefit of <Link to="/feat/spirited_charge">Spirited Charge</Link>.</p>
</>};
const _horrific_gorging = {title: "Horrific Gorging", jsx: <><h2 id="feat-horrific_gorging-horrific-gorging-combat">Horrific Gorging (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 88</Link></p>
<p>In the space of a few horrific seconds, you can chew up and gulp down an entire humanoid body.<br/><strong>Prerequisites:</strong> Bite attack, Large or larger, <Link to="/umr/swallow_whole">swallow whole</Link> universal monster ability.<br/><strong>Benefit:</strong> As a full-round action, you can completely consume a dead, unconscious, paralyzed, or otherwise helpless humanoid creature that you could normally swallow with your swallow whole ability. When you do, you deal bite damage as a critical hit and swallow the humanoid as your swallow whole special ability.</p>
<p>Allies of the swallowed creature within 30 feet that can see you indulge in this horrific feast must succeed at a Will save (DC = 10 + 1/2 your Hit Dice + your Charisma modifier) to avoid being <Link to="/misc/shaken">shaken</Link> for 1d4 rounds. This part of the ability is a mind-affecting fear effect.</p>
</>};
const _horse_master = {title: "Horse Master", jsx: <><h2 id="feat-horse_master-horse-master-combat">Horse Master (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 104</Link></p>
<p>You blend horsemanship skills from disparate traditions into a seamless mounted combat technique.<br/><strong>Prerequisites:</strong> Expert trainer class feature, Ride 6 ranks.<br/><strong>Benefit:</strong> Use your character level to determine your effective druid level for determining the powers and abilities of your mount.<br/><strong>Normal:</strong> You use your cavalier level to determine your effective druid level for determining the powers and abilities of your mount.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-horse_master--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-horse_master-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>You can spend 5 stamina points to grant your mount a number of temporary hit points equal to your character level. These temporary hit points last for 1 minute.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _horse_sense = {title: "Horse Sense", jsx: <><h2 id="feat-horse_sense-horse-sense">Horse Sense</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_132_the_six_legend_soul">Pathfinder #132: The Six-Legend Soul pg. 73</Link></p>
<p>You take Grand Prince Beldam I's insistence upon the resilience of simple creatures to heart, emulating them to shield yourself from complex mental effects.<br/><strong>Prerequisites:</strong> Wis 15, <Link to="/feat/iron_will">Iron Will</Link>.</p>
<p>When you attempt a saving throw against an enchantment effect that cannot affect an animal (such as <Link to="/spell/charm_person">charm person</Link>), you can roll the saving throw twice and take the better result.</p>
</>};
const _horse_whisperer = {title: "Horse Whisperer", jsx: <><h2 id="feat-horse_whisperer-horse-whisperer">Horse Whisperer</h2>
<p><strong>Sources</strong> <Link to="/source/adventurers_guide">Adventurer's Guide pg. 15</Link></p>
<p>Your skill at handling horses allows you to influence all the horses in the area.<br/><strong>Benefit:</strong> You gain a +2 bonus on Handle Animal and Ride checks to handle or ride horses. In addition, you can attempt one Handle Animal check to issue a command to all horses within a 60-foot radius. An opponent whose animal companion or mount is within range can attempt a DC 20 Handle Animal check as an immediate action to prevent her horse from being influenced by you. If the opponent succeeds, you cannot influence that creature again for 1 hour.</p>
</>};
const _hover = {title: "Hover", jsx: <><h2 id="feat-hover-hover-monster">Hover (Monster)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_rpg_bestiary">Pathfinder RPG Bestiary pg. 315</Link></p>
<p>This creature can hover in place with ease and can kick up clouds of dust and debris.<br/><strong>Prerequisites:</strong> Fly speed.<br/><strong>Benefit:</strong> A creature with this feat can halt its movement while flying, allowing it to hover without needing to make a Fly skill check.</p>
<p>If a creature of size Large or larger with this feat hovers within 20 feet of the ground in an area with lots of loose debris, the draft from its wings creates a hemispherical cloud with a radius of 60 feet. The winds generated can snuff torches, small campfires, exposed lanterns, and other small, open flames of non-magical origin. Clear vision within the cloud is limited to 10 feet. Creatures have concealment at 15 to 20 feet (20% miss chance). At 25 feet or more, creatures have total concealment (50% miss chance, and opponents cannot use sight to locate the creature).</p>
<p><strong>Normal:</strong> Without this feat, a creature must make a Fly skill check to hover and the creature does not create a cloud of debris while hovering.</p>
</>};
const _human_guise = {title: "Human Guise", jsx: <><h2 id="feat-human_guise-human-guise">Human Guise</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_beast">Blood of the Beast pg. 13</Link></p>
<p>You have the ability to perfectly emulate a human.<br/><strong>Prerequisites:</strong> <Link to="/umr/change_shape">Change shape</Link> ability, shapechanger subtype, must be able to change shape into a human or must have a true form that appears human.<br/><strong>Benefit:</strong> You count as both human and your race for the purpose of taking character options, such as archetypes, feats, spells, traits, and prestige classes. In addition, you count as human for all other effects whenever you would otherwise appear human. For instance, a +1 human <Link to="/magic-enh/bane">bane</Link> arrow would deal additional damage to a <Link to="/race/kitsune">kitsune</Link> with this feat while she was in her human form (as per change shape), but not in her true form. Likewise, such an arrow would deal additional damage to a <Link to="/race/skinwalker">skinwalker</Link> with this feat while she was in her true form, but would not in her bestial form (as per change shape).</p>
</>};
const _human_spirit = {title: "Human Spirit", jsx: <><h2 id="feat-human_spirit-human-spirit">Human Spirit</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 47</Link></p>
<p>Your blood burns with the passion and unyielding quest for self-improvement displayed so prominently by your human relatives.<br/><strong>Prerequisites:</strong> <Link to="/race/half_elf">Half-elf</Link>.<br/><strong>Benefit:</strong> You receive 1 bonus skill rank. Whenever you gain another Hit Die, you gain an additional skill rank. You cannot gain more than four skill ranks in this way.<br/><strong>Special:</strong> You can only take this feat at 1st level. If you take this feat, you cannot take the <Link to="/feat/drow_spirit">Drow Spirit</Link> or <Link to="/feat/elven_spirit">Elven Spirit</Link> feats.</p>
</>};
const _hunter_of_dahak = {title: "Hunter of Dahak", jsx: <><h2 id="feat-hunter_of_dahak-hunter-of-dahak">Hunter of Dahak</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_gods">Inner Sea Gods pg. 213</Link></p>
<p>You viciously hunt and sacrifice metallic dragons.<br/><strong>Prerequisites:</strong> <Link to="/ability/favored_enemy">Favored enemy</Link> (dragon), worshiper of <Link to="/faith/dahak">Dahak</Link>.<br/><strong>Benefit:</strong> Your favored enemy bonuses increase by 2 against metallic dragons.</p>
</>};
const _huntmaster = {title: "Huntmaster", jsx: <><h2 id="feat-huntmaster-huntmaster">Huntmaster</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 77</Link></p>
<p>You are an expert trainer of horses, hounds, falcons, or hunting cats.<br/><strong>Prerequisites:</strong> Handle Animal 1 rank; either the animal companion, divine bond (mount), or mount class feature; <Link to="/race/human">human</Link>.<br/><strong>Benefit:</strong> If you have the <Link to="/ability/animal_companion">animal companion</Link> class feature, pick one of the following types of animal companions that this feat affects: <Link to="/companion/bird">bird</Link>, <Link to="/companion/dog">dog</Link>, <Link to="/companion/small_cat">small cat</Link>, or <Link to="/companion/horse">horse</Link>. If you have the divine bond (mount) or mount class feature, this feat always affects horses.</p>
<p>You gain a +2 bonus on Handle Animal and Knowledge (nature) checks with creatures of that type of animal. Furthermore, you are treated as one level higher when determining the abilities of your animal companion or mount, as long as it is of the chosen type.</p>
</>};
const _hurricane_punch = {title: "Hurricane Punch", jsx: <><h2 id="feat-hurricane_punch-hurricane-punch-combat">Hurricane Punch (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/elemental_masters_handbook">Elemental Master's Handbook pg. 19</Link></p>
<p>Your fast strikes hit with the force of a hurricane, pushing your foes away.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/improved_bull_rush">Improved Bull Rush</Link>, <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link>, <Link to="/feat/power_attack">Power Attack</Link>.<br/><strong>Benefit:</strong> When you hit the same creature with unarmed strikes at least twice in the same round, you can attempt a <Link to="/rule/bull_rush">bull rush</Link> combat maneuver against that creature as a swift action. You can also move with the target even if you have no movement remaining, but the distance you move can't exceed half your speed.</p>
</>};
const _hurtful = {title: "Hurtful", jsx: <><h2 id="feat-hurtful-hurtful-combat">Hurtful (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 20</Link></p>
<p>You know how to add injury to insult.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/power_attack">Power Attack</Link>.<br/><strong>Benefit:</strong> When you successfully demoralize an opponent within your melee reach with an <Link to="/skill/intimidate">Intimidate</Link> check, you can make a single melee attack against that creature as a swift action. If your attack fails to damage the target, its <Link to="/misc/shaken">shaken</Link> condition from being demoralized immediately ends.</p>
</>};
const _hydraulic_maneuver = {title: "Hydraulic Maneuver", jsx: <><h2 id="feat-hydraulic_maneuver-hydraulic-maneuver">Hydraulic Maneuver</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 177</Link></p>
<p>You can use your hydraulic push to disarm or trip.<br/><strong>Prerequisites:</strong> Hydraulic push spell-like ability, <Link to="/race/undine">undine</Link>.<br/><strong>Benefit:</strong> You may use <em>hydraulic push</em> to attempt a <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/disarm">disarm</Link>, <Link to="/rule/dirty_trick">dirty trick</Link>, or <Link to="/rule/trip">trip</Link> combat maneuver. Each time you use hydraulic push, you must decide which of the allowed combat maneuvers you want to perform. You may use this feat with your hydraulic push racial spell-like ability, your class-granted use of hydraulic push, or any hydraulic push spells you cast, but not with magic items or other external sources that use that spell.<br/><strong>Normal:</strong> Hydraulic push can only be used to make a bull rush combat maneuver.</p>
</>};
const _hydroponic_adaptation = {title: "Hydroponic Adaptation", jsx: <><h2 id="feat-hydroponic_adaptation-hydroponic-adaptation">Hydroponic Adaptation</h2>
<p><strong>Sources</strong> <Link to="/source/legacy_of_the_first_world">Legacy of the First World pg. 8</Link></p>
<p>You can change your wings to instead be effective underwater.<br/><strong>Prerequisites:</strong> <Link to="/race/gathlain">Gathlain</Link>, racial fly speed.<br/><strong>Benefit:</strong> Once per day as a full-round action, you can lose your fly speed to gain a swim speed of 30 feet as you reconfigure your symbiotic vines to help you move underwater. This effect lasts for 1 hour, or until you end it as a full-round action.</p>
</>};
const _hymn_singer = {title: "Hymn Singer", jsx: <><h2 id="feat-hymn_singer-hymn-singer">Hymn Singer</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_night">Blood of the Night pg. 28</Link></p>
<p>Your music is infused with your faith.<br/><strong>Prerequisites:</strong> <Link to="/ability/bardic_performance">Bardic performance</Link>, good alignment, worshiper of a good deity.<br/><strong>Benefit:</strong> When using bardic performance, you may choose to play, recite, or sing a religious song or piece of scripture of your faith. Each round of bardic performance you spend in this way, you count as presenting a holy symbol, chanting prayers, or ringing a hand bell for the purpose of keeping <Link to="/template/vampire">vampires</Link> at bay.</p>
</>};
const _ice_climber = {title: "Ice Climber", jsx: <><h2 id="feat-ice_climber-ice-climber">Ice Climber</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 113</Link></p>
<p>You can move or clamber across slippery surfaces with great skill.<br/><strong>Prerequisites:</strong> <Link to="/feat/arctic_adaptation">Arctic Adaptation</Link> or <Link to="/feat/mountaineer">Mountaineer</Link>; Climb 2 ranks.<br/><strong>Benefit:</strong> When moving across a slippery surface (including but not limited to icy surfaces), you gain a +5 bonus on Climb checks and on Acrobatics checks to maintain your balance. If you fail a Climb check, you fall only if you fail the check by 10 or more. You also gain a +5 bonus on Perception checks to notice an <Link to="/rule/avalanches">avalanche</Link> and a +2 circumstance bonus on Reflex saves to avoid an avalanche.</p>
</>};
const _iconoclast = {title: "Iconoclast", jsx: <><h2 id="feat-iconoclast-iconoclast-combat">Iconoclast (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/faiths_and_philosophies">Faiths and Philosophies pg. 7</Link></p>
<p>You know how to turn a holy symbol into a weapon against her followers.<br/><strong>Prerequisites:</strong> <Link to="/feat/divine_defiance">Divine Defiance</Link>, <Link to="/feat/improved_sunder">Improved Sunder</Link>, <Link to="/feat/power_attack">Power Attack</Link>, Intimidate 3 ranks.<br/><strong>Benefit:</strong> When you succeed at a <Link to="/rule/sunder">sunder</Link> combat maneuver against a holy or unholy symbol, you can attempt an Intimidate check to demoralize as a free action. This demoralization affects all followers of the deity or philosophy whose symbol you sundered who saw you sunder it and are within 30 feet. If you destroyed the symbol, you gain a +5 bonus on your Intimidate check. You can use this feat when sundering any physical holy symbol - it doesn't have to be the hand-held variety commonly used by clerics and other divine spellcasters.</p>
</>};
const _icy_stare = {title: "Icy Stare", jsx: <><h2 id="feat-icy_stare-icy-stare">Icy Stare</h2>
<p><strong>Sources</strong> <Link to="/source/monster_codex">Monster Codex pg. 68</Link></p>
<p>Your eyes burn like ice, allowing you to freeze and weaken foes with a glance.<br/><strong>Prerequisites:</strong> <Link to="/feat/born_of_frost">Born of Frost</Link>, <Link to="/monster/frost_giant">frost giant</Link>.<br/><strong>Benefit:</strong> As a standard action, you can direct your icy stare against a single creature or object within 10 feet. Targeted creatures must succeed at a Fortitude save (DC = 10 + 1/2 your Hit Dice + your Charisma modifier) or take 1d6 points of cold damage. Unattended objects cannot attempt a saving throw. Creatures damaged by the spell must succeed at a Fortitude save or take 1 point of Strength damage.</p>
<p>This feat doesn't grant an actual gaze attack - foes and allies are not in danger simply by meeting your gaze.</p>
</>};
const _illusion_mastery = {title: "Illusion Mastery", jsx: <><h2 id="feat-illusion_mastery-illusion-mastery-item-mastery">Illusion Mastery (Item Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 26</Link></p>
<p>You can weave figments with illusion magic items.<br/><strong>Prerequisites:</strong> Use Magic Device 2 ranks, base Fortitude save bonus +4.<br/><strong>Benefit:</strong> You can cause an item that has an illusion spell of 1st level or higher in its construction requirements to cast <Link to="/spell/minor_image">minor image</Link>. You can use this feat once per day, plus an additional time per day at base Fortitude save bonus +6, +8, +10, and +12.</p>
</>};
const _illusive_gnome_bewilderment = {title: "Illusive Gnome Bewilderment", jsx: <><h2 id="feat-illusive_gnome_bewilderment-illusive-gnome-bewilderment-combat">Illusive Gnome Bewilderment (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 12</Link></p>
<p>You can use your gnome weapons in unusual ways.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/gnome_weapon_focus">Gnome Weapon Focus</Link>, <Link to="/feat/illusive_gnome_style">Illusive Gnome Style</Link>, <Link to="/feat/illusive_gnome_surprise">Illusive Gnome Surprise</Link>, <Link to="/feat/improved_feint">Improved Feint</Link>, gnome magic and weapon familiarity racial traits.<br/><strong>Benefit:</strong> While using Illusive Gnome Style, when you successfully use Bluff to feint against an opponent, you can pick one special weapon feature from among those listed by Illusive Gnome Surprise and deny the opponent its Dexterity modifier to AC, as normal for feinting; alternatively, you can pick two special weapon features instead of one.</p>
</>};
const _illusive_gnome_style = {title: "Illusive Gnome Style", jsx: <><h2 id="feat-illusive_gnome_style-illusive-gnome-style-combat-style">Illusive Gnome Style (Combat, Style)</h2>
<p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 12</Link></p>
<p>The chaotic, somewhat random design of your racial weapons makes it easy to combine them with illusions.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/gnome_weapon_focus">Gnome Weapon Focus</Link>, <Link to="/feat/improved_feint">Improved Feint</Link>, base attack bonus +1, gnome magic and weapon familiarity racial traits.<br/><strong>Benefit:</strong> While feinting with a melee weapon that has "gnome" in its name, you can sacrifice a spell slot, a spell of the illusion school, or a spell from the gnome magic racial trait to gain a bonus on the skill check attempted to feint. This bonus is equal to 1 + the level of the spell sacrificed. If you sacrifice a 0-level spell, you cannot cast or sacrifice that spell again for 24 hours.</p>
</>};
const _illusive_gnome_surprise = {title: "Illusive Gnome Surprise", jsx: <><h2 id="feat-illusive_gnome_surprise-illusive-gnome-surprise-combat">Illusive Gnome Surprise (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 12</Link></p>
<p>You can use gnome weapons in unusual ways.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>, <Link to="/feat/gnome_weapon_focus">Gnome Weapon Focus</Link>, <Link to="/feat/illusive_gnome_style">Illusive Gnome Style</Link>, <Link to="/feat/improved_feint">Improved Feint</Link>.<br/><strong>Benefit:</strong> While using Illusive Gnome Style, you gain a +2 bonus on combat maneuver checks to perform dirty tricks and on Bluff checks to feint. In addition, when you successfully use Bluff to feint against a foe, instead of denying that foe its Dexterity bonus to AC, you can treat one "gnome" weapon that you are wielding as if it had one of the following weapon special features: <Link to="/misc/blocking">blocking</Link>, <Link to="/misc/brace">brace</Link>, <Link to="/misc/disarm">disarm</Link>, <Link to="/misc/distracting">distracting</Link>, <Link to="/misc/performance">performance</Link>, <Link to="/misc/sunder">sunder</Link>, or <Link to="/misc/trip">trip</Link>. This benefit applies only against that foe and lasts for a number of rounds equal to your Charisma modifier (minimum 1).</p>
</>};
const _impact_critical_shot = {title: "Impact Critical Shot", jsx: <><h2 id="feat-impact_critical_shot-impact-critical-shot-combat-critical">Impact Critical Shot (Combat, Critical)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 104</Link></p>
<p>With a series of ranged attacks, you bring your foes to their knees or force them to move.<br/><strong>Prerequisites:</strong> Dex 13, <Link to="/feat/point_blank_shot">Point-Blank Shot</Link>, base attack bonus +9.<br/><strong>Benefit:</strong> Whenever you score a critical hit with a ranged attack, in addition to the normal damage your attack deals, if your confirmation roll exceeds your opponent's CMD, you can push your opponent back as if from the <Link to="/rule/bull_rush">bull rush</Link> combat maneuver or knock that target <Link to="/rule/prone">prone</Link> as if from a <Link to="/rule/trip">trip</Link> combat maneuver. If you choose to bull rush, you cannot move with the target. Your maneuver does not provoke an attack of opportunity.<br/><strong>Normal:</strong> You must perform a bull rush combat maneuver to bull rush an opponent, and you must perform a trip combat maneuver to trip an opponent.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-impact_critical_shot--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-impact_critical_shot-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When you confirm a critical hit and use this feat to either bull rush or trip the target, you can spend 5 stamina points to perform the other combat maneuver as well. Use the confirmation roll for the combat maneuver check of both maneuvers.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _impaling_critical = {title: "Impaling Critical", jsx: <><h2 id="feat-impaling_critical-impaling-critical-combat-critical">Impaling Critical (Combat, Critical)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 105</Link></p>
<p>Your critical hits can skewer your foes.<br/><strong>Prerequisites:</strong> <Link to="/feat/critical_focus">Critical Focus</Link>, <Link to="/feat/weapon_specialization">Weapon Specialization</Link> with selected piercing melee weapon, base attack bonus +11.<br/><strong>Benefit:</strong> Whenever you score a critical hit with the selected piercing melee weapon, you can impale your opponent on your weapon. While your opponent is impaled in this way, each time he starts his turn, you deal damage equal to your weapon's damage dice plus the extra damage dice from your weapon's properties. As an immediate action, you can pull your weapon out of your opponent. If your opponent is ever outside your reach, you must spend a free action to let go of your weapon or pull it out of him. Your opponent can also spend a move action to pull your weapon out. When the weapon comes out, your opponent takes damage as if starting his turn impaled. While you impale your opponent with your weapon, you cannot use it to attack, and you must hold on to it.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-impaling_critical--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-impaling_critical-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When you impale a foe with this feat, you can spend 5 stamina points to make the weapon require a standard action to remove (rather than a move action).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _imperial_prankster = {title: "Imperial Prankster", jsx: <><h2 id="feat-imperial_prankster-imperial-prankster">Imperial Prankster</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_132_the_six_legend_soul">Pathfinder #132: The Six-Legend Soul pg. 73</Link></p>
<p>You model your behavior on that of the legendary trickster, Grand Prince Beldam I, to confound proponents of law and order.<br/><strong>Prerequisites:</strong> Bluff 5 ranks, any chaotic alignment.<br/><strong>Benefit:</strong> You gain a +2 bonus on Bluff checks and combat maneuver checks against lawful creatures. Against creatures with the lawful subtype, this bonus increases to +4.</p>
</>};
const _implacable = {title: "Implacable", jsx: <><h2 id="feat-implacable-implacable-combat">Implacable (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/inner_sea_taverns">Inner Sea Taverns pg. 59</Link></p>
<p>You aren't easily fazed, especially when you've been drinking.<br/><strong>Benefit:</strong> You gain a +2 bonus on saving throws against pain effects. When you are <Link to="/rule/drunkenness">drunk or soused</Link>, you gain DR 5/piercing or slashing.</p>
</>};
const _implant_bomb = {title: "Implant Bomb", jsx: <><h2 id="feat-implant_bomb-implant-bomb">Implant Bomb</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_magic">Ultimate Magic pg. 152</Link></p>
<p>You can attach a bomb to a creature that explodes when the creature dies or after 24 hours.<br/><strong>Prerequisites:</strong> Heal 5 ranks, <Link to="/discovery/delayed_bomb">delayed bomb</Link> alchemist discovery.<br/><strong>Benefit:</strong> You may implant a bomb in a willing or helpless creature (a mindless creature under your control, such as a <Link to="/template/zombie">zombie</Link>, counts as willing for this purpose). This takes 1 hour and expends 1 use of your bomb ability for the day. When the implanted creature dies or is destroyed, the bomb detonates in the creature's square as if it were a delayed bomb set by you (though you can set the bomb's damage to less than your normal bomb damage). You can use any bomb-affecting discoveries on this implanted bomb (<Link to="/discovery/acid_bomb">acid bomb</Link>, <Link to="/discovery/frost_bomb">frost bomb</Link>, <Link to="/discovery/smoke_bomb">smoke bomb</Link>, and so on) as normal. The bomb automatically detonates 24 hours after you implant it in the creature.</p>
<p>If you expend 150 gp worth of alchemical reagents per die of the bomb's damage (for example, 750 gp for a 5d6 bomb), the bomb does not automatically detonate after 24 hours, and only detonates if the creature dies or is destroyed (24 hours after implantation, this bomb no longer counts toward your daily total).</p>
<p>Implanting a bomb is as invasive as using the <Link to="/skill/heal">Heal</Link> skill to treat deadly wounds and leaves surgical scars unless the creature is healed by magic or abilities such as <Link to="/umr/regeneration">regeneration</Link> or <Link to="/umr/fast_healing">fast healing</Link>. Some creatures (such as oozes, elementals, and creatures with the incorporeal quality) cannot have bombs implanted in them. Removing an implanted bomb requires a Heal check to treat deadly wounds, followed by a <Link to="/spell/dispel_magic">dispel magic</Link> spell or Disable Device check to neutralize the bomb (DC = 11 + alchemist's caster level).</p>
</>};
const _implement_focus = {title: "Implement Focus", jsx: <><h2 id="feat-implement_focus-implement-focus">Implement Focus</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 135</Link></p>
<p>You are more adept at spending generic focus on focus powers from your chosen school.<br/><strong>Prerequisites:</strong> Occultist level 3rd.<br/><strong>Benefit:</strong> Select one of your <Link to="/ability/implements">implement schools</Link>. When you spend generic focus to activate focus powers with one of that school's implements, the focus powers cost their listed amount of mental focus.<br/><strong>Normal:</strong> Any focus power activated with generic focus costs twice as much focus to use and maintain.<br/><strong>Special:</strong> You can take this feat multiple times. Each time, you must select a different implement school.</p>
</>};
const _implement_mastery = {title: "Implement Mastery", jsx: <><h2 id="feat-implement_mastery-implement-mastery-item-mastery">Implement Mastery (Item Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/magic_tactics_toolbox">Magic Tactics Toolbox pg. 30</Link></p>
<p>You can use your implements to unlock secrets of mastering relics and other items of power.<br/><strong>Prerequisites:</strong> Implements class feature, mental focus class feature.<br/><strong>Benefit:</strong> For the purposes of using <Link to="/main/feats_item_mastery">item mastery feats</Link>, you treat your <Link to="/ability/implements">implements</Link> as magic items with all spells that you know from each implement's associated implement school functioning as their effective construction requirements. When using an implement to activate an item mastery feat, you can spend a number of points of mental focus equal to half of the feat's base Fortitude save bonus prerequisite to activate the feat without counting the use against the item mastery feat's total number of daily uses.<br/><strong>Special:</strong> An <Link to="/class/occultist">occultist</Link> who has this feat can select item mastery feats in place of focus powers, provided he meets the feats' prerequisites.</p>
</>};
const _imposing_bearing = {title: "Imposing Bearing", jsx: <><h2 id="feat-imposing_bearing-imposing-bearing-armor-mastery-combat">Imposing Bearing (Armor Mastery, Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 17</Link></p>
<p>Your armor allows you to push your opponents around.<br/><strong>Prerequisites:</strong> <Link to="/feat/poised_bearing">Poised Bearing</Link>, base attack bonus +11 or fighter level 8th, armor training class feature, proficiency with heavy armor.<br/><strong>Benefit:</strong> You treat your size as two categories larger for the purposes of determining the size of creatures against which you can attempt <Link to="/rule/bull_rush">bull rush</Link>, <Link to="/rule/drag">drag</Link>, <Link to="/rule/overrun">overrun</Link>, and <Link to="/rule/trip">trip</Link> combat maneuvers.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-imposing_bearing--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-imposing_bearing-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 20</Link><br/>You can spend 5 stamina points as a swift action to add half your armor bonus to your next combat maneuver check this turn. Alternatively, you can spend 5 stamina points as an immediate action to add half your armor bonus to your CMD against a single combat maneuver this turn.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _impressive_grit = {title: "Impressive Grit", jsx: <><h2 id="feat-impressive_grit-impressive-grit-weapon-mastery">Impressive Grit (Weapon Mastery)</h2>
<p><strong>Sources</strong> <Link to="/source/weapon_masters_handbook">Weapon Master's Handbook pg. 21</Link></p>
<p>Your mastery of ranged weapons allows you to perform impressive deeds.<br/><strong>Prerequisites:</strong> Base attack bonus +11, weapon training class feature with a ranged weapon.<br/><strong>Benefit:</strong> Select one of the following gunslinger deeds: <Link to="/deed/dead_shot">dead shot</Link>, <Link to="/deed/startling_shot">startling shot</Link>, or <Link to="/deed/targeting">targeting</Link>. You can perform the selected deed a number of times per day equal to your highest mental ability score modifier (Intelligence, Wisdom, or Charisma; minimum 1). You can use this deed with an appropriate ranged weapon. If you also have the selected deed as a class feature, reduce the number of grit points that you need to use it by 1, as per the <Link to="/feat/signature_deed">Signature Deed</Link> feat.<br/><strong>Special:</strong> You can select Impressive Grit up to three times. Each time you select it, choose a different gunslinger deed. A gunslinger can ignore the weapon training class feature prerequisite of Impressive Grit.</p>
</>};
const _improved_armor_focus = {title: "Improved Armor Focus", jsx: <><h2 id="feat-improved_armor_focus-improved-armor-focus-combat">Improved Armor Focus (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 16</Link></p>
<p>Your mastery makes the most of your armor.<br/><strong>Prerequisites:</strong> <Link to="/feat/armor_focus">Armor Focus</Link>, base attack bonus +6, proficiency with selected armor.<br/><strong>Benefit:</strong> The armor check penalty of the selected armor decreases by 1 (to a minimum of 0). You also use your character level in place of your base attack bonus for the purpose of <Link to="/rule/mastery_feats">armor mastery feat</Link> prerequisites.<br/><strong>Special:</strong> You can gain this feat multiple times. Its effects do not stack. Each time you take the feat, it applies to a new type of armor.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-improved_armor_focus--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-improved_armor_focus-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/armor_masters_handbook">Armor Master's Handbook pg. 20</Link><br/>You can spend 5 stamina points to negate your armor's armor check penalty for 1 skill check.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _improved_awesome_blow = {title: "Improved Awesome Blow", jsx: <><h2 id="feat-improved_awesome_blow-improved-awesome-blow-combat">Improved Awesome Blow (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_class_guide">Advanced Class Guide pg. 150</Link></p>
<p>You are skilled at sending your opponents flying.<br/><strong>Prerequisites:</strong> Str 13; <Link to="/feat/awesome_blow">Awesome Blow</Link> or awesome blow class feature; <Link to="/feat/power_attack">Power Attack</Link><br/><strong>Benefit:</strong> You receive a +2 bonus on checks to perform an awesome blow combat maneuver. You also gain a +2 bonus to your combat maneuver defense whenever an opponent tries to perform an awesome blow combat maneuver against you. Whenever you successfully perform an awesome blow combat maneuver, your opponent's movement provokes attacks of opportunity from all your allies (but not you).<br/><strong>Normal:</strong> Creatures moved by awesome blow do not provoke attacks of opportunity.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-improved_awesome_blow--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-improved_awesome_blow-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When a creature attempts an awesome blow combat maneuver against you, you can spend up to 3 stamina points to increase your Combat Maneuver Defense against that combat maneuver by an amount equal to the number of stamina points you spent. This bonus stacks with the bonus granted by Improved Awesome Blow.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _improved_awesome_throw = {title: "Improved Awesome Throw", jsx: <><h2 id="feat-improved_awesome_throw-improved-awesome-throw-combat">Improved Awesome Throw (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_91_battle_of_bloodmarch_hills">Pathfinder #91: Battle of Bloodmarch Hills pg. 69</Link></p>
<p>When you perform an awesome throw, you knock opponents back farther.<br/><strong>Prerequisites:</strong> Str 25, <Link to="/feat/awesome_throw">Awesome Throw</Link>, <Link to="/feat/greater_bull_rush">Greater Bull Rush</Link>, <Link to="/feat/throw_anything">Throw Anything</Link> or <Link to="/umr/rock_throwing">rock throwing</Link>, size Large or larger.<br/><strong>Benefit:</strong> When you make an awesome throw combat maneuver, for every 5 by which your combat maneuver check exceeds the target's CMD, you send the target flying 5 additional feet. Furthermore, this movement provokes attacks of opportunity from your allies.</p>
</>};
const _improved_back_to_back = {title: "Improved Back to Back", jsx: <><h2 id="feat-improved_back_to_back-improved-back-to-back-teamwork">Improved Back to Back (Teamwork)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 105</Link></p>
<p>After much practice, you and an ally have become adept at fighting in close proximity to one another.<br/><strong>Prerequisites:</strong> <Link to="/feat/back_to_back">Back to Back</Link>, Perception 5 ranks.<br/><strong>Benefit:</strong> While you are adjacent to an ally who is <Link to="/rule/flanked">flanked</Link> and also has this feat, you can spend a swift action to gain a +2 bonus to AC against all flankers until the start of your next turn.</p>
</>};
const _improved_balor_whip = {title: "Improved Balor Whip", jsx: <><h2 id="feat-improved_balor_whip-improved-balor-whip-combat">Improved Balor Whip (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/villain_codex">Villain Codex pg. 80</Link></p>
<p>You can pull in foes with your whip and attack them with your sword.<br/><strong>Prerequisites:</strong> <Link to="/feat/balor_whip">Balor Whip</Link>, <Link to="/feat/whip_mastery">Whip Mastery</Link>, base attack bonus +12.<br/><strong>Benefit:</strong> When you succeed at a <Link to="/rule/drag">drag</Link> attempt with your <Link to="/eq-weapon/whip">whip</Link> against a non-adjacent target and the target ends the drag adjacent to you, as a free action you can make a single attack against the target at your highest attack bonus using the melee weapon held in your other hand. You gain an additional +2 bonus on drag combat maneuver checks when using a whip to drag, but this bonus does not stack with the bonus from <Link to="/feat/greater_drag">Greater Drag</Link>.</p>
</>};
const _improved_beast_hunter = {title: "Improved Beast Hunter", jsx: <><h2 id="feat-improved_beast_hunter-improved-beast-hunter-combat">Improved Beast Hunter (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 113</Link></p>
<p>You are well trained in stalking and hunting the animals of the wild.<br/><strong>Prerequisites:</strong> <Link to="/feat/beast_hunter">Beast Hunter</Link>; base attack bonus +3; Knowledge (nature) or Survival 3 ranks.<br/><strong>Benefit:</strong> When fighting animals that are at least one size category larger than you and that are native to the terrain you have chosen with Beast Hunter, you gain a +4 bonus on <Link to="/rule/combat_maneuver">combat maneuver</Link> checks and a +4 to your CMD against such animals' attempts to use combat maneuvers against you. Additionally, you gain a +2 bonus on Reflex saves against attacks by the animal that allow a Reflex save (such as attempting to avoid a <Link to="/umr/trample">trample</Link> attack).<br/><strong>Special:</strong> If you have selected Beast Hunter multiple times, you gain this benefit for all of the terrains you have chosen for those feats.</p>
</>};
const _improved_bestial_transformation = {title: "Improved Bestial Transformation", jsx: <><h2 id="feat-improved_bestial_transformation-improved-bestial-transformation">Improved Bestial Transformation</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_night">Blood of the Night pg. 16</Link></p>
<p>You have mastered the ability to transform into a variety of beasts.<br/><strong>Prerequisites:</strong> <Link to="/template/vampire">Vampire</Link>.<br/><strong>Benefit:</strong> You can <Link to="/umr/change_shape">change shape</Link> to assume the form of one of the following beasts, as <Link to="/spell/beast_shape_ii">beast shape II</Link>: <Link to="/monster/boar">boar</Link>, <Link to="/monster/dire_bat">dire bat</Link>, <Link to="/monster/giant_frog">giant frog</Link>, <Link to="/monster/grizzly_bear">grizzly bear</Link>, <Link to="/monster/hyena">hyena</Link>, <Link to="/monster/leopard">leopard</Link>, <Link to="/monster/lion">lion</Link>, <Link to="/monster/shark">shark</Link>, <Link to="/monster/squid">squid</Link>, or <Link to="/monster/wolf">wolf</Link>. This is a supernatural ability.<br/><strong>Special:</strong> You can gain this feat multiple times. Each time you take this feat, choose another animal transformation.</p>
</>};
const _improved_bless_equipment = {title: "Improved Bless Equipment", jsx: <><h2 id="feat-improved_bless_equipment-improved-bless-equipment">Improved Bless Equipment</h2>
<p><strong>Sources</strong> <Link to="/source/undead_slayers_handbook">Undead Slayer's Handbook pg. 7</Link></p>
<p>You can channel even more energy into weapons and armor to grant them several divine powers at once.<br/><strong>Prerequisites:</strong> <Link to="/feat/bless_equipment">Bless Equipment</Link>, caster level 9th, <Link to="/ability/channel_energy">channel energy</Link> class feature.<br/><strong>Benefit:</strong> The number of uses of channeled energy you must expend to bless a piece of equipment using Bless Equipment and <Link to="/feat/align_equipment">Align Equipment</Link> decreases by one (to a minimum of one use of channel energy per blessing).</p>
<p>You can also bless a piece of equipment with up to two blessings at a time. Each blessing provides a different special ability drawn from the Bless Equipment list (and the Align Equipment list if you possess that feat). You must still have a high enough caster level to bless a piece of equipment with each of the selected blessings.</p>
<p>You expend the appropriate number of uses of channeled energy required for each blessing, taking into account the reduction granted by this feat (and the increase for blessing a masterwork item, if needed). For example, a cleric with this feat would need to expend two uses of channeled energy to bless a weapon with the undead-bane and ghost touch special abilities (one use for <Link to="/magic-enh/bane">bane</Link> plus one use for <Link to="/magic-enh/ghost_touch">ghost touch</Link>).</p>
<p>If a given piece of equipment already has a blessing on it, you can give it a second blessing. When another blessing is applied to a piece of equipment that currently has a blessing active on it, the durations for the two blessings are tracked separately.</p>
</>};
const _improved_blind_fight = {title: "Improved Blind-Fight", jsx: <><h2 id="feat-improved_blind_fight-improved-blind-fight-combat">Improved Blind-Fight (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_players_guide">Advanced Player's Guide pg. 162</Link></p>
<p>Your keen senses guide your hand against hidden foes.<br/><strong>Prerequisites:</strong> Perception 10 ranks, <Link to="/feat/blind_fight">Blind-Fight</Link>.<br/><strong>Benefit:</strong> Your melee attacks ignore the miss chance for less than total <Link to="/rule/concealment">concealment</Link>. You may still reroll your miss chance percentile roll for total concealment.</p>
<p>If you successfully pinpoint an invisible or hidden attacker within 30 feet, that attacker gets no advantages related to hitting you with ranged attacks. That is, you don't lose your Dexterity bonus to Armor Class, and the attacker doesn't get the usual +2 bonus for being invisible.</p>
<p><strong>Special:</strong> The Improved Blind-Fight feat is of no use against a character who is the subject of a <Link to="/spell/blink">blink</Link> spell.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-improved_blind_fight--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-improved_blind_fight-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When attacking a foe with total concealment, you can spend 5 stamina points to treat that foe as having normal concealment (20% miss chance instead of 50%).</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _improved_bravery = {title: "Improved Bravery", jsx: <><h2 id="feat-improved_bravery-improved-bravery-combat">Improved Bravery (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 84</Link></p>
<p>Your bravery protects you from more than just fear.<br/><strong>Prerequisites:</strong> Cha 13, bravery class feature.<br/><strong>Benefit:</strong> Add your bravery bonus against all mind-affecting effects instead of just against fear.</p>
</>};
const _improved_bull_rush = {title: "Improved Bull Rush", jsx: <><h2 id="feat-improved_bull_rush-improved-bull-rush-combat">Improved Bull Rush (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 126</Link></p>
<p>You are skilled at pushing your foes around.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +1.<br/><strong>Benefit:</strong> You do not provoke an attack of opportunity when performing a <Link to="/rule/bull_rush">bull rush</Link> combat maneuver. In addition, you receive a +2 bonus on checks made to bull rush a foe. You also receive a +2 bonus to your Combat Maneuver Defense whenever an opponent tries to bull rush you.<br/><strong>Normal:</strong> You provoke an attack of opportunity when performing a bull rush combat maneuver.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-improved_bull_rush--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-improved_bull_rush-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When you are the target of a bull rush combat maneuver, you can spend a number of stamina points up to your Strength or Dexterity bonus, whichever is greater. Your CMD increases by that number for that bull rush attempt.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-improved_bull_rush--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Improved Bull Rush</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 66</Link><br/>You push foes around with amazing ease.<br/><strong>Prerequisites:</strong> Improved Bull Rush.<br/><strong>Benefit:</strong> You gain a bonus equal to half your tier on checks to bull rush, and to your CMD when an opponent bull rushes you. These bonuses stack with those granted by non-mythic Improved Bull Rush.</p>
<p>Furthermore, you can make an attack of opportunity against any creature that attempts to bull rush you, unless it also has this feat.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-improved_bull_rush--table-2"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>This feat has been removed, replaced with the new <Link to="/rule/powerful_maneuvers">Powerful Maneuvers</Link> feat.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _improved_called_shot = {title: "Improved Called Shot", jsx: <><h2 id="feat-improved_called_shot-improved-called-shot-called-shot">Improved Called Shot (Called Shot)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 195</Link></p>
<p>You are skilled at landing blows right where you want to.<br/><strong>Prerequisites:</strong> Int 13, <Link to="/feat/combat_expertise">Combat Expertise</Link>.<br/><strong>Benefit:</strong> You receive a +2 bonus on attack rolls when making a <Link to="/rule/called_shots">called shot</Link>. When taking a full-round or standard action that gives you multiple attacks, you can replace a single attack with a called shot. You may only attempt one called shot per round.<br/><strong>Normal:</strong> You can make one called shot per round as a full-round action.</p>
</>};
const _improved_channel = {title: "Improved Channel", jsx: <><h2 id="feat-improved_channel-improved-channel">Improved Channel</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 126</Link></p>
<p>Your channeled energy is harder to resist.<br/><strong>Prerequisites:</strong> <Link to="/ability/channel_energy">Channel energy</Link> class feature.<br/><strong>Benefit:</strong> Add 2 to the DC of saving throws made to resist the effects of your channel energy ability.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-improved_channel--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Improved Channel</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 66</Link><br/>As a divine conduit for energy, you're unmatched.<br/><strong>Prerequisites:</strong> Improved Channel.<br/><strong>Benefit:</strong> Non-mythic creatures that take damage from your channel energy must roll their saving throws twice and take the lower result.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _improved_channel_force = {title: "Improved Channel Force", jsx: <><h2 id="feat-improved_channel_force-improved-channel-force">Improved Channel Force</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 88</Link></p>
<p>You move your enemies within a beam of righteous energy.<br/><strong>Prerequisites:</strong> <Link to="/feat/channel_force">Channel Force</Link>, <Link to="/race/aasimar">aasimar</Link>, <Link to="/ability/channel_energy">channel energy</Link> 4d6.<br/><strong>Benefit:</strong> When using Channel Force, you can affect all creatures in a 60-foot line or a 30-foot cone-shaped burst. You must choose to either push or pull all creatures within the affected area that fail their saves.</p>
</>};
const _improved_charging_hurler = {title: "Improved Charging Hurler", jsx: <><h2 id="feat-improved_charging_hurler-improved-charging-hurler-combat">Improved Charging Hurler (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 105</Link></p>
<p>Every muscle in your body adds its force to your thrown weapons.<br/><strong>Prerequisites:</strong> <Link to="/feat/charging_hurler">Charging Hurler</Link>.<br/><strong>Benefit:</strong> When you use Charging Hurler, your target can be at any range up to your weapon's maximum range. If your target is within 30 feet, you gain a +2 bonus on damage rolls.<br/><strong>Normal:</strong> Using Charging Hurler requires you to end your movement within 30 feet of your opponent.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-improved_charging_hurler--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-improved_charging_hurler-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>When using Charging Hurler against a target within 30 feet, you can spend up to 2 stamina points. When you do, the bonus on your damage roll for that attack increases by double the number of stamina points you spent.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _improved_cleaving_finish = {title: "Improved Cleaving Finish", jsx: <><h2 id="feat-improved_cleaving_finish-improved-cleaving-finish-combat">Improved Cleaving Finish (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 105</Link></p>
<p>You can cut down many opponents in a single strike.<br/><strong>Prerequisites:</strong> Str 13, <Link to="/feat/cleave">Cleave</Link>, <Link to="/feat/cleaving_finish">Cleaving Finish</Link>, <Link to="/feat/great_cleave">Great Cleave</Link>, <Link to="/feat/power_attack">Power Attack</Link>, base attack bonus +6.<br/><strong>Benefit:</strong> You can use Cleaving Finish any number of times per round.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-improved_cleaving_finish--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-improved_cleaving_finish-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 122</Link><br/>Once per round when you confirm a critical hit, you can spend 5 stamina points to treat that attack as if you reduced the target to 0 or fewer hit points for the purpose of using the Cleaving Finish feat.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _improved_collectors_boon = {title: "Improved Collector's Boon", jsx: <><h2 id="feat-improved_collectors_boon-improved-collectors-boon">Improved Collector's Boon</h2>
<p><strong>Sources</strong> <Link to="/source/chronicle_of_legends">Chronicle of Legends pg. 24</Link></p>
<p>Your knack for unlocking the true potential of magical equipment allows you to draw great power from your equipment.<br/><strong>Prerequisites:</strong> <Link to="/feat/collectors_boon">Collector's Boon</Link>, character level 9th.</p>
<p>While you are wearing or wielding at least three items from a <Link to="/main/magic_misc">set</Link>, you can gain the benefits of the three-, four-, and five-item benefits listed in the set, as appropriate for the total number of pieces of the set in your possession. In addition, you gain a +2 circumstance bonus on Use Magic Device checks as long as you are currently wearing or wielding at least five pieces of magical equipment (such as magic armor, magic weapons, magic rings, or wondrous items). For the purposes of determining whether you gain this benefit, gauntlets that are part of a suit of magic armor count as a separate magic item only if they have been enchanted as weapons.</p>
</>};
const _improved_conceal_spell = {title: "Improved Conceal Spell", jsx: <><h2 id="feat-improved_conceal_spell-improved-conceal-spell">Improved Conceal Spell</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_intrigue">Ultimate Intrigue pg. 84</Link></p>
<p>You can conceal the mightiest spells in the subtlest fashions.<br/><strong>Prerequisites:</strong> <Link to="/feat/conceal_spell">Conceal Spell</Link>, <Link to="/feat/deceitful">Deceitful</Link>, Bluff 5 ranks, Disguise 5 ranks, Sleight of Hand 10 ranks, ability to cast 3rd-level spells or use a 3rd-level spell-like ability.<br/><strong>Benefit:</strong> When you use Conceal Spell, creatures no longer gain a bonus equal to the level of the spell or spell-like ability on their checks to notice the hidden spell.<br/><strong>Normal:</strong> Creatures attempting to notice a spell hidden with Conceal Spell gain a bonus equal to the level of the spell or spell-like ability on their Perception, Sense Motive, and Spellcraft checks.</p>
</>};
const _improved_counterspell = {title: "Improved Counterspell", jsx: <><h2 id="feat-improved_counterspell-improved-counterspell">Improved Counterspell</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 126</Link></p>
<p>You are skilled at countering the spells of others using similar spells.<br/><strong>Benefit:</strong> When <Link to="/rule/counterspells">counterspelling</Link>, you may use a spell of the same school that is one or more spell levels higher than the target spell.<br/><strong>Normal:</strong> Without this feat, you may counter a spell only with the same spell or with a spell specifically designated as countering the target spell.</p>
<div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-improved_counterspell--table-0"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Improved Counterspell</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 66</Link><br/>Your innate understanding of magical mechanics allows you to unravel spells with pure magical energy.<br/><strong>Prerequisites:</strong> Improved Counterspell.<br/><strong>Benefit:</strong> When counterspelling, you can use a spell of the same school that is the same or higher spell level as the target spell.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _improved_critical = {title: "Improved Critical", jsx: <><h2 id="feat-improved_critical-improved-critical-combat">Improved Critical (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/prpg_core_rulebook">PRPG Core Rulebook pg. 127</Link></p>
<p>Attacks made with your chosen weapon are quite deadly.<br/><strong>Prerequisites:</strong> Proficient with weapon, base attack bonus +8.<br/><strong>Benefit:</strong> When using the weapon you selected, your threat range is doubled.<br/><strong>Special:</strong> You can gain Improved Critical multiple times. The effects do not stack. Each time you take the feat, it applies to a new type of weapon. This effect doesn't stack with any other effect that expands the threat range of a weapon.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-improved_critical--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-improved_critical-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 123</Link><br/>When you hit with an attack and the roll fails to threaten a critical hit by 3 or less, you can spend 5 stamina points to attempt to deal double damage anyway. Roll as if confirming a critical hit. If this confirmation roll succeeds, your attack is still not a critical hit, but it deals double damage.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional mythic"><ScrollContainer id="feat-improved_critical--table-1"><table><tbody><tr><ThLink scope="row" to="/rule/mythic_feats" rowSpan={2}><IonIcon aria-label="Mythic Rules" icon="/icons/ancient-sword.svg" /></ThLink><th scope="col">Mythic Improved Critical</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/mythic_adventures">Mythic Adventures pg. 66</Link><br/>Your critical strikes with your chosen weapon are deadlier than most.<br/><strong>Prerequisites:</strong> Improved Critical, base attack bonus +8.<br/><strong>Benefit:</strong> Your critical multiplier with your chosen weapon is increased by 1 (to a maximum of &times;6).<br/><strong>Special:</strong> You can gain this feat multiple times. The effects do not stack. Each time you take this feat, it applies to a different non-mythic Improved Critical feat.</p>
</td></tr></tbody></table></ScrollContainer></div><div className="sideNoteWrap singular optional elephant"><ScrollContainer id="feat-improved_critical--table-2"><table><tbody><tr><ThLink scope="row" to="/rule/the_elephant_in_the_room"><IonIcon aria-label="The Elephant in the Room" icon="/icons/elephant.svg" /></ThLink><td><p><strong>Sources</strong> <Link to="/source/the_elephant_in_the_room_feat_taxes_in_pathfinder">The Elephant in the Room: Feat Taxes in Pathfinder</Link><br/>Choose one <Link to="/ability/weapon_groups">weapon group</Link> listed under the fighter's Weapon Training class feature. Attacks made with your chosen weapons are quite deadly.<br/><strong>Prerequisites:</strong> Proficiency with at least one weapon from the selected weapon group, base attack bonus +8.<br/><strong>Benefit:</strong> When using any weapon from the selected group, your threat range is doubled.<br/><strong>Special:</strong> You can gain Improved Critical multiple times. The effects do not stack. Each time you take the feat, it applies to a new weapon group.</p>
<p>This effect doesn't stack with any other effect that expands the threat range of a weapon.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
const _improved_dark_sight = {title: "Improved Dark Sight", jsx: <><h2 id="feat-improved_dark_sight-improved-dark-sight">Improved Dark Sight</h2>
<p><strong>Sources</strong> <Link to="/source/advanced_race_guide">Advanced Race Guide pg. 112</Link></p>
<p>With further modification, your eyes see clearly in not only normal darkness, but in magical darkness as well.<br/><strong>Prerequisites:</strong> <Link to="/feat/dark_sight">Dark Sight</Link>, <Link to="/feat/gloom_sight">Gloom Sight</Link>, <Link to="/race/fetchling">fetchling</Link>.<br/><strong>Benefit:</strong> You gain the <Link to="/umr/see_in_darkness">see in darkness</Link> ability and lose the <Link to="/umr/light_sensitivity">light sensitivity</Link> weakness, but gain the <Link to="/umr/light_blindness">light blindness</Link> weakness.</p>
</>};
const _improved_day_job = {title: "Improved Day Job", jsx: <><h2 id="feat-improved_day_job-improved-day-job">Improved Day Job</h2>
<p><strong>Sources</strong> <Link to="/source/pathfinder_society_primer">Pathfinder Society Primer pg. 8</Link></p>
<p>You learned the importance of an honest day's work while training as an initiate of the <Link to="/rule/pathfinder_society">Pathfinder Society</Link>.<br/><strong>Prerequisites:</strong> Ability to attempt Day Job checks (see the <em>Guide to Pathfinder Society Organized Play</em> <sup><InnerLink showBacklink="backlink-feat-improved_day_job-ref-X-1" id="feat-improved_day_job-ref-X-1" data-hash-target to="feat-improved_day_job-X">1</InnerLink></sup>).<br/><strong>Benefit:</strong> You gain a +3 bonus on Day Job checks using one skill you choose when you take this feat. This bonus stacks with other feats that grant a bonus to the chosen skill, including <Link to="/feat/skill_focus">Skill Focus</Link>.</p>
<section data-footnotes>
<h3 id="feat-improved_day_job-label">Footnotes</h3>
<ol>
<li id="feat-improved_day_job-X">
<p>Not included in this app. The Day Job appears in version 1.1 of that document, but not all versions. <InnerLink id="backlink-feat-improved_day_job-ref-X-1" data-hash-target to="feat-improved_day_job-ref-X-1" aria-label="Back to reference X-1">↩</InnerLink></p>
</li>
</ol>
</section>
</>};
const _improved_death_stealing = {title: "Improved Death-Stealing", jsx: <><h2 id="feat-improved_death_stealing-improved-death-stealing">Improved Death-Stealing</h2>
<p><strong>Sources</strong> <Link to="/source/demons_revisited">Demons Revisited pg. 44</Link></p>
<p>Your death-stealing gaze creates more powerful undead.<br/><strong>Prerequisites:</strong> <Link to="/monster/nabasu">Nabasu</Link>, <Link to="/feat/ability_focus">Ability Focus</Link> (death-stealing gaze)<br/><strong>Benefit:</strong> When you would normally create a ghoul with your death-stealing gaze, you instead create a <Link to="/monster/ghast">ghast</Link>. As a free action, you may also spend a number of growth points in order to even further augment your new undead minion as it is created. If you spend 1 growth point, you create a <Link to="/monster/wight">wight</Link> instead of a ghast. If you spend 3 growth points, you create a <Link to="/monster/wraith">wraith</Link> instead of a ghast. And if you spend 5 growth points, you transform the target into a <Link to="/template/juju_zombie">juju zombie</Link> instead of a ghast. Note that spending growth in this manner reduces your statistics as appropriate.</p>
</>};
const _improved_devastating_strike = {title: "Improved Devastating Strike", jsx: <><h2 id="feat-improved_devastating_strike-improved-devastating-strike-combat">Improved Devastating Strike (Combat)</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_combat">Ultimate Combat pg. 105</Link></p>
<p>The fury and power channeled through your attack is enough to kill a lesser being outright.<br/><strong>Prerequisites:</strong> <Link to="/feat/devastating_strike">Devastating Strike</Link>, <Link to="/feat/vital_strike">Vital Strike</Link>, base attack bonus +13.<br/><strong>Benefit:</strong> Whenever you use Vital Strike, <Link to="/feat/improved_vital_strike">Improved Vital Strike</Link>, or <Link to="/feat/greater_vital_strike">Greater Vital Strike</Link>, you gain a bonus on attack rolls to confirm a critical hit equal to the bonus on damage rolls you gain from Devastating Strike.</p>
<div className="sideNoteWrap singular optional stamina"><ScrollContainer id="feat-improved_devastating_strike--table-0"><table><tbody><tr><ThLink scope="row" to="/feat/combat_stamina" rowSpan={2}><IonIcon aria-label="Combat Tricks and Stamina" icon="/icons/shield-bash.svg" /></ThLink><th scope="col" id="feat-improved_devastating_strike-combat_trick" data-hash-target>Combat Trick</th></tr><tr><td><p><strong>Sources</strong> <Link to="/source/pathfinder_unchained">Pathfinder Unchained pg. 123</Link><br/>Whenever you use the Devastating Strike combat trick, increase the bonus damage to +6 on each of the extra sets of weapon damage dice. For weapons with more than one damage die, count all the weapon's base damage dice together as one set.</p>
</td></tr></tbody></table></ScrollContainer></div></>};
